-- Poems batch 279
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f7bd4983-9004-4897-b5eb-212ff56f0935','寄朱仁中','謝翱','宋','宋诗','song-poetry','','[]','聞君經亂後，居處畏山顛。',48,'全唐诗/poet.song.246000.json','["聞君經亂後，居處畏山顛。", "家在聚如客，糧餘食带烟。", "戍鴉分落日，燒草共殘年。", "因憶先丘壠，于今是極邊。"]'),
('042014e7-9250-4d62-a4e0-c2e3f81782bf','僧舍避暑分韻得入字','謝翱','宋','宋诗','song-poetry','','[]','故人隔天風，海水吹不立。',48,'全唐诗/poet.song.246000.json','["故人隔天風，海水吹不立。", "聊將塵渴心，遠赴山中汲。", "晴香芝菌生，暝翠霧露濕。", "唯應雞犬深，幽林聽經入。"]'),
('19e23c9f-e3a1-4633-8a92-5764ede86b7b','遊釣臺','謝翱','宋','宋诗','song-poetry','','[]','古臺臨釣渚，遺像在蒼烟。',48,'全唐诗/poet.song.246000.json','["古臺臨釣渚，遺像在蒼烟。", "有客隨槎到，無僧依樹禪。", "風塵侵祭器，樵獵避兵船。", "應有前朝蹟，看碑數漢年。"]'),
('0a50cb65-6f3c-4fad-add2-e6b7aea8e51e','西臺哭所思','謝翱','宋','宋诗','song-poetry','','[]','殘年哭知己，白日下荒臺。',48,'全唐诗/poet.song.246000.json','["殘年哭知己，白日下荒臺。", "淚落吳江水，隨潮到海迴。", "故衣猶染碧，后土不憐才。", "未老山中客，唯應賦八哀。"]'),
('32b26ee0-5c3d-4d50-a511-8ae4734cc5fa','江上別友','謝翱','宋','宋诗','song-poetry','','[]','相看仍慟哭，欲學晉諸賢。',48,'全唐诗/poet.song.246000.json','["相看仍慟哭，欲學晉諸賢。", "戍近風鳴柝，江空雨送船。", "朔雲侵別色，南雪憶歸年。", "擬共鋤青朮，無爲俗事牽。"]'),
('76b89b1f-f357-4233-a564-1fabbe63c423','題翁徵君集後','謝翱','宋','宋诗','song-poetry','','[]','樵獵識冠裳，何言志四方。',48,'全唐诗/poet.song.246000.json','["樵獵識冠裳，何言志四方。", "離秦風日泠，過楚薜蘿長。", "野夢違徵詔，衰年枉薦章。", "故山唐室晚，應種朮爲糧。"]'),
('b1f9a343-741b-4816-a3c0-f7a15c34059d','除夜聞雷','謝翱','宋','宋诗','song-poetry','','[]','牢落長爲客，殘年獨擁衾。',48,'全唐诗/poet.song.246000.json','["牢落長爲客，殘年獨擁衾。", "燈分寒夜火，雨過震餘陰。", "搗藥滋玄髪，書符𤞣黑祲。", "相看故鄉淚，不敢效吳音。"]'),
('96879fe1-07a0-4b27-b9d8-c6cd37660b00','元日枕流亭聽雨','謝翱','宋','宋诗','song-poetry','','[]','征鐸殘年雨，吟聽憶到城。',48,'全唐诗/poet.song.246000.json','["征鐸殘年雨，吟聽憶到城。", "愁雲侵歙盡，夢日向吳生。", "藥産難離性，灘流不掩聲。", "他宵樺燭飲，因想此中行。"]'),
('cea62002-be04-4a98-a6a9-654e6317094b','春日寄書代鄉人答','謝翱','宋','宋诗','song-poetry','','[]','滄江失釣緡，白社苦吟身。',48,'全唐诗/poet.song.246000.json','["滄江失釣緡，白社苦吟身。", "風雨他年別，干戈舊國貧。", "春祠占遠夢，臘市憶行人。", "故壘夫差地，遥知哭爲親。"]'),
('2dcf351f-7564-4062-9bfe-7ce0b9ab21ab','人日雪','謝翱','宋','宋诗','song-poetry','','[]','連年逢此日，寂寞在山居。',48,'全唐诗/poet.song.246000.json','["連年逢此日，寂寞在山居。", "故國雲歸盡，高杉雪下初。", "陰霾占戶口，雷電失天書。", "可得俱無事，清吟始晏如。"]'),
('4b79ee65-43f3-4e83-a28e-572d6ebcf8ff','早春寄嶺海流人','謝翱','宋','宋诗','song-poetry','','[]','短褐隨南賈，衰年異壯遊。',48,'全唐诗/poet.song.246000.json','["短褐隨南賈，衰年異壯遊。", "龍旂虛左箇，鴻影別中州。", "晚避高麗使，春乘百濟舟。", "王孫與芳草，相憶可能留。"]'),
('bec24bd2-352e-4308-8273-fa3104b46d2f','過孫君文舊避地處','謝翱','宋','宋诗','song-poetry','','[]','相逢還自失，相見盡天涯。',48,'全唐诗/poet.song.246000.json','["相逢還自失，相見盡天涯。", "鄰壤初移戍，空山此寄家。", "剪茸春過鹿，伐竹舊燒畬。", "去後餘荒槿，依溝結影斜。"]'),
('39ee934d-d1b0-4618-938c-495829c02632','春日遲子芳遊烏龍山','謝翱','宋','宋诗','song-poetry','','[]','烏龍烟靄北，君去爲親留。',48,'全唐诗/poet.song.246000.json','["烏龍烟靄北，君去爲親留。", "綵舞初離席，音書缺寄郵。", "雨登人日冢，槎別客星洲。", "應有他宵約，相從及此遊。"]'),
('e44474ae-96f0-4182-9366-ce4f13f30f2a','奉和毛益亂後經太白墳','謝翱','宋','宋诗','song-poetry','','[]','遥知風雨後，明月濕江蘺。',48,'全唐诗/poet.song.246000.json','["遥知風雨後，明月濕江蘺。", "幾處如寒食，荒流空莫思。", "雨耕侵壞冢，春網得沈碑。", "若起論茲世，先生何所爲。"]'),
('94ff2c60-cd84-4b26-b953-be0aa1a8b02a','憶過徐偃王祠下作','謝翱','宋','宋诗','song-poetry','','[]','徐王遺蹟地，花落舊巖阿。',48,'全唐诗/poet.song.246000.json','["徐王遺蹟地，花落舊巖阿。", "山鬼下茅屋，野雞啼苧蘿。", "別祠江路見，疑冢草間多。", "寒食思家客，空村記所過。"]'),
('edb82150-a8aa-4830-959c-7a32db61563a','山驛送春','謝翱','宋','宋诗','song-poetry','','[]','逢春憶舊時，愛著舊春衣。',48,'全唐诗/poet.song.246000.json','["逢春憶舊時，愛著舊春衣。", "雨別如知處，天涯應共歸。", "驛花留客盡，帆日聚鴉微。", "歲歲子規鳥，寄巢於此飛。"]'),
('62afa139-409d-49af-8542-51df5989329b','蜂','謝翱','宋','宋诗','song-poetry','','[]','蛹黑春如翳，寒崖舉族懸。',48,'全唐诗/poet.song.246000.json','["蛹黑春如翳，寒崖舉族懸。", "撲香粘絮落，采汗近僧禪。", "聚暗移花幄，分喧割蜜烟。", "閑房無處著，應架井泉邊。"]'),
('b68fca07-4f2b-49a7-b560-6e4f4d5dad41','雨中感懷','謝翱','宋','宋诗','song-poetry','','[]','幽齋蒲稗裏，夜色入柴荆。',48,'全唐诗/poet.song.246000.json','["幽齋蒲稗裏，夜色入柴荆。", "坐久雨聲絕，水深荷刺生。", "聽猿思楚宿，失鶴夢南征。", "白屋青山下，何年返舊耕。"]'),
('58f94623-b79e-43bb-b841-4747d8043970','桐華','謝翱','宋','宋诗','song-poetry','','[]','隨風泊釣楂，弄日色侵霞。',48,'全唐诗/poet.song.246000.json','["隨風泊釣楂，弄日色侵霞。", "燒地不鋤草，荒池舊漚麻。", "偶尋僧坐石，見落鳥銜花。", "餳粥春寒後，多逢楝樹家。"]'),
('02a2b4cf-2763-4d6b-ae13-b8854eb0da91','僧池青蛙','謝翱','宋','宋诗','song-poetry','','[]','隠見多無定，時開一道萍。',48,'全唐诗/poet.song.246000.json','["隠見多無定，時開一道萍。", "癭分荷背白，身带蘚文青。", "吐雹收寒井，隨僧入凈缾。", "柏壇祠后稷，應想作龍靈。"]'),
('9091f62f-3523-4472-8f1b-2365fdf06d17','夜宿江山寺','謝翱','宋','宋诗','song-poetry','','[]','寺圖接異境，僧影濕香烟。',48,'全唐诗/poet.song.246000.json','["寺圖接異境，僧影濕香烟。", "落月安禪處，翻經置縣年。", "天河當夏白，泉水入杉懸。", "到此懷甌越，空家寄海邊。"]'),
('879ddea9-e49c-4f15-bc51-662cf4066924','雪榻瀑布','謝翱','宋','宋诗','song-poetry','','[]','潄石清塵暑，雲深畏解携。',48,'全唐诗/poet.song.246000.json','["潄石清塵暑，雲深畏解携。", "寒巖蕭寺下，縣水薜陰西。", "鳥浴濕栖樹，花流晴下溪。", "謫龍聞呪起，奇服反初笄。"]'),
('d0fb2325-e3b0-4d87-b64f-80cd8e6aa2b3','虎石','謝翱','宋','宋诗','song-poetry','','[]','寺深留片石，山雨長苔新。',48,'全唐诗/poet.song.246000.json','["寺深留片石，山雨長苔新。", "昔日栖禪處，遺風想至人。", "錫前行虎獨，鍾後到猿頻。", "越客因逃暑，於茲喜掛巾。"]'),
('a92b11a1-6342-4036-9a8b-3275cccf3203','寺南小池','謝翱','宋','宋诗','song-poetry','','[]','寺南疏小沼，堤隠獺行蹤。',48,'全唐诗/poet.song.246000.json','["寺南疏小沼，堤隠獺行蹤。", "杉影動寒水，夕陽藏半峰。", "清涵落鳥毳，寒怯病僧容。", "聞說初開日，鉢盂盛養龍。"]'),
('0773bab9-53a7-4709-a0f0-6efb9ddd8f19','夏夜山房會宿賦得竹禽','謝翱','宋','宋诗','song-poetry','','[]','入竹雲初翳，餘更警露禽。',48,'全唐诗/poet.song.246000.json','["入竹雲初翳，餘更警露禽。", "羈雌迷故侶，凉意滿西林。", "雨宿移枝暗，明翻下籜深。", "微吟觸幽興，離思不能任。"]'),
('00a52a27-2240-46ce-8e53-a78f944344ee','芭蕉雨','謝翱','宋','宋诗','song-poetry','','[]','吳楚燈前侶，芭蕉海上身。',48,'全唐诗/poet.song.246000.json','["吳楚燈前侶，芭蕉海上身。", "凉宵知過雨，病葉與羈人。", "白屋愁看曉，滄洲宿語貧。", "西南多苦竹，應與越禽鄰。"]'),
('6c222cc4-433b-406b-aa06-1c6110609d46','中秋龍井翫月','謝翱','宋','宋诗','song-poetry','','[]','逢秋月再圓，不與復休眠。',48,'全唐诗/poet.song.246000.json','["逢秋月再圓，不與復休眠。", "腦滿魚龍夜，精藏樹石年。", "嗅衣腥在水，窺戶影疑禪。", "長嘯望參伐，行來精舍邊。"]'),
('ce72eea0-24c9-497e-a856-ee163a10638b','夜坐呈韶卿','謝翱','宋','宋诗','song-poetry','','[]','修行吳楚間，鶴去杳難攀。',48,'全唐诗/poet.song.246000.json','["修行吳楚間，鶴去杳難攀。", "衰世已如此，愁身更入山。", "巢居避太歲，藥飯救羸顔。", "故友在江海，相思不得還。"]'),
('44f8b1da-e57a-4eba-ba75-395a3b26f83f','韶卿往烏傷寄劉元益','謝翱','宋','宋诗','song-poetry','','[]','他日憶逢君，林中訪恵勤。',48,'全唐诗/poet.song.246000.json','["他日憶逢君，林中訪恵勤。", "鹿麛行處見，流水別時聞。", "草沒秦人冢，山通越國雲。", "音書年歲失，莫訝白鷗群。"]'),
('fb497d21-0529-4984-8db1-e5dbf535c398','寄贈王僉判龍澤新之官廣陵','謝翱','宋','宋诗','song-poetry','','[]','多君孝子里，雲物尚依然。',48,'全唐诗/poet.song.246000.json','["多君孝子里，雲物尚依然。", "歲晏木葉下，月明湖水邊。", "看圖須女分，對策亮陰年。", "到此若爲別，猶言贈馬鞭。"]'),
('37882ea4-844c-4852-9728-1f87d596c5e5','十日菊寄所思','謝翱','宋','宋诗','song-poetry','','[]','籬菊是秋鄰，青蕤幾日新。',48,'全唐诗/poet.song.246000.json','["籬菊是秋鄰，青蕤幾日新。", "忽逢初過節，相憶早衰人。", "囊枕離湘濕，分杯度嶺貧。", "想應無事業，遥念更沾巾。"]'),
('5702bd64-0546-4fc6-86c0-29806db7d4aa','野霞觀瀑','謝翱','宋','宋诗','song-poetry','','[]','他年疏上浮，早日此中投。',72,'全唐诗/poet.song.246000.json','["他年疏上浮，早日此中投。", "汲飲當魚入，垂綸即𧈭遊。", "凈祠無血食，噀雨不腥流。", "僧語皆前事，人來盡別州。", "草諳長過雪，沙犯欲捐湫。", "至竟何依止，蒼茫難禱求。"]'),
('aa10e703-12a2-4d45-99d7-2768750db810','己丑除夜','謝翱','宋','宋诗','song-poetry','','[]','鬢絲殘雪影，况復在塵埃。',48,'全唐诗/poet.song.246000.json','["鬢絲殘雪影，况復在塵埃。", "暮色隨鐘盡，年光逐水來。", "鄰逋燈下索，鄉夢戍邊回。", "明日聽春雨，渡江登越臺。"]'),
('dafc57ef-9555-433e-86a8-abe32908ccfd','元旦立春','謝翱','宋','宋诗','song-poetry','','[]','椒柏多年樹，閑庭憶粵鄉。',48,'全唐诗/poet.song.246000.json','["椒柏多年樹，閑庭憶粵鄉。", "發春當獻歲，爲客未休糧。", "飲後憐衰齒，行南避忌方。", "星周元朔曆，時運可能忘。"]'),
('6800b337-0ba3-419f-974e-e209ec97829a','寒食同方行父明中往淥渚舟中作寄東安方子仁','謝翱','宋','宋诗','song-poetry','','[]','自食嶼雲薇，聞君白接籬。',48,'全唐诗/poet.song.246000.json','["自食嶼雲薇，聞君白接籬。", "謁靈隨社到，爲客寄音遲。", "瓢入新城水，舟回故渚祠。", "南衣離火浣，垢敝禁烟時。"]'),
('f08d60cc-d681-42ae-beea-f7c7d6aa848f','萬松道中望南太白','謝翱','宋','宋诗','song-poetry','','[]','笋輿行萬山，中有十里亭。',72,'全唐诗/poet.song.246000.json','["笋輿行萬山，中有十里亭。", "老樹祇一色，野公逾百齡。", "柴關當太白，藥氣近樵青。", "罔草粘枯翼，巢枝落退翎。", "期探幽谷水，共斸松根苓。", "艾納下天雨，塵風吹冥冥。"]'),
('8b42b4e5-a834-4cb5-8ddd-d2899c347dcf','雨宿太白','謝翱','宋','宋诗','song-poetry','','[]','城中家斧冰，此地絕炎蒸。',96,'全唐诗/poet.song.246000.json','["城中家斧冰，此地絕炎蒸。", "天食青童捧，龍居白氣升。", "暗燈猶宿火，寢服尚衷繒。", "客話從前事，書傳入內僧。", "風流今獨盡，雲物老相仍。", "凈榻搜凉卧，危闌入醉凭。", "雨師行下界，鳥夢識中乘。", "明發甬南去，他山逢智弘。"]'),
('a13059fc-7f46-4203-bbd5-0aa3d50b7127','寄育王賢上人','謝翱','宋','宋诗','song-poetry','','[]','于今祇老身，從昔少埃塵。',48,'全唐诗/poet.song.246000.json','["于今祇老身，從昔少埃塵。", "失蜀年爲客，居山石作鄰。", "南遊宗竺法，西語問巴人。", "開戶藤花落，多浮茗椀春。"]'),
('8e83997d-47c3-4800-b1d5-41604092ec7c','海亭夜坐','謝翱','宋','宋诗','song-poetry','','[]','孤身滯海垠，暑溽上南雲。',48,'全唐诗/poet.song.246000.json','["孤身滯海垠，暑溽上南雲。", "歸日喜秋近，愁人畏夜分。", "坐凉依井氣，眠濕動星文。", "故友在山北，音書不得聞。"]'),
('30bcf113-3076-4d1a-bc81-79fb34231e09','採藥候潮山宿山頂精藍夜中望海','謝翱','宋','宋诗','song-poetry','','[]','蛟門南去鳥，此地望迢迢。',96,'全唐诗/poet.song.246000.json','["蛟門南去鳥，此地望迢迢。", "積濕侵幡黑，生寒入夢飄。", "見燈歸舶夜，聞偈解衣朝。", "土植皆爲藥，山枝不滿樵。", "暗光珠母徙，秋影石花消。", "擬候槎回漢，寧甘客老遼。", "却尋徐福島，因問秦皇橋。", "於彼看日出，羽旌焉可招。"]'),
('36ab7899-fd06-433e-a11f-084e66463559','夜宿雪竇上方','謝翱','宋','宋诗','song-poetry','','[]','眠山枕斧柯，獨客愛盤阿。',72,'全唐诗/poet.song.246000.json','["眠山枕斧柯，獨客愛盤阿。", "畏日生塵夢，尋仙到鳥窠。", "下方聞夕磬，南斗挂秋河。", "寢服侵雲卷，頮泉通瀑和。", "竇分滄海月，禪入沃洲歌。", "此地精靈聚，中宵弄薜蘿。"]'),
('10a54446-20fa-4ca4-becf-637ea3cd9db7','魯國圖詩','謝翱','宋','宋诗','song-poetry','','[]','秋風嶽下城，海客見圖新。',48,'全唐诗/poet.song.246000.json','["秋風嶽下城，海客見圖新。", "樹入舞雩里，水來浮磬濱。", "東封餘輦路，西狩問虞人。", "被髪逢夫子，狂歌作放民。"]'),
('66609727-c2b8-4107-a6b8-3ff6990e51fc','董孝子墓','謝翱','宋','宋诗','song-poetry','','[]','修修古孝子，家移來水旁。',48,'全唐诗/poet.song.246000.json','["修修古孝子，家移來水旁。", "母病食此水，母死葬其鄉。", "殺人自白吏，就家起爲郎。", "至今廟下草，猶带食水香。"]'),
('910be0da-b7d2-4e68-938d-5a58268627d5','過杭州故宮二首  其一','謝翱','宋','宋诗','song-poetry','','[]','禾黍何人爲守閽，落花臺殿暗銷魂。',32,'全唐诗/poet.song.246000.json','["禾黍何人爲守閽，落花臺殿暗銷魂。", "朝元閣下歸來燕，不見前頭鸚鵡言。"]'),
('dd3bfd61-8364-4b86-9611-f2e90026f8a8','過杭州故宮二首  其二','謝翱','宋','宋诗','song-poetry','','[]','紫雲樓閣讌流霞，今日凄凉佛子家。',32,'全唐诗/poet.song.246000.json','["紫雲樓閣讌流霞，今日凄凉佛子家。", "殘照下山花霧散，萬年枝上挂袈裟。"]'),
('4d824eab-cf78-4e63-8058-de16e02d728e','重過二首  其一','謝翱','宋','宋诗','song-poetry','','[]','複道垂楊草欲交，武林無樹著凌霄。',32,'全唐诗/poet.song.246000.json','["複道垂楊草欲交，武林無樹著凌霄。", "野猿引子移來住，覆盡花枝翡翠巢。"]'),
('62a2008d-7f05-4db9-b49b-f5229d40a75c','重過二首  其二','謝翱','宋','宋诗','song-poetry','','[]','隔江風雨動諸陵，無主園池草自春。',32,'全唐诗/poet.song.246000.json','["隔江風雨動諸陵，無主園池草自春。", "聞說就中誰最泣，女冠猶有舊宮人。"]'),
('8e8ef771-0251-42b6-b13a-e7ba7b8e9530','野望','謝翱','宋','宋诗','song-poetry','','[]','心遊太古後，轉覺此生浮。',48,'全唐诗/poet.song.246000.json','["心遊太古後，轉覺此生浮。", "天外知何物，山中著得愁。", "岸花低草色，潮水逆江流。", "消盡盈虛裏，令人白盡頭。"]'),
('c6b33237-9f6e-4d08-97a9-f0123589b6fc','無題','謝翱','宋','宋诗','song-poetry','','[]','天風下黄葉，山樹挂綠蓑。',48,'全唐诗/poet.song.246000.json','["天風下黄葉，山樹挂綠蓑。", "世情逐流水，東去無迴波。", "可與語人少，不成眠夜多。", "濕雲黏短髪，漂泊奈愁何。"]'),
('b23f66ab-984a-4511-8a3b-dad68ffc66aa','春閨詞','謝翱','宋','宋诗','song-poetry','','[]','手觸殘紅頭懶梳，香隨蝴蝶上衣裾。',32,'全唐诗/poet.song.246000.json','["手觸殘紅頭懶梳，香隨蝴蝶上衣裾。", "暖風吹睡無言語，又向床頭看夢書。"]'),
('0e07e96e-b4e2-49cb-8446-82c4c02fd60d','四皓','謝翱','宋','宋诗','song-poetry','','[]','冷却秦灰鬢已翁，紫芝歌罷落花風。',32,'全唐诗/poet.song.246000.json','["冷却秦灰鬢已翁，紫芝歌罷落花風。", "若教一出無遺恨，莫入留侯準擬中。"]'),
('f0387764-de5c-4cb4-83db-acfc03cc8e5a','散髪','謝翱','宋','宋诗','song-poetry','','[]','乾坤一楚囚，散髪向滄洲。',48,'全唐诗/poet.song.246000.json','["乾坤一楚囚，散髪向滄洲。", "詩病多於馬，身閒不似鷗。", "因看東去水，都是夜來愁。", "晚意落花覺，殘枝香更幽。"]'),
('5d840796-a88f-4b21-b07c-200b4862e41e','友人自杭回建寄別三首  其一','謝翱','宋','宋诗','song-poetry','','[]','同來不同去，離別暗銷魂。',24,'全唐诗/poet.song.246000.json','["同來不同去，離別暗銷魂。", "閩浙若同水，遍舟送到門。"]'),
('fb49f0a8-bb1a-4122-81c1-915146c2414e','友人自杭回建寄別三首  其二','謝翱','宋','宋诗','song-poetry','','[]','潮信到巖瀨，水色過衢城。',24,'全唐诗/poet.song.246000.json','["潮信到巖瀨，水色過衢城。", "寄潮不寄水，潮去有回程。"]'),
('a829f24d-a59c-4c1c-8a51-93ed6924e7dd','友人自杭回建寄別三首  其三','謝翱','宋','宋诗','song-poetry','','[]','水到衢城盡，梅花上嶺生。',24,'全唐诗/poet.song.246000.json','["水到衢城盡，梅花上嶺生。", "不如寄明月，步步送君行。"]'),
('67c42003-2cb7-4123-97c7-c2c2036b4b07','孤山','謝翱','宋','宋诗','song-poetry','','[]','又冒晴絲向水涯，寒雲冉冉護巾紗。',64,'全唐诗/poet.song.246000.json','["又冒晴絲向水涯，寒雲冉冉護巾紗。", "能知綠鬢幾回至，欲行黄冠此處家。", "已把掖垣等茅舍，不愁封禪對梅花。", "晚風吹袂過船去，看鶴上天衝碧霞。"]'),
('eaa7545c-3c92-4a7f-a1bf-512dd05e71b4','雪','謝翱','宋','宋诗','song-poetry','','[]','片片知何似，無根零亂花。',48,'全唐诗/poet.song.246000.json','["片片知何似，無根零亂花。", "任隨飛到處，不揀是誰家。", "縫密天如翳，擎深樹半斜。", "城中新酒貴，羈旅若爲賒。"]'),
('19bfcbc9-37b8-456e-8638-98eeb93d2448','畫秦宮人','謝翱','宋','宋诗','song-poetry','','[]','結草爲衣類鶴翎，初來一味服黄精。',32,'全唐诗/poet.song.246000.json','["結草爲衣類鶴翎，初來一味服黄精。", "宮鶑幾處啣花出，猶向山中認得聲。"]'),
('68e6f088-87a2-472e-aa50-0cfd96a5bc82','織婦嘆','謝翱','宋','宋诗','song-poetry','','[]','待得𧔞蠶繭上絲，織成送女去還歸。',32,'全唐诗/poet.song.246000.json','["待得𧔞蠶繭上絲，織成送女去還歸。", "支機本是寒砧石，留取秋深自搗衣。"]'),
('99e9194e-7aec-43e1-817e-c0aac937724d','商人婦','謝翱','宋','宋诗','song-poetry','','[]','抱兒來拜月，去日爾初生。',48,'全唐诗/poet.song.246000.json','["抱兒來拜月，去日爾初生。", "已自滿三歲，無人問五行。", "孤燈寒杵石，殘夢遠鐘聲。", "夜夜鄰家女，吹簫到二更。"]'),
('e34c24da-1111-404a-97b1-1f67b8316a43','憶湖上','謝翱','宋','宋诗','song-poetry','','[]','擾擾忽半月，征衣雜市塵。',48,'全唐诗/poet.song.246000.json','["擾擾忽半月，征衣雜市塵。", "頗疑湖上客，不是城中人。", "岸柳垂拂槳，山雲泫濕巾。", "明朝在何處，相怪墮凡身。"]'),
('8916b0c3-9309-4ee7-b604-0996b72ced6a','悼古季清','謝翱','宋','宋诗','song-poetry','','[]','典刑前一輩，言語尚風流。',48,'全唐诗/poet.song.246000.json','["典刑前一輩，言語尚風流。", "詩律縛不住，梅花惱得愁。", "雲烟今變滅，老病總宜休。", "喚醒菟裘夢，嚴城上雨秋。"]'),
('a5bc8076-c20d-4fa0-a95f-17648c112d31','蠟梅','謝翱','宋','宋诗','song-poetry','','[]','冷艷清香受雪知，雨中誰把蠟爲衣。',32,'全唐诗/poet.song.246000.json','["冷艷清香受雪知，雨中誰把蠟爲衣。", "蜜房做就花枝色，留得寒蜂宿不歸。"]'),
('882320bd-8281-467b-8b65-7ecc5152454d','留別顧君際','謝翱','宋','宋诗','song-poetry','','[]','萬里行可到，詩人吟到難。',48,'全唐诗/poet.song.246000.json','["萬里行可到，詩人吟到難。", "愁來時自語，寫出許誰看。", "月落望如失，山空坐更寒。", "此時多少意，欲別路漫漫。"]'),
('77d8b09b-0441-47c0-a9de-fb5e4f45cd75','後桂花引','謝翱','宋','宋诗','song-poetry','','[]','修月山人飯玉屑，瑶鴨騰騰何處熱。',64,'全唐诗/poet.song.246000.json','["修月山人飯玉屑，瑶鴨騰騰何處熱。", "吳剛生愁樹合創，毫飄玉斧高枝折。", "此時待罪扣帝庭，素蛾騎蟾涕泪零。", "月中落子如雨星，至今收拾無六丁。"]'),
('0d70797c-e857-40c8-a1c6-9bbf8b299732','吳山謁祠','謝翱','宋','宋诗','song-poetry','','[]','吳山坊頂戴高祠，禁地凄凉江水悲。',32,'全唐诗/poet.song.246000.json','["吳山坊頂戴高祠，禁地凄凉江水悲。", "却是北人題記壁，迤南耆舊獨無詩。"]'),
('7a57ed75-f78a-4f03-a7ec-017849e653ce','雪後湖堤步歸','謝翱','宋','宋诗','song-poetry','','[]','無求如有得，散策堤邊行。',48,'全唐诗/poet.song.246000.json','["無求如有得，散策堤邊行。", "山碧眼花亂，水寒毛孔生。", "窮冬疑有雨，一雪却成晴。", "勞謝天涯月，相隨步入城。"]'),
('fa089b71-41ef-4300-804b-521035af3b9c','梅花二首  其一','謝翱','宋','宋诗','song-poetry','','[]','春過江南問故家，孤根生夢半槎牙。',32,'全唐诗/poet.song.246000.json','["春過江南問故家，孤根生夢半槎牙。", "到無香去飄成雪，未有葉來開盡花。"]'),
('f27849d2-45be-43bc-aa7e-539b4857d7f7','梅花二首  其二','謝翱','宋','宋诗','song-poetry','','[]','吹老單于月一痕，江南知是幾黄昏。',32,'全唐诗/poet.song.246000.json','["吹老單于月一痕，江南知是幾黄昏。", "水仙冷落瓊花死，祇有南枝尚返魂。"]'),
('9dfc0843-4d66-4612-a5df-2afa60ecc184','往姑蘇與友人別杭州','謝翱','宋','宋诗','song-poetry','','[]','北關到吳會，烟草亦詩情。',48,'全唐诗/poet.song.246000.json','["北關到吳會，烟草亦詩情。", "飲少但知價，行疏數問程。", "天陰月不死，江闊水能生。", "別後不得寐，相思還二更。"]'),
('edc645ca-67a5-4f95-8eb4-74270536bd45','雪霽有感','謝翱','宋','宋诗','song-poetry','','[]','夜長春度夢，門雪擁笆籬。',48,'全唐诗/poet.song.246000.json','["夜長春度夢，門雪擁笆籬。", "不倚成山積，情知有霽時。", "日高簷自雨，氣上瓦如炊。", "風過梅花濕，寒香只戀枝。"]'),
('8d42e6bc-5e41-4e78-bbbb-890525f88d75','山中道士','謝翱','宋','宋诗','song-poetry','','[]','山中道士服朝霞，二十修行別故家。',32,'全唐诗/poet.song.246000.json','["山中道士服朝霞，二十修行別故家。", "留客一杯清苦蜜，蜂房知是近梅花。"]'),
('48066776-5e31-46ac-9573-1daec269ac41','餘杭樵歌','謝翱','宋','宋诗','song-poetry','','[]','樵斧丁丁響翠微，頳肩半脫汗身衣。',32,'全唐诗/poet.song.246000.json','["樵斧丁丁響翠微，頳肩半脫汗身衣。", "因來避雨巖前洞，裹得山蜂和蜜歸。"]'),
('f7c95614-0e6c-406e-aaa7-34e85e6a9b70','書文山卷後','謝翱','宋','宋诗','song-poetry','','[]','魂飛萬里程，天地隔幽明。',48,'全唐诗/poet.song.246000.json','["魂飛萬里程，天地隔幽明。", "死不從公死，生如無此生。", "丹心渾未化，碧血已先成。", "無處堪揮泪，吾今變姓名。"]'),
('0c1da981-0c1b-4903-8bd7-6de9ca3ef753','十年','謝翱','宋','宋诗','song-poetry','','[]','忘却寒溫語，相逢一揖休。',48,'全唐诗/poet.song.246000.json','["忘却寒溫語，相逢一揖休。", "十年只如此，今日若爲愁。", "月白夜亦晝，山寒春更秋。", "無情溪澗水，只是下灘流。"]'),
('3dfb45f7-e85b-498e-acf0-9070361f68f7','秋夜詞','謝翱','宋','宋诗','song-poetry','','[]','愁生山外山，恨殺樹邊樹。',24,'全唐诗/poet.song.246000.json','["愁生山外山，恨殺樹邊樹。", "隔斷秋月明，不使共一處。"]'),
('f05f28c4-5564-4528-8367-affb1ea82655','除夜舟中遇雪','謝翱','宋','宋诗','song-poetry','','[]','歲月安有限，利名心未灰。',48,'全唐诗/poet.song.246000.json','["歲月安有限，利名心未灰。", "雪飛今夜止，潮去隔年來。", "交友窮中見，江山盡處回。", "家人誰念道，耳熱不因杯。"]'),
('d640a304-d501-4992-87d1-c243039cbcd3','元旦舟中聽潮','謝翱','宋','宋诗','song-poetry','','[]','東望拜潮水，無家在客船。',48,'全唐诗/poet.song.246000.json','["東望拜潮水，無家在客船。", "一來仍一往，今日又今年。", "有信從天外，緣聲到枕邊。", "海門春樹暖，吹浪起晴烟。"]'),
('01008a0c-9ed0-4c66-ba92-42fc5f2771cc','鸕鷀步尋方元英故居','謝翱','宋','宋诗','song-poetry','','[]','遺像雙臺下，結廬烟水傍。',48,'全唐诗/poet.song.246000.json','["遺像雙臺下，結廬烟水傍。", "子孫今幾世，風雨半他鄉。", "山靜雲眠影，葉乾蟲食香。", "高名故相壓，吟苦不成章。"]'),
('9fbf2c1c-c725-4006-9cdd-6430eaa1951d','青篛亭','謝翱','宋','宋诗','song-poetry','','[]','青山何處似，疑是剡溪傍。',48,'全唐诗/poet.song.246000.json','["青山何處似，疑是剡溪傍。", "採篛無人到，生莎滿徑荒。", "水交難辨色，花和不同香。", "歸路逢樵子，麻衣草結裳。"]'),
('38df19f2-d8da-49ff-9732-bc7662d9b2d9','題酒家壁','謝翱','宋','宋诗','song-poetry','','[]','綠陰深處問天涯，黄鳥聲中見酒家。',32,'全唐诗/poet.song.246000.json','["綠陰深處問天涯，黄鳥聲中見酒家。", "樹上猢猻摘殘果，向來纔見是春花。"]'),
('b9d73226-ccb6-4fc5-be83-33dd1f9e1db0','正三立春','謝翱','宋','宋诗','song-poetry','','[]','舟中隔歲話，偪仄信誰從。',48,'全唐诗/poet.song.246000.json','["舟中隔歲話，偪仄信誰從。", "山带去年雪，春來何處峰。", "移軍增野竈，落磧減機舂。", "明日金華洞，牧羊尋故蹤。"]'),
('87f678dd-4e89-41ca-8932-c8c9b0c94f18','贈山中友','謝翱','宋','宋诗','song-poetry','','[]','散策亂山雲，值此山林友。',48,'全唐诗/poet.song.246000.json','["散策亂山雲，值此山林友。", "種松高及身，掃葉落隨手。", "斫盡松上枝，縛作山中帚。", "夜夜對西峰，明月生戶牖。"]'),
('890e5b6c-f9cd-4cdf-b070-8d4fb90d88c5','沙岸登舟','謝翱','宋','宋诗','song-poetry','','[]','五里兒女步，虛沙映斷筇。',48,'全唐诗/poet.song.246000.json','["五里兒女步，虛沙映斷筇。", "雲支半山石，帆席上溪風。", "數雁憐身隻，聞鵑願耳聾。", "市橋東半榻，側影夕陽中。"]'),
('6df8f0d9-7d1d-462c-b817-e0d2d49e2815','僧房疥壁','謝翱','宋','宋诗','song-poetry','','[]','松樹落釵股，曉行猶見燈。',48,'全唐诗/poet.song.246000.json','["松樹落釵股，曉行猶見燈。", "圓亭方井水，老寺少年僧。", "澗響夜疑雨，雲寒春欲冰。", "山僮錯相認，應道我來曾。"]'),
('bf01e4ed-dd1e-4fdd-98aa-c64259f5d607','山居','謝翱','宋','宋诗','song-poetry','','[]','宿火石中取，人烟隔斷霞。',48,'全唐诗/poet.song.246000.json','["宿火石中取，人烟隔斷霞。", "盜侵鄰壤粟，女寄外翁家。", "野樹刺生葉，枯松藤纏花。", "老翁頭未白，相對話天涯。"]'),
('af5b739d-f19b-46a8-ad89-be6f2d2e458a','望仙都山二首  其一','謝翱','宋','宋诗','song-poetry','','[]','鼎湖只在柱峰上，地險山空不可家。',32,'全唐诗/poet.song.246000.json','["鼎湖只在柱峰上，地險山空不可家。", "山下人居五六月，天風吹雨碧荷花。"]'),
('844c4c29-c0c4-4ea3-9006-b831166f454e','望仙都山二首  其二','謝翱','宋','宋诗','song-poetry','','[]','道人誦經半峰下，洞裏山神不敢歸。',32,'全唐诗/poet.song.246000.json','["道人誦經半峰下，洞裏山神不敢歸。", "我欲乘風到峰頂，擘翻荷葉作蓑衣。"]'),
('c371ac74-229e-43e8-a6b6-702c16eecc07','疊山','謝翱','宋','宋诗','song-poetry','','["\u592a\u6e56"]','礧磈復崔嵬，晴雲撥不開。',48,'全唐诗/poet.song.246000.json','["礧磈復崔嵬，晴雲撥不開。", "鐘聞上界響，石自太湖來。", "靈草擣爲藥，寒松燼作煤。", "欲窮登覽興，未到已徘徊。"]'),
('23b76c8e-a6f3-4faf-9fef-fdae6b80a7f0','社前','謝翱','宋','宋诗','song-poetry','','[]','無家借燕住，離別又經年。',48,'全唐诗/poet.song.246000.json','["無家借燕住，離別又經年。", "客館依山上，春分到社前。", "雨來換宿水，雲起暗晴川。", "颯颯吹衣带，因風問去船。"]'),
('d43b165b-9a3d-4b5f-9c70-e6881ff0ad3a','艤舟江心寺','謝翱','宋','宋诗','song-poetry','','[]','數聲清磬出晴暮，落木人家散烟霧。',32,'全唐诗/poet.song.246000.json','["數聲清磬出晴暮，落木人家散烟霧。", "風送年年江上潮，白雲生根吹不去。"]'),
('591f416b-779f-4c1f-9a07-f3f991bac848','歲月','謝翱','宋','宋诗','song-poetry','','[]','歲月記不得，曾行此處村。',48,'全唐诗/poet.song.246000.json','["歲月記不得，曾行此處村。", "日欹眠石影，樹長蝕藤根。", "晚羨棲猿鳥，春來問子孫。", "勞生空可說，不是欲忘言。"]'),
('1a97727e-a8ba-4ae0-834f-d249ca61f755','霅女吟','謝翱','宋','宋诗','song-poetry','','[]','罨畫溪頭歛翠眉，綠楊扶起又低垂。',32,'全唐诗/poet.song.246000.json','["罨畫溪頭歛翠眉，綠楊扶起又低垂。", "春風盡與花爲主，不解庭前百結枝。"]'),
('efe0be11-bf11-48de-8fbd-937d4d309750','文房四友歎','謝翱','宋','宋诗','song-poetry','','[]','昆吾莫邪輕毛錐，平生故人皆引去。',192,'全唐诗/poet.song.246000.json','["昆吾莫邪輕毛錐，平生故人皆引去。", "剡溪之皙絳邑黔，獨與石君作一處。", "中書間起免冠謝，輒被溺冠仍嫚駡。", "見幾自媿後穆生，正恐髠舂不與赦。", "有時怒髪豎相如，熟視蒙恬挽其鬚。", "泓尤淪棄敢自愛，老龜支床息猶在。", "荆山風雨朝暮號，璞在吾懷足何罪。", "恨不雪恥酬諸姬，背水一戰漢爲池。", "楮生不改舊邊幅，三褫何但高閣束。", "客卿騎項百折磨，猶恐玄能赤吾族。", "此時不平義重生，陽城裂麻欲死爭。", "平生國士立橋下，誓死守此漆身啞。"]'),
('13ab21bc-d676-4ce0-9058-9167c0cf7552','秋社寄山中故人','謝翱','宋','宋诗','song-poetry','','[]','燕子來時人送客，不堪離別淚沾衣。',32,'全唐诗/poet.song.246000.json','["燕子來時人送客，不堪離別淚沾衣。", "如今爲客秋風裏，更向人家送燕歸。"]'),
('842bb68f-a334-4b34-8898-b746e141f5b4','登西臺作楚歌招文丞相魂','謝翱','宋','宋诗','song-poetry','','[]','魂朝往兮何極，莫歸來兮關塞黑，化爲朱鳥兮有咮焉食。',25,'全唐诗/poet.song.246000.json','["魂朝往兮何極，莫歸來兮關塞黑，化爲朱鳥兮有咮焉食。"]'),
('2e4ea5a7-fa62-4e11-ae5c-a511fcaa593a','續琴操哀江南 我赴薊門四之一','謝翱','宋','宋诗','song-poetry','','[]','我赴薊門，我心何苦。',80,'全唐诗/poet.song.246000.json','["我赴薊門，我心何苦。", "我本南人，我行北土。", "視彼翼軫，客星光光。", "自陪輦轂，久涉戎行。", "靡歲不戰，何兵不潰。", "偷生有慼，就死無罪。", "莽莽黄沙，依依翠華。", "我皇何在，忍恤我家。"]'),
('d97ecd99-1958-4d0b-9d68-8824b7ce1707','續琴操哀江南 瞻彼江漢四之二','謝翱','宋','宋诗','song-poetry','','[]','瞻彼江漢，截淮及楚。',80,'全唐诗/poet.song.246000.json','["瞻彼江漢，截淮及楚。", "起兵海隈，亡命無所。", "枕戈待旦，憤不顧身。", "我視王室，誰非國人。", "噫嘻昊天，使汝縲絏。", "姦黨心寒，健兒膽裂。", "黄河萬里，冰雪峨峨。", "爾死得死，我生謂何。"]'),
('30a3a1f1-ffdd-4e42-b4fe-00f7ca1815b3','續琴操哀江南 我操南音四之三','謝翱','宋','宋诗','song-poetry','','[]','我操南音，爰𮠨我酒。',80,'全唐诗/poet.song.246000.json','["我操南音，爰𮠨我酒。", "風摧我裳，冰裂我手。", "薄送于野，曷云同歸。", "自貽伊阻，不得奮飛。", "持此盈觴，化爲別淚。", "昔也姬姜，今焉憔悴。", "山高水遠，無相見時。", "各保玉體，將死爲期。"]'),
('7a346493-27c6-4ae3-98eb-1bb4f7c3f389','續琴操哀江南 興言自古四之四','謝翱','宋','宋诗','song-poetry','','[]','興言自古，使我速老。',80,'全唐诗/poet.song.246000.json','["興言自古，使我速老。", "麋鹿是游，姑蘇荒草。", "起秣我馬，裴回舊鄉。", "江山不改，風景忘亡。", "誰觸塵埃，不見日月。", "梨園雲散，羽林鳥沒。", "吞聲躑躅，悲風四來。", "爾非遺民，胡獨不哀。"]'),
('99096a5b-79b9-494e-a38a-8cca70f35811','立春日同陳有之步至賀家湖','謝翱','宋','宋诗','song-poetry','','[]','風烟回首失，歲月但尋常。',48,'全唐诗/poet.song.246000.json','["風烟回首失，歲月但尋常。", "忠義行衰世，淒凉在異鄉。", "春流荒禹蹟，天淚濕句芒。", "擬剪園中韭，携籃有跛臧。"]'),
('847720c2-7472-403b-b11f-b0b08e450a27','黄精','謝翱','宋','宋诗','song-poetry','','[]','野鹿銜花見却馴，山人采葯避徭征。',32,'全唐诗/poet.song.246000.json','["野鹿銜花見却馴，山人采葯避徭征。", "塵中劍米無炊甑，自洗黄精九曝蒸。"]'),
('3e8192b9-1951-49ce-9edf-0bb897a042b4','西巖 天壇','謝翱','宋','宋诗','song-poetry','','[]','風吹軟桂枝，下掃西南氛。',24,'全唐诗/poet.song.246000.json','["風吹軟桂枝，下掃西南氛。", "壇中仙人影，冉冉化爲雲。"]'),
('5bc25722-8cdb-42d4-a36e-acbd48af9b72','西巖 天扉','謝翱','宋','宋诗','song-poetry','','[]','朝從雙扉出，莫從雙扉還。',24,'全唐诗/poet.song.246000.json','["朝從雙扉出，莫從雙扉還。", "狂風吹山花，落我衣袖間。"]'),
('8f427128-b26d-4b43-8859-5a4cff175151','西巖 雪壁','謝翱','宋','宋诗','song-poetry','','[]','麻姑東南別，衣袂濕空翠。',24,'全唐诗/poet.song.246000.json','["麻姑東南別，衣袂濕空翠。", "雪中米黄花，願餉西南使。"]'),
('0be31fdb-f2d7-4a73-a61e-ec8db2985296','烟蘿洞','謝翱','宋','宋诗','song-poetry','','[]','山人挂綠蘿，亂後到人多。',48,'全唐诗/poet.song.246000.json','["山人挂綠蘿，亂後到人多。", "夜久積空翠，天深聞櫂歌。", "禱龍疑井厭，看鶴值仙過。", "搔首愁紛白，無窮奈此何。"]'),
('0746c1b1-f399-4e20-a3c7-d07ff51daa12','寄王監簿英孫','謝翱','宋','宋诗','song-poetry','','[]','天柱西南隅，開窗見雪初。',48,'全唐诗/poet.song.246000.json','["天柱西南隅，開窗見雪初。", "野泉過濕竹，仙鳥下巢樗。", "草長平新塹，門閒閉舊居。", "他年賓從在，誰得入鷗書。"]'),
('ca068aad-3dd9-4e9d-a506-8a079e5168f2','義門曲','謝翱','宋','宋诗','song-poetry','','[]','金蓉山上雲采采，白麟溪前水歸海。',128,'全唐诗/poet.song.246000.json','["金蓉山上雲采采，白麟溪前水歸海。", "溪中赤文長鯉魚，恨無神翅謁龍威。", "廣陵城頭大風急，吹散遊魂歸未得。", "不結瓊英后土祠，當充蘭佩離騷國。", "富貴易奪生莫移，誰肯殺身爲聯枝。", "鶺鴒原上赴急難，我有冠裳可不如。", "子孫至今無裂籍，六代傳來猶一日。", "白頭秀才誇能文，得似君家好弟昆。"]'),
('a1675ac4-7e1b-40bd-b93d-8e67edfd34a5','寄韶卿','謝翱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','莫因梅柳憶西湖，且守仙華小隠居。',64,'全唐诗/poet.song.246000.json','["莫因梅柳憶西湖，且守仙華小隠居。", "霜木絕憐諸老盡，雨燈動是十年疏。", "休官陶令長思友，陋巷嵇康懶報書。", "衣食有餘休浪出，我愁無地可耕漁。"]'),
('aeb2da5c-9118-424d-945e-b16e90ec821c','送張士達遊黄山歌','謝翱','宋','宋诗','song-poetry','','[]','黄山三十六點雲，中秘幽奇世人未見猶未聞。',142,'全唐诗/poet.song.246000.json','["黄山三十六點雲，中秘幽奇世人未見猶未聞。", "混沌乍開始自大唐國，易黟爲黄而附軒轅鍊丹盟仙群。", "天都蓮花突兀直入青雲上，諸峰吐烟噴雪如波之蕩漾平天矼。", "是蛟龍飛舞變幻而莫測，下有海深萬丈空洞氤氳雲吼浪。", "更有仙燈諸洞九龍諸潭仙橋月塔諸勝蹟。", "君今策杖蠟屐走險一一當遍歷，須令向禽宗炳之輩嘆羨而莫及。"]'),
('49e3bf7f-c2d4-4dc4-84dd-6e701ae7c1f1','句','謝翱','宋','宋诗','song-poetry','','[]','謝豹花開桑葉齊，戴勝芊生藥草肥，九鎖山人歸未歸。',24,'全唐诗/poet.song.246000.json','["謝豹花開桑葉齊，戴勝芊生藥草肥，九鎖山人歸未歸。"]'),
('fabe9f52-0c9c-4c39-b2ea-944c79600e4e','新秋','羅公升','宋','宋诗','song-poetry','','[]','團扇初辭暑，虛簷恰受風。',24,'全唐诗/poet.song.246000.json','["團扇初辭暑，虛簷恰受風。", "簾花孤月冷，秋在不聲中。"]'),
('8aad21d1-f78a-494b-8512-a4a022f4cd52','禽言 日中烏','羅公升','宋','宋诗','song-poetry','','[]','日中有癡烏，食日療饑腹。',24,'全唐诗/poet.song.246000.json','["日中有癡烏，食日療饑腹。", "不省日無光，此身難駐足。"]'),
('d5787bf7-3bca-4fce-877c-4980b91c736b','禽言 梟','羅公升','宋','宋诗','song-poetry','','[]','人誰獨無母，汝母良可悲。',24,'全唐诗/poet.song.246000.json','["人誰獨無母，汝母良可悲。", "汝飽詎幾乎，亦有生子時。"]'),
('3671ffa9-58bb-4efe-bbdf-6eb8d83d142c','禽言 夜鶴','羅公升','宋','宋诗','song-poetry','','[]','月黑衆慝起，夜鶴乘時呼。',24,'全唐诗/poet.song.246000.json','["月黑衆慝起，夜鶴乘時呼。", "懸知不足畏，奈此淵中□。"]'),
('2b9814b8-920d-4d6c-94f9-399a7cee1ffc','秋懷  其一','羅公升','宋','宋诗','song-poetry','','[]','錢塘八月潮，勝絕聞古今。',24,'全唐诗/poet.song.246000.json','["錢塘八月潮，勝絕聞古今。", "吳兒識潮耳，不識潮中心。"]'),
('2d011971-b571-4bd8-b0e7-b1eeaac754e0','秋懷  其二','羅公升','宋','宋诗','song-poetry','','[]','空庭下梧葉，欲靜聞疏雨。',24,'全唐诗/poet.song.246000.json','["空庭下梧葉，欲靜聞疏雨。", "幽懷耿無寐，鄰客終夜語。"]'),
('6f6d9640-5acb-483c-aacb-841b4026ae6a','雜詠  其一','羅公升','宋','宋诗','song-poetry','','[]','帝曆千年統，神州百代居。',24,'全唐诗/poet.song.246000.json','["帝曆千年統，神州百代居。", "但看今日事，莫信古人書。"]'),
('2ac60efe-ba03-4d49-ae32-ce99b5431a77','雜詠  其二','羅公升','宋','宋诗','song-poetry','','[]','胡羯寧知分，中原欲並驅。',24,'全唐诗/poet.song.246000.json','["胡羯寧知分，中原欲並驅。", "設兵生建武，堪與赤眉俱。"]'),
('65b4aea8-bf37-4ea3-8981-86468c70804b','觀獵','羅公升','宋','宋诗','song-poetry','','[]','詭御羞禽獲，隨車忍獸呼。',24,'全唐诗/poet.song.246000.json','["詭御羞禽獲，隨車忍獸呼。", "爲敺須桀紂，競逐欠陳吾。"]'),
('71424d9e-6cab-4d70-9c96-a7cd8a2b09d0','謝松野叔惠菊','羅公升','宋','宋诗','song-poetry','','[]','囷粟分公瑾，千金壽仲連。',24,'全唐诗/poet.song.246000.json','["囷粟分公瑾，千金壽仲連。", "山人不須此，再拜菊花前。"]'),
('85cf214f-e18d-4457-bc1f-a36de1d68ac2','溪上','羅公升','宋','宋诗','song-poetry','','[]','往歲貪奇覽，今年遂考槃。',24,'全唐诗/poet.song.246000.json','["往歲貪奇覽，今年遂考槃。", "門前溪一髪，我作五湖看。"]'),
('eeebfdad-2fd1-4096-93da-e06ff5674711','冬夜獨坐','羅公升','宋','宋诗','song-poetry','','[]','庭幽蟄談口，燭盡輟書卷。',24,'全唐诗/poet.song.246000.json','["庭幽蟄談口，燭盡輟書卷。", "牆外醉客喧，堪憎更堪羨。"]'),
('290163cf-2f4b-4374-88bb-f698ba1cc2f7','次韻槐姪送花','羅公升','宋','宋诗','song-poetry','','[]','塵欺雙鬢少，春寄一枝多。',24,'全唐诗/poet.song.246000.json','["塵欺雙鬢少，春寄一枝多。", "爲報花神道，晴天載酒過。"]'),
('c412bfe4-5b6f-4080-8a93-a67bca1d6705','七絕句  其一','羅公升','宋','宋诗','song-poetry','','[]','吟昔從軍瘦，生涯出仕空。',24,'全唐诗/poet.song.246000.json','["吟昔從軍瘦，生涯出仕空。", "山中破茅屋，日日是秋風。"]'),
('c27044c2-fc44-40bd-8456-a2d16991893e','七絕句  其二','羅公升','宋','宋诗','song-poetry','','[]','天豈私貧我，看書每自疑。',24,'全唐诗/poet.song.246000.json','["天豈私貧我，看書每自疑。", "寸心即知己，不用世人知。"]'),
('a1c6a04f-aaa5-4a7e-a0c9-6e3f07788577','七絕句  其三','羅公升','宋','宋诗','song-poetry','','[]','賈生空痛哭，漢吏孰分憂。',24,'全唐诗/poet.song.246000.json','["賈生空痛哭，漢吏孰分憂。", "謾倚天爲命，天命不自由。"]'),
('88b19281-17fe-4b98-b7dc-ef060210a750','七絕句  其四','羅公升','宋','宋诗','song-poetry','','[]','群盜田夫耳，兵疲萬骨枯。',24,'全唐诗/poet.song.246000.json','["群盜田夫耳，兵疲萬骨枯。", "千年干羽事，只道聖人迂。"]'),
('b700799d-7bc2-49e7-be83-24d06627e3a4','七絕句  其五','羅公升','宋','宋诗','song-poetry','','[]','水旱關何事，兵凶孰汝憐。',24,'全唐诗/poet.song.246000.json','["水旱關何事，兵凶孰汝憐。", "但尋師辟穀，莫誤客求田。"]'),
('c5297252-283b-4025-a74f-4733869821b4','七絕句  其六','羅公升','宋','宋诗','song-poetry','','[]','橐重馿鳴苦，村空鬼哭悲。',24,'全唐诗/poet.song.246000.json','["橐重馿鳴苦，村空鬼哭悲。", "黄華存大體，不肯問狐狸。"]'),
('1c2a712e-824d-42d1-9846-73189c53ecfc','七絕句  其七','羅公升','宋','宋诗','song-poetry','','[]','本是山林物，中間一念差。',24,'全唐诗/poet.song.246000.json','["本是山林物，中間一念差。", "稻粱今懶種，况乃種桃花。"]'),
('69777022-ec0f-4bd0-9e7c-33e1cd45f0f9','送歸使絕句  其一','羅公升','宋','宋诗','song-poetry','','[]','目斷歸帆急，無身可得追。',24,'全唐诗/poet.song.246000.json','["目斷歸帆急，無身可得追。", "親庭如有問，依說鬢成絲。"]'),
('38ef46d2-8386-4296-ae27-cf0a8a2cf34c','送歸使絕句  其二','羅公升','宋','宋诗','song-poetry','','[]','東老真仙者，神遊八極周。',24,'全唐诗/poet.song.246000.json','["東老真仙者，神遊八極周。", "此行滄海上，定得拜蒼虯。"]'),
('3261f12c-3430-47b9-ada4-c09b19e6d82b','送歸使絕句  其三','羅公升','宋','宋诗','song-poetry','','[]','百年詩禮訓，惟彝仲容賢。',24,'全唐诗/poet.song.246000.json','["百年詩禮訓，惟彝仲容賢。", "慎勿如癡叔，膏明適自煎。"]'),
('60d3afbc-b0c4-4c47-9ef2-6a8b697c9782','送歸使絕句  其四','羅公升','宋','宋诗','song-poetry','','[]','梁楚連天闊，江湖接海浮。',24,'全唐诗/poet.song.246000.json','["梁楚連天闊，江湖接海浮。", "故人相憶夜，風雨定何州。"]'),
('e188eddd-bb72-4c52-8921-6be8adc7b9c9','送歸使絕句  其五','羅公升','宋','宋诗','song-poetry','','[]','魚鱉甘貽禍，雞豚飽自焚。',24,'全唐诗/poet.song.246000.json','["魚鱉甘貽禍，雞豚飽自焚。", "莫云鷗鷺宿，饞口不饒君。"]'),
('da882bce-6e1b-4d3d-8fb2-26919f2c0ed7','送歸使絕句  其六','羅公升','宋','宋诗','song-poetry','','[]','手植東臯松，勿遣樵牧經。',24,'全唐诗/poet.song.246000.json','["手植東臯松，勿遣樵牧經。", "他時化鶴歸，要斵千年苓。"]'),
('034eed00-3897-4be0-abac-0c4dbfddc087','送歸使絕句  其七','羅公升','宋','宋诗','song-poetry','','[]','人問我何之，我以此詩對。',24,'全唐诗/poet.song.246000.json','["人問我何之，我以此詩對。", "雲飛百川流，只在天地內。"]'),
('8d05a4af-743a-44d3-8a8b-a9a7681c079e','送介翁兄自揚州還南城','羅公升','宋','宋诗','song-poetry','','[]','聲滿對松縣，功成浮海船。',48,'全唐诗/poet.song.246000.json','["聲滿對松縣，功成浮海船。", "去隨騎鶴侶，歸訪擘鱗仙。", "馬首吟情溢，鴛屏別夢牽。", "相思不憚暑，計日話燈前。"]'),
('12a1aaec-f240-472d-80d8-7d7864023140','挽章','羅公升','宋','宋诗','song-poetry','','[]','憶昔垂髫日，相期志已深。',48,'全唐诗/poet.song.246000.json','["憶昔垂髫日，相期志已深。", "國家當日事，父母此時心。", "劫火分南北，秋風隔古今。", "病軀可堪此，無淚足沾襟。"]'),
('6a7c5c16-bac7-4ef0-9502-4517b63cd586','旅坐','羅公升','宋','宋诗','song-poetry','','[]','負却征塵債，飄零迄未休。',48,'全唐诗/poet.song.246000.json','["負却征塵債，飄零迄未休。", "孤蓬江貯夢，深巷雨添愁。", "山色分濃淡，禽聲互去留。", "班超亦良苦，萬里覓封侯。"]'),
('dc952ffe-34b7-48e3-86ce-1cb220290e16','所聞','羅公升','宋','宋诗','song-poetry','','[]','試問南來雁，何時戰馬閑。',48,'全唐诗/poet.song.246000.json','["試問南來雁，何時戰馬閑。", "古聞侵柳塞，今見入梅關。", "南海潮方怒，西江士不還。", "凄凉廣州婦，萬里沒燕山。"]'),
('3f13a911-72e2-4fb0-a6eb-bd913d9ff49a','秋望','羅公升','宋','宋诗','song-poetry','','[]','遠樹嵐煙合，孤村落照橫。',48,'全唐诗/poet.song.246000.json','["遠樹嵐煙合，孤村落照橫。", "江從前日濁，山似去年青。", "暝色鴉分去，羈愁蛩說成。", "乾坤久蕭瑟，消息聽鴻聲。"]'),
('1a11b23f-aaf8-4f21-bb27-da4df699e1cc','牢落','羅公升','宋','宋诗','song-poetry','','[]','牢落歲時晚，天寒遊子悲。',48,'全唐诗/poet.song.246000.json','["牢落歲時晚，天寒遊子悲。", "相幾如趙壹，舌不救張儀。", "夢短雞聲急，心飛雁足遲。", "亂愁已堪織，零雨更如絲。"]'),
('1f61067a-fad1-489a-9678-d77bfa31976e','嘗稻','羅公升','宋','宋诗','song-poetry','','[]','楚稻中秋熟，珠璣椀面浮。',48,'全唐诗/poet.song.246000.json','["楚稻中秋熟，珠璣椀面浮。", "已諳藜藿味，敢作稻粱謀。", "農業年年減，官征日日稠。", "憑誰寄焦飯，少慰倚門憂。"]'),
('8e693e76-24c2-4866-b30b-6f315cdaca59','秋懷','羅公升','宋','宋诗','song-poetry','','[]','舊日方山子，凄凉寄一簞。',48,'全唐诗/poet.song.246000.json','["舊日方山子，凄凉寄一簞。", "蟲聲來倦枕，秋思入凭闌。", "已是肱三折，那堪指一彈。", "中宵更風雨，誰念客氈寒。"]'),
('c18cf993-3cb5-479b-b1fb-f2b59e6e1c35','送劉玉田通判歸山','羅公升','宋','宋诗','song-poetry','','[]','詩工窮鬼妬，貌古俗人譏。',48,'全唐诗/poet.song.246000.json','["詩工窮鬼妬，貌古俗人譏。", "達士何榮辱，閒官更是非。", "面無三已慍，身带一癯歸。", "已試囊中法，春田玉正肥。"]'),
('e7a3738b-bf20-42c4-bd15-bb7d93975196','送同邸劉學古','羅公升','宋','宋诗','song-poetry','','[]','入彀西山月，驪駒幾屬行。',48,'全唐诗/poet.song.246000.json','["入彀西山月，驪駒幾屬行。", "如君今又別，令我若爲情。", "句入歸舟好，蛩憎客夢成。", "梅邊會相見，風樹莫離聲。"]'),
('360ec4f5-4d31-4842-ac8e-5d59f16f8bd6','東平府文廟規模頗壯其中亦有儒生十數然無一可語者','羅公升','宋','宋诗','song-poetry','','[]','當年鄒魯地，弦誦久無聲。',48,'全唐诗/poet.song.246000.json','["當年鄒魯地，弦誦久無聲。", "刀筆迂顔閔，章縫羨甲兵。", "谷陵朝暮改，日月古今明。", "歲晚高皇帝，猶難致兩生。"]'),
('05271a95-3cf7-4ddf-ad26-31d115a5b3c7','黄州','羅公升','宋','宋诗','song-poetry','','[]','十里南來道，初逢第一州。',48,'全唐诗/poet.song.246000.json','["十里南來道，初逢第一州。", "地因蘇子重，江替老瞞羞。", "路轉淮山□，天開楚岸浮。", "吾無赤壁賦，聊亦駕扁舟。"]'),
('0a1e5938-40a6-44d3-9366-853454b30e5e','江州寒食','羅公升','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','旅食逄寒食，風聲佐雨聲。',48,'全唐诗/poet.song.246000.json','["旅食逄寒食，風聲佐雨聲。", "野墳猶有主，客舍若爲情。", "家近心逾切，囊空眼便生。", "廬山如不過，此去信無名。"]'),
('e5311ac1-e77a-490d-94e0-62b74b59cd7e','寄蕭高風','羅公升','宋','宋诗','song-poetry','','[]','義氣凌秋日，高懷亙海雲。',48,'全唐诗/poet.song.246000.json','["義氣凌秋日，高懷亙海雲。", "古人如取友，天下獨逄君。", "暑退顔何似，書疏夢却勤。", "木瓜何以報，明月爲君分。"]'),
('8fad74e8-d1d7-4f10-bb83-c199e5506f3c','挽何見山  其一','羅公升','宋','宋诗','song-poetry','','[]','大父平生友，惟公意莫違。',48,'全唐诗/poet.song.246000.json','["大父平生友，惟公意莫違。", "山嵇欣月托，張許竟同歸。", "光嶽留英笑，陽秋見是非。", "終天臣子淚，今日重沾衣。"]'),
('7fbdd35a-ac43-4230-b624-b0cafbb6cc28','挽何見山  其二','羅公升','宋','宋诗','song-poetry','','[]','試手聞絃化，焦頭諭檄馳。',48,'全唐诗/poet.song.246000.json','["試手聞絃化，焦頭諭檄馳。", "鵬方從海運，鰲已戴山移。", "虛哭玄元廟，還賡鷲嶺詩。", "寥寥島中客，不負故王知。"]'),
('2bf64d05-a9b2-4da6-9b1c-abf1dc5c7ded','世故','羅公升','宋','宋诗','song-poetry','','[]','世故年年別，人煙處處非。',48,'全唐诗/poet.song.246000.json','["世故年年別，人煙處處非。", "詩從出山俗，客已及門稀。", "凱入猶聞警，場登更苦饑。", "乾坤多事在，未許製荷衣。"]'),
('d34a1913-d529-423c-b9c3-bfa82e17b981','辟地  其一','羅公升','宋','宋诗','song-poetry','','[]','雨急啼鴉切，山昏去客奔。',48,'全唐诗/poet.song.246000.json','["雨急啼鴉切，山昏去客奔。", "竄身楚南極，獨立鄭東門。", "卜處無神珓，招餘有斷魂。", "死生毫髪事，不足累乾坤。"]'),
('2ee72e4f-c9b6-4475-b4ca-c138e933f8c4','辟地  其二','羅公升','宋','宋诗','song-poetry','','[]','四海風濤日，誰歟柱急流。',48,'全唐诗/poet.song.246000.json','["四海風濤日，誰歟柱急流。", "山東雄劇孟，薊北化田疇。", "氣靜天閽晚，星沉戍角秋。", "如君關氣數，寧不重嫠憂。"]'),
('4a9c5315-b4d7-481c-812e-ced27cfe1350','聞息有變','羅公升','宋','宋诗','song-poetry','','[]','斗粟將誰憾，關弓只自憐。',48,'全唐诗/poet.song.246000.json','["斗粟將誰憾，關弓只自憐。", "竟成瓜蔓摘，深愧棣華翩。", "甘苦同三月，幽明冀百年。", "衰宗更如此，愁絕古松烟。"]'),
('b4664846-a695-4aae-a2db-77f9ac80c5ba','得家問  其一','羅公升','宋','宋诗','song-poetry','','[]','乍喜平安報，俄增放逐愁。',48,'全唐诗/poet.song.246000.json','["乍喜平安報，俄增放逐愁。", "親闈萬里老，客境四時秋。", "意往形空在，詩成影自酬。", "東風巖瀨在，不是欠扁舟。"]'),
('b99d2739-c1bb-4925-b85f-f1c5aac331f3','得家問  其二','羅公升','宋','宋诗','song-poetry','','[]','萬里平泉夢，誰憐創業難。',48,'全唐诗/poet.song.246000.json','["萬里平泉夢，誰憐創業難。", "已聞封樹伐，敢惜賜書殘。", "鷹擊寧論飽，烏棲不奈寒。", "長平門下客，知復幾任安。"]'),
('4280955b-c442-4d8f-ae22-a13e0d3b304b','春日皇帝閣  其一','羅公升','宋','宋诗','song-poetry','','[]','蓬萊宮闕五雲端，太液冰澌不敢寒。',32,'全唐诗/poet.song.246000.json','["蓬萊宮闕五雲端，太液冰澌不敢寒。", "須信帝家春事早，勾芒昨夜引春班。"]'),
('e3f9e585-8283-44aa-a439-be1af104f555','春日皇帝閣  其二','羅公升','宋','宋诗','song-poetry','','[]','太液池邊數樹紅，年年先得占春風。',32,'全唐诗/poet.song.246000.json','["太液池邊數樹紅，年年先得占春風。", "那知萬物含仁義，都在君王一笑中。"]'),
('27ec4f98-afee-4195-87ec-67de4d87dc9d','端午皇帝閣','羅公升','宋','宋诗','song-poetry','','[]','化日舒長萬國陶，南風古韻入絃高。',32,'全唐诗/poet.song.246000.json','["化日舒長萬國陶，南風古韻入絃高。", "天心廣大乾坤小，添得神遊一兩遭。"]'),
('b0580c72-0adc-4964-956c-510bef4b6b8c','春日皇后閣','羅公升','宋','宋诗','song-poetry','','[]','坤元布氣本無私，載物功深世不知。',32,'全唐诗/poet.song.246000.json','["坤元布氣本無私，載物功深世不知。", "天上春回椒殿暖，春風纔入萬年枝。"]'),
('5ac8ab8c-4793-4ad6-a2bd-cc097076750d','春日夫人閣','羅公升','宋','宋诗','song-poetry','','[]','君王著意在經帷，無復瓊林宴賞時。',32,'全唐诗/poet.song.246000.json','["君王著意在經帷，無復瓊林宴賞時。", "從此六宮休鬬草，碧紗窗下讀毛詩。"]'),
('644572f6-78f2-490c-a3d1-152ca9f0c79a','端午夫人閣','羅公升','宋','宋诗','song-poetry','','[]','黄金角黍照盤明，秋月弓灣鬬彩贏。',32,'全唐诗/poet.song.246000.json','["黄金角黍照盤明，秋月弓灣鬬彩贏。", "應是君王方右武，內家仙子亦知兵。"]'),
