('393ec9d8-a670-4d89-9c91-490485c1fc32','蔡州  其二','羅公升','宋','宋诗','song-poetry','','[]','臣子應思累世讎，况憑朽壤捍狂流。',32,'全唐诗/poet.song.247000.json','["臣子應思累世讎，况憑朽壤捍狂流。", "今人不恨南兵弱，却恨南兵入蔡州。"]'),
('a22e8af9-b8a8-4589-942c-b60d02a11ae3','即事','羅公升','宋','宋诗','song-poetry','','[]','早知色外本無身，不踏閻浮末世塵。',32,'全唐诗/poet.song.247000.json','["早知色外本無身，不踏閻浮末世塵。", "說與達多何用許，如來元自等冤親。"]'),
('24d62a6f-ecf9-4977-ae01-b757b08cc0a4','旌德寺靜雲亭','羅公升','宋','宋诗','song-poetry','','[]','岩壑幽幽竹樹青，山泉鳴處看雲生。',32,'全唐诗/poet.song.247000.json','["岩壑幽幽竹樹青，山泉鳴處看雲生。", "蒼苔不沒摩崖字，留與遊人唾姓名。"]'),
('bfaeafd4-66a6-4369-a4f1-6020150b69b5','演福寺','羅公升','宋','宋诗','song-poetry','','[]','禕翟當年讓福人，早知何用羨長春。',32,'全唐诗/poet.song.247000.json','["禕翟當年讓福人，早知何用羨長春。", "帝鄉抔土真無憾，怨絕龍沙萬里身。"]'),
('2dcbc396-58f7-438e-9d7a-9aad5494dbf2','菩提寺','羅公升','宋','宋诗','song-poetry','','[]','一畝方池幾劫灰，哭聲未了笑聲催。',32,'全唐诗/poet.song.247000.json','["一畝方池幾劫灰，哭聲未了笑聲催。", "六橋烟柳相逄處，半是菩提拭淚來。"]'),
('2e16fa39-1d58-41ce-9f8f-73ae02a7070a','觀潮  其一','羅公升','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','白馬揚波信有神，了知忠憤不緣身。',32,'全唐诗/poet.song.247000.json','["白馬揚波信有神，了知忠憤不緣身。", "潮頭却向西陵出，猶爲君王擊越人。"]'),
('96c8e222-4dc5-47bc-a90b-b12a44e66392','觀潮  其二','羅公升','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','仆越吞荆志未酬，此身生死只吳鈎。',32,'全唐诗/poet.song.247000.json','["仆越吞荆志未酬，此身生死只吳鈎。", "今人自有長驅策，不待君王賜屬鏤。"]'),
('537e4d85-1b8e-4c68-8bc0-8801e69cbc92','發湖州  其一','羅公升','宋','宋诗','song-poetry','','[]','秋色頻於客鬢加，歸期猶自嘆無涯。',32,'全唐诗/poet.song.247000.json','["秋色頻於客鬢加，歸期猶自嘆無涯。", "行纏剩欠江湖債，未著袈裟已出家。"]'),
