('3b39a19f-17a4-493d-9967-f7ff8b6520ca','靈巖寺  其一','羅公升','宋','宋诗','song-poetry','','[]','石門木老勢槎牙，曾見吳娃擁翠華。',32,'全唐诗/poet.song.247000.json','["石門木老勢槎牙，曾見吳娃擁翠華。", "底事秦宮與唐苑，百年多屬梵王家。"]'),
('39f2117d-c76b-4e88-a466-77bd675205a9','靈巖寺  其二','羅公升','宋','宋诗','song-poetry','','[]','馬嵬錦襪戰塵中，辱頸空餘頸血紅。',32,'全唐诗/poet.song.247000.json','["馬嵬錦襪戰塵中，辱頸空餘頸血紅。", "却是西施偏命好，國亡猶得嫁朱公。"]'),
('94c39444-a0f2-4076-8706-243888d72b67','飄蓬','羅公升','宋','宋诗','song-poetry','','[]','飄蓬未敢怨途窮，晉殿吳宮事亦空。',64,'全唐诗/poet.song.247000.json','["飄蓬未敢怨途窮，晉殿吳宮事亦空。", "宇宙不能逃劫數，山河元只戲英雄。", "佇觀成敗無過月，多管興亡只有風。", "擬學飛鴻離塵網，飛鴻猶在稻粱中。"]'),
('80af5fbb-b503-41b1-99c6-54ec1defd74c','感懷','羅公升','宋','宋诗','song-poetry','','[]','自緣舉世棄君平，寧爲蓴鱸憶季鷹。',64,'全唐诗/poet.song.247000.json','["自緣舉世棄君平，寧爲蓴鱸憶季鷹。", "不識將軍何用揖，元非進士底須稱。", "歸尋城郭渾如鶴，只欠袈裟便是僧。", "書冊至今成糞土，夜窗猶對短檠燈。"]'),
('0851a4cd-4f49-4991-b26e-71609aee7056','見遠亭次韻','羅公升','宋','宋诗','song-poetry','','[]','望中無處覓塵囂，只有詩人度石橋。',64,'全唐诗/poet.song.247000.json','["望中無處覓塵囂，只有詩人度石橋。", "萬里龍鱗歸雪屋，千山羊角下風條。", "斜陽盡處青山小，飛鳥行中碧樹遥。", "更把新吟作三絕，不妨東國使人描。"]'),
('1c2be637-14b3-4239-a56c-78bcb2271a21','故相府','羅公升','宋','宋诗','song-poetry','','[]','擎天力盡午橋休，狐舞中庭草塞樓。',64,'全唐诗/poet.song.247000.json','["擎天力盡午橋休，狐舞中庭草塞樓。", "鐵騎竟侵司馬宅，金椎誰報子房仇。", "事關氣數英雄老，位易乾坤史冊羞。", "故舊凄凉幾人在，羊曇無淚到西州。"]'),
('e28ca910-219f-41ef-a55a-2d845bb4969e','湖山人隠居','羅公升','宋','宋诗','song-poetry','','[]','幽人不管興亡事，贏得三年只下簾。',64,'全唐诗/poet.song.247000.json','["幽人不管興亡事，贏得三年只下簾。", "居介兩山今李愿，園開三徑古陶潜。", "傳家書已爲兒計，種秫田應爲客添。", "要與山神結緣去，一丘分我卜茅簷。"]'),
('69d4b300-0674-41e6-84b3-9805e7db83f3','和潘彥國見贈','羅公升','宋','宋诗','song-poetry','','[]','風雨千山落葉秋，不知當歲泣尼丘。',64,'全唐诗/poet.song.247000.json','["風雨千山落葉秋，不知當歲泣尼丘。", "仲由有勇休憑虎，寧戚雖賢且飯牛。", "史筆謾貽來世恨，書生空替古人愁。", "憑君局外留高著，莫道乾坤只麽休。"]'),
('9747dfcf-d5eb-490f-a075-3ac2e2c6f90a','代前清江守滕大著贈李吉州','羅公升','宋','宋诗','song-poetry','','[]','福星又見出虛危，螺浦千山亦展眉。',64,'全唐诗/poet.song.247000.json','["福星又見出虛危，螺浦千山亦展眉。", "八邑命懸循吏傳，萬家春在道州詩。", "旌旗已變河陽色，布粟猶憐蔡土饑。", "只恐九天歸詔急，去思還似鳳洲時。"]'),
('17afc0a6-07f1-4531-a6ee-f3ee268f13cc','九日言懷','羅公升','宋','宋诗','song-poetry','','[]','木落湖山萬葉黄，亂愁深處見重陽。',64,'全唐诗/poet.song.247000.json','["木落湖山萬葉黄，亂愁深處見重陽。", "絺衣只慣詩人體，酒盞全乖病客腸。", "只道事隨人意改，如何花作舊時香。", "孤樓不作還家夢，卧聽松風響夜長。"]'),
('f26a4975-8eeb-481f-aef9-676178f126bc','蛾眉亭','羅公升','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里風濤競擊撞，乾坤設險鍵南邦。',64,'全唐诗/poet.song.247000.json','["萬里風濤競擊撞，乾坤設險鍵南邦。", "五更畫角三州夢，兩岸青山四面窗。", "太白風流空舊月，虞公勳業自長江。", "倚闌何物堪持玩，萬頃長江鷺一雙。"]'),
('7f11d539-fd96-4b3e-96a6-8881c7c05492','乙酉元日遊長春宮奚真人所居之地雕砌文礎皆汴都宮殿舊物','羅公升','宋','宋诗','song-poetry','','[]','元日能關一日開，解鞍杖策訪雲端。',64,'全唐诗/poet.song.247000.json','["元日能關一日開，解鞍杖策訪雲端。", "樹衝劍氣千秋老，泉遇松聲六月寒。", "朝市未妨閒野樂，山村猶恨世途難。", "凄凉龍德宮中石，裝點琳宮處道冠。"]'),
('1b6b73c8-923b-41c9-af6d-6f7f416c11b1','洞巖','羅公升','宋','宋诗','song-poetry','','[]','但見佳山便合登，不須憑幻說超昇。',64,'全唐诗/poet.song.247000.json','["但見佳山便合登，不須憑幻說超昇。", "崢嶸神禹疏河勢，鏜鞳軒皇奏樂聲。", "已有道人稱吏隠，應無處士樂巖耕。", "近來太守君知否，只記西園是玉京。"]'),
('782549b0-9f73-4ff1-99e7-7eb43cda1829','贈劉次山','羅公升','宋','宋诗','song-poetry','','[]','片雲相望不相識，萬里相思首重回。',64,'全唐诗/poet.song.247000.json','["片雲相望不相識，萬里相思首重回。", "剡曲正須安道見，高陽真爲朗陵來。", "天分瑞葉供吟料，春遣梅花侑酒杯。", "安得受廛成二老，日陪杖履說敲推。"]'),
('89c0e4d6-1b65-4754-bb7c-d1dcd65638f3','別次山館中諸客','羅公升','宋','宋诗','song-poetry','','[]','德星光照斗牛野，我亦沙鷗尾鳳鸞。',64,'全唐诗/poet.song.247000.json','["德星光照斗牛野，我亦沙鷗尾鳳鸞。", "聚首自憐我輩在，畫眉莫與世人看。", "正平幸作忘年好，靈運那知入社難。", "明日回頭別羣玉，亂山何處兀孤鞍。"]'),
('f231b014-9182-45ee-a7de-11b3c52958d3','過表湖逢彭奇山','羅公升','宋','宋诗','song-poetry','','[]','入眼溪山亦世情，故人無復舊家聲。',64,'全唐诗/poet.song.247000.json','["入眼溪山亦世情，故人無復舊家聲。", "賣刀未得逢龔遂，置醴那知爲穆生。", "相鼠聊爲慶封贈，巨牛應待老瞞烹。", "倘無聽雨連牀樂，慚愧先□冒暑行。"]'),
('2ca4177f-6d93-422e-82b1-423530fad523','山背道中','羅公升','宋','宋诗','song-poetry','','[]','是間定可著吾家，流水深林一逕斜。',64,'全唐诗/poet.song.247000.json','["是間定可著吾家，流水深林一逕斜。", "天下獨清惟雪色，客中舊識是梅花。", "妍媸顛倒驚時事，戰伐紛紜老歲華。", "風雨窮山爲誰苦，故人何處岸烏紗。"]'),
('5f075f67-92ed-4f72-b941-56d557e7bb3a','和羅菊潭','羅公升','宋','宋诗','song-poetry','','[]','六月茫茫天晝昏，涇清渭濁不須分。',64,'全唐诗/poet.song.247000.json','["六月茫茫天晝昏，涇清渭濁不須分。", "安能夜踏文城雪，只合朝看太華雲。", "異日親曾拜黄石，他年應有好玄文。", "人間無著掀髯處，天姥峰頭一喚君。"]'),
('6dc96517-0328-4283-ad18-aecc8b4a7c7d','雪後望廬山','羅公升','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一別爐峰十載餘，重來相對雪消初。',64,'全唐诗/poet.song.247000.json','["一別爐峰十載餘，重來相對雪消初。", "湖中怒長陽侯氣，林外先生佛子廬。", "鼎鑊夢回山屐在，塵埃業重草堂疏。", "匆匆未副登臨願，終擬誅茅賦卜居。"]'),
('acc361d0-9410-4b6d-a2bb-44206fc647d3','庾樓','羅公升','宋','宋诗','song-poetry','','[]','萬里淮山萬里江，庾公曾此據胡牀。',64,'全唐诗/poet.song.247000.json','["萬里淮山萬里江，庾公曾此據胡牀。", "西風塵土謀誠誤，故國關河念未亡。", "對策記談乘塞事，倚闌今送入京航。", "六朝人物知多少，只有東籬百歲香。"]'),
('d9bea5ee-162d-4cbc-82aa-7c2fc37dbad7','安慶府','羅公升','宋','宋诗','song-poetry','','[]','金城圖上各論功，彈壓江流勢自雄。',64,'全唐诗/poet.song.247000.json','["金城圖上各論功，彈壓江流勢自雄。", "但使老熊當道左，寧愁遊騎入回中。", "幕間客解稱楊子，席上伶誰賦皖公。", "禾黍漸多青燐歇，郡人猶憶降元戎。"]'),
('3ac9b238-89d6-4350-959f-eeebdb04edf8','九日','羅公升','宋','宋诗','song-poetry','','[]','客樓坐閲帝居移，强賦愁邊九日詩。',64,'全唐诗/poet.song.247000.json','["客樓坐閲帝居移，强賦愁邊九日詩。", "稱壽無從辜菊把，避災何處愧茱枝。", "興如陷賊藍田日，吟到聞兵漢北時。", "萬里朔風將夢去，故園鷗鷺訴相思。"]'),
('ac9ed1bd-dabb-455e-bba6-abe97a52cb61','再如吳門','羅公升','宋','宋诗','song-poetry','','[]','地凍江空雁不飛，孤帆何事又乘危。',64,'全唐诗/poet.song.247000.json','["地凍江空雁不飛，孤帆何事又乘危。", "更無殘雪山陰興，漫有窮通蜀道詩。", "自笑大瓢長濩落，可辭群鳥議瑕玼。", "吳門市隠非梁籍，名姓寧須假手知。"]'),
('18c2094b-af6f-494b-a789-41fdf134a805','過嘉興雪中','羅公升','宋','宋诗','song-poetry','','[]','天末雄風捲白波，玉舟既曉泛銀河。',64,'全唐诗/poet.song.247000.json','["天末雄風捲白波，玉舟既曉泛銀河。", "不知瑞入耕疇未，但覺寒生客路多。", "四海儘寬胡至此，一丘無分欲如何。", "只因歲晚嘉禾道，剩要先生賦七歌。"]'),
('63e99f29-67a7-4760-a567-7981f0cb989e','儗過錢塘約諸客同賦','羅公升','宋','宋诗','song-poetry','','[]','去者勿戚戚，來者勿赫赫。',48,'全唐诗/poet.song.247000.json','["去者勿戚戚，來者勿赫赫。", "天地猶乘除，萬古晨有夕。", "詎知今時今，不作異時昔。", "吳山越山青，舊日錢王宅。"]'),
('83db68f0-ca2b-4f3b-90a7-3466b3769e7e','謝松野叔贈詩用首句驚舟出瞿塘還有平流安十字爲韻  其一','羅公升','宋','宋诗','song-poetry','','[]','庭中鳥鵲噪，門外雞犬驚。',48,'全唐诗/poet.song.247000.json','["庭中鳥鵲噪，門外雞犬驚。", "知有錦綉章，來作金石聲。", "松因屈子恥，菊爲淵明清。", "今我獨何者，照几新詩明。"]'),
('fe83d983-777b-450d-8a80-c1dfea3d1446','謝松野叔贈詩用首句驚舟出瞿塘還有平流安十字爲韻  其二','羅公升','宋','宋诗','song-poetry','','[]','君字若修竹，瀟灑風雨秋。',48,'全唐诗/poet.song.247000.json','["君字若修竹，瀟灑風雨秋。", "君詩若輕帆，滄海萬斛舟。", "快讀意自醒，痼疾一劑瘳。", "細讀殊味益，汲井百丈憂。"]'),
('f4e940ee-4883-4640-8612-dfa70eea4757','入書室東垣有神光自几案出  其一','羅公升','宋','宋诗','song-poetry','','[]','若以俗眼觀，榮枯幾翻手。',48,'全唐诗/poet.song.247000.json','["若以俗眼觀，榮枯幾翻手。", "若以法眼觀，窮達竟何有。", "吾身以覺贅，身外安足守。", "若□謝□□，爲我作不朽。"]'),
('9454dbeb-f4af-42c4-9768-bd2fcfcef56b','入書室東垣有神光自几案出  其二','羅公升','宋','宋诗','song-poetry','','[]','江海東南瀉，日月西北傾。',48,'全唐诗/poet.song.247000.json','["江海東南瀉，日月西北傾。", "天地豈不仁，作此大不平。", "遂使宇宙內，千載拏甲兵。", "人間勿設險，設險招戰爭。"]'),
('ca0db931-c96f-4236-a0b7-71901b9d4525','入書室東垣有神光自几案出  其三','羅公升','宋','宋诗','song-poetry','','[]','征鴻且勿飛，我憑問長安。',48,'全唐诗/poet.song.247000.json','["征鴻且勿飛，我憑問長安。", "長安在何許，征鴻亦良難。", "世狹日月短，氣縮天地慳。", "春色豈不深，風雨猶晚寒。"]'),
('fb8af143-5c9c-4586-9200-dcc4ee9e4b50','秋懷','羅公升','宋','宋诗','song-poetry','','[]','明月從東來，幽窗光炯炯。',36,'全唐诗/poet.song.247000.json','["明月從東來，幽窗光炯炯。", "疏窗一尺許，寫我肩與頂。", "可憐窗下心，愧此窗上影。"]'),
('f033058b-74ae-44e5-aa39-ed35460b0aec','秋夕','羅公升','宋','宋诗','song-poetry','','[]','客散燭亦盡，明月共寂寥。',48,'全唐诗/poet.song.247000.json','["客散燭亦盡，明月共寂寥。", "三生東華夢，歲晚依僧寮。", "秋宵豈不凉，客心自如燒。", "循簷耿無寐，顧影自蕭蕭。"]'),
('2688b587-eea9-4c96-9597-716c68129021','讀史  其一','羅公升','宋','宋诗','song-poetry','','[]','祖龍吞八荒，功名再開闢。',48,'全唐诗/poet.song.247000.json','["祖龍吞八荒，功名再開闢。", "方貪蓬山金，肯信滈池璧。", "平生焚椒蘭，死得鮑魚力。", "長城空巍巍，千古表漢域。"]'),
('f9162256-7493-4d66-a8e1-d505142dfdfe','讀史  其二','羅公升','宋','宋诗','song-poetry','','[]','季龍紾兄臂，晚以兵自强。',48,'全唐诗/poet.song.247000.json','["季龍紾兄臂，晚以兵自强。", "笑看華林花，謂與天地長。", "豈知肘腋間，豚犬皆豺狼。", "多鬚既濫死，朽骨污清漳。"]'),
('6ec80b9d-96ae-4eaf-b197-d7bb90d71826','讀史  其三','羅公升','宋','宋诗','song-poetry','','[]','隋文偉姿相，談笑取周鼎。',48,'全唐诗/poet.song.247000.json','["隋文偉姿相，談笑取周鼎。", "俘陳朝突厥，四海絕纖警。", "奈何梟獍禍，老不保腰領。", "不如臨春人，到此醉不醒。"]'),
('e4376fd0-e66a-4722-8e46-eaa70c6df6d4','讀史  其四','羅公升','宋','宋诗','song-poetry','','[]','德光起龍沙，忽拔汴水幟。',48,'全唐诗/poet.song.247000.json','["德光起龍沙，忽拔汴水幟。", "赭袍拜千官，始識皇帝貴。", "飲冰一何愚，剖腹有餘穢。", "可憐無知石，猶紀會同歲。"]'),
('5f507ef2-d34b-4449-8dac-d3b54efa5bcb','憶故人','羅公升','宋','宋诗','song-poetry','','[]','簷前一矯首，雲凍天欲愁。',48,'全唐诗/poet.song.247000.json','["簷前一矯首，雲凍天欲愁。", "客心急歲晚，留滯此何州。", "黄金不療饑，暖老各一裘。", "珍重山中人，幅巾自無憂。"]'),
('473213aa-9d4d-45bf-8d64-165db11f63b4','病中','羅公升','宋','宋诗','song-poetry','','[]','十日兩示疾，修途若爲情。',48,'全唐诗/poet.song.247000.json','["十日兩示疾，修途若爲情。", "閉蓬風濤中，益覺遺死生。", "頑石無枯株，千年亦何成。", "平生一大事，時至不須驚。"]'),
('eb290900-9f54-45c5-9b20-2c5fa98d7f98','西樓火','羅公升','宋','宋诗','song-poetry','','[]','祝融下省方，掉鞭鞭火龍。',96,'全唐诗/poet.song.247000.json','["祝融下省方，掉鞭鞭火龍。", "夜行失故路，誤入書窗中。", "紅光拂斗極，幻出琉璃宮。", "魚龍沸幽壑，臺觀遊太空。", "六丁攝圖史，羽化茫無蹤。", "成毀有定理，那足介我胸。", "造物解相補，放入山數重。", "此境如此心，空洞無垣墉。"]'),
('2ea5d91d-ecd6-4fce-94db-9dbc0419d10b','食新稻','羅公升','宋','宋诗','song-poetry','','[]','野人何所贈，金粟眩雙目。',132,'全唐诗/poet.song.247000.json','["野人何所贈，金粟眩雙目。", "吾廬幸徒壁，恐受賈禍速。", "熟視心始平，中有稻一斛。", "開囊带風露，入釜間黄綠。", "雲碓明珠跳，甆椀幽蘭馥。", "已分先農餘，不假惠伯卜。", "侑以手種松，領此一歲熟。", "大笑老杜陵，橡栗款空腹。", "天不憐萬民，何以生百穀。", "所懼風雨疾，翻使風雨覆。", "倘無飄泊憂，田舍有餘福。"]'),
('69cc5323-dc55-4f30-9821-4e633e898eee','道傍古樟有竹附焉可發一嘆','羅公升','宋','宋诗','song-poetry','','[]','古樟蟠山間，垂蔭翳我里。',120,'全唐诗/poet.song.247000.json','["古樟蟠山間，垂蔭翳我里。", "歲久或反常，村童祭爲鬼。", "大穴藏精靈，小隙竄蛇虺。", "嘗聞有驚霆，搜抉破根柢。", "竹我君子徒，冰霜凜在齒。", "胡爲事鑽刺，蟠屈嶔岩裏。", "乾坤亦廣大，朽木何足恃。", "託身一失所，萬水難復洗。", "松梅各相弔，爲我二友恥。", "去去非吾徒，偷生不如死。"]'),
('0fecc040-5883-4c14-821c-ce7b99825653','至日見菊花盛開有感','羅公升','宋','宋诗','song-poetry','','[]','玄冥用事久，百卉不復餘。',96,'全唐诗/poet.song.247000.json','["玄冥用事久，百卉不復餘。", "今晨轉陽律，始見天地初。", "黄花獨何事，佳色炯自如。", "淵明骨已朽，餘子不稱渠。", "風霜不汝容，歲若馳故車。", "獨立良自苦，歸根勿徐徐。", "寶此後凋質，會見秋香舒。", "吾亦焚筆硯，南山荷春鉏。"]'),
('6dff73bc-6778-4578-a521-cba11ccec24f','脫身軍府暫憩先月亭前挹湖光左右花木交映壁間題字亦有可觀惜未及見月也','羅公升','宋','宋诗','song-poetry','','[]','四年塵沙中，奔走日不給。',72,'全唐诗/poet.song.247000.json','["四年塵沙中，奔走日不給。", "空歌下泉詩，頗愧夔子集。", "今晨出軍府，心與歸鳥急。", "花迎曉日笑，樹沐清露濕。", "清漪舞游鱗，照影孤小立。", "重來期秋風，領略蟾影入。"]'),
('1c1710c7-dd2c-414d-bde5-1d704994fcd7','故里','羅公升','宋','宋诗','song-poetry','','[]','生長太平日，不識悲歡殊。',96,'全唐诗/poet.song.247000.json','["生長太平日，不識悲歡殊。", "今晨入故里，萬感忽啟予。", "人去鳥鼠樂，草長牛羊肥。", "土花幸無恙，猶作頹垣娛。", "平生懷古筆，擬賦東西都。", "豈知桑梓地，今即咸陽墟。", "欲知當日事，試問牆上烏。", "安得超世網，片帆渺江湖。"]'),
('83e40f39-44bf-404a-b570-15977280c9cc','秋夜觀書','羅公升','宋','宋诗','song-poetry','','[]','秋夜不可奈，孤燈耿殘書。',96,'全唐诗/poet.song.247000.json','["秋夜不可奈，孤燈耿殘書。", "書中何所陳，興亡鑒賢愚。", "心兵忽森起，掩卷長嗟吁。", "童子問我言，自古夫何如。", "小人計目前，君子思遠圖。", "雙髀骨已滿，攬鏡猶故吾。", "跼蹐蟻封裏，負此六尺軀。", "投桃勿復道，候蟲弔風梧。"]'),
('21a91b14-57a4-44c8-9b17-4abd88d012b2','悶','羅公升','宋','宋诗','song-poetry','','[]','簾纖江上雨，送我作飄零。',96,'全唐诗/poet.song.247000.json','["簾纖江上雨，送我作飄零。", "江海飄雙鬢，乾坤贅一萍。", "兔株空自守，龜筴爲誰靈。", "嵇筆懷憂憤，湘吟苦獨醒。", "眼看四海白，血灑九天青。", "萱背占烏鵲，圜扉痛鶺鴒。", "無由歸海島，誰爲哭秦庭。", "欲問鄜州信，鴻飛更杳冥。"]'),
('12e53909-984c-494b-b79b-2611fbf307a2','抵舍一夕復行途中遣懷','羅公升','宋','宋诗','song-poetry','','[]','乾坤本無邊，我命自荆棘。',120,'全唐诗/poet.song.247000.json','["乾坤本無邊，我命自荆棘。", "去住風濤中，生死無消息。", "茲晨夢中歸，真幻竟莫測。", "形聲各已改，老稚不我識。", "一燈話清凉，喜極淚始滴。", "出門動經年，還合甫浹昔。", "云胡作驚鷗，又復告行役。", "雨聲挾離思，春晚作秋色。", "暮山試回首，上有雲氣白。", "天長眼力短，此意幾悽惻。"]'),
('1e68a7ff-dce9-417a-93ca-0f6b7599ac81','觀棋','羅公升','宋','宋诗','song-poetry','','[]','秋風動江臯，吹落鷗鷺影。',96,'全唐诗/poet.song.247000.json','["秋風動江臯，吹落鷗鷺影。", "先生江湖心，收作目中景。", "庭深樹陰好，門掩禽語靜。", "一聲寂寞中，恍若隔人境。", "胸中兵十萬，臨敵暇且整。", "歛之塞成臯，縱去舉鄢郢。", "僕方棲會稽，蹇足未得騁。", "中原倘相逢，亦有憑軾請。"]'),
('42c89465-8996-4647-9ae4-92abb9be39e3','洪扇饋松野叔','羅公升','宋','宋诗','song-poetry','','[]','霜筠析絲豪，雪楮翦圭琬。',96,'全唐诗/poet.song.247000.json','["霜筠析絲豪，雪楮翦圭琬。", "凉颸生其間，懷袖覺清婉。", "賤子西北來，持此獻大阮。", "亦知秋氣深，爲表別懷遠。", "洪鈞轉二氣，暑極寒必返。", "君看千古日，未可異衰盾。", "霜雪雖云奪，篋笥亦何損。", "倘有解慍功，來歲出未晚。"]'),
('df6197dd-c68d-44c8-b8a6-bc5b76574a8c','看書有感','羅公升','宋','宋诗','song-poetry','','[]','齠齔趨庭日，真期萬里程。',96,'全唐诗/poet.song.247000.json','["齠齔趨庭日，真期萬里程。", "開編十行下，刻燭五言成。", "頗笑阿時學，方懷覽古情。", "祇言如昨日，不悟已前生。", "客裏餘長鋏，忙中負短檠。", "舊言如遠客，新卷即生兵。", "文武終何執，行藏兩未明。", "空餘清夜夢，時作讀書聲。"]'),
('8ea117db-c006-49e4-81f3-05049150f147','秋懷','羅公升','宋','宋诗','song-poetry','','[]','歸輿穿翠微，夜久樹益蒼。',60,'全唐诗/poet.song.247000.json','["歸輿穿翠微，夜久樹益蒼。", "海蟾浴清波，吐此林表光。", "今宵衣上露，明日履下霜。", "兒童不知此，且喜今夕凉。", "風林忽響答，似識予心腸。"]'),
('25b303d0-0858-442f-8783-9737afa76902','紀秦漢間事  其一','羅公升','宋','宋诗','song-poetry','','[]','秦焰亦已灰，函關碎周文。',60,'全唐诗/poet.song.247000.json','["秦焰亦已灰，函關碎周文。", "玄感老東都，不救身首分。", "慎勿輕瘠牛，猶足僨孤豚。", "高文信神武，□往乘□昏。", "落果固有時，燥者勿與言。"]'),
('06a847d5-e90e-427b-9b67-6c5907112652','紀秦漢間事  其二','羅公升','宋','宋诗','song-poetry','','[]','秦王狹百二，猛虎正負嵎。',96,'全唐诗/poet.song.247000.json','["秦王狹百二，猛虎正負嵎。", "壯哉田家子，赤手摩其鬚。", "叩關固蹉跎，未覺此計迂。", "沛公居山東，財色良區區。", "一朝咸陽去，始作帝者圖。", "碭公倘不偶，陳中遂長驅。", "求知千載下，優劣當何如。", "九原已黄土，極目空欷歔。"]'),
('1e27d102-2dee-40ef-bc89-246659aa7868','早行','羅公升','宋','宋诗','song-poetry','','[]','殘月不肯吐，鄰雞殊未鳴。',60,'全唐诗/poet.song.247000.json','["殘月不肯吐，鄰雞殊未鳴。", "已驚火星沒，况值玄雲生。", "居人酣春夢，行客貪修程。", "衆愁春露冷，我喜旦氣清。", "小立著定眼，自覺歸路明。"]'),
('081671b7-d91b-401a-8607-eb2366c2de6d','感舊','羅公升','宋','宋诗','song-poetry','','[]','逝水日已遠，愈覺別恨重。',108,'全唐诗/poet.song.247000.json','["逝水日已遠，愈覺別恨重。", "歲月不可留，又已聞鳴蛩。", "故衣餘手澤，見肘未忍縫。", "遥知春去後，飛花散無縱。", "遊魂定何依，馬蹄隔千峰。", "誰與持麥飯，一灑塚上松。", "憑高酹觴酒，聊以寫我胸。", "彭殤同所歸，百歲還相逢。", "但留一寸心，不愧三尺封。"]'),
('8cde3f50-9df6-4432-aff5-1c3e82ebc18c','戲蕭高風曾孟聲二友  其一','羅公升','宋','宋诗','song-poetry','','[]','丹鳳辭舊棲，四海求其凰。',96,'全唐诗/poet.song.247000.json','["丹鳳辭舊棲，四海求其凰。", "偶來梧竹間，振翮鳴朝陽。", "衆禽不自揣，競欲依餘光。", "神物要自珍，微羽那足當。", "了知霄漢姿，不集灌莽場。", "所憂燕雀雜，坐更鴻鵠藏。", "丹山有佳侶，足以陪雙翔。", "人間勿爲留，歸哉白雲鄉。"]'),
('1a74a878-62d1-4637-8cb2-d8816e619e9e','戲蕭高風曾孟聲二友  其二','羅公升','宋','宋诗','song-poetry','','[]','飛鴻響遥空，抱弋空遺影。',96,'全唐诗/poet.song.247000.json','["飛鴻響遥空，抱弋空遺影。", "遊鱗縱前川，把釣睨枯井。", "相看各如夢，欲去幾延頸。", "勞心縱有獲，所獲僅蛙黽。", "行人見之笑，千喚不一省。", "滄溟四無邊，盡納天地境。", "巨鰲載三山，未足污吾綆。", "相顧作清遊，濯足壺嶠頂。"]'),
('dcde2ce2-9026-40a8-a245-7fb510439faa','偶賦  其一','羅公升','宋','宋诗','song-poetry','','[]','定力了萬花，正眼空須彌。',72,'全唐诗/poet.song.247000.json','["定力了萬花，正眼空須彌。", "俯仰天地間，此身亦如遺。", "平生空洞腹，不受俗子窺。", "奈何區區者，妄欲求吾嗤。", "掀鬚對南山，但見雲度遲。", "却後百五歲，舉似爾輩知。"]'),
('a8abebfc-d4d0-434d-a47f-d9907697f055','偶賦  其二','羅公升','宋','宋诗','song-poetry','','[]','巢由善擇富，四海不易牛。',72,'全唐诗/poet.song.247000.json','["巢由善擇富，四海不易牛。", "古人恥苟得，一粟懷十憂。", "誰云黄屋榮，可掩頳面羞。", "那知井裏蛙，錙銖重山丘。", "肝腸果何罪，日夕森戈矛。", "頭曼豈不天，哀哉國爲仇。"]'),
('479dfc5c-656e-424a-8338-137d0b24deaf','雜詩  其一','羅公升','宋','宋诗','song-poetry','','[]','叔夜七不堪，投筆竄耕壟。',72,'全唐诗/poet.song.247000.json','["叔夜七不堪，投筆竄耕壟。", "被毛學新鄙，暴虎悔舊勇。", "歛身蝸殻間，榻外即關隴。", "□無奏記手，門絕問奇踵。", "人言明府驕，我欲廷尉重。", "可人忽東來，明月雲樂擁。"]'),
('d059417c-d470-4025-b475-b7f6eea4518e','雜詩  其二','羅公升','宋','宋诗','song-poetry','','[]','世故如遊塵，朝掃暮還有。',72,'全唐诗/poet.song.247000.json','["世故如遊塵，朝掃暮還有。", "向平待畢婚，謝事計已後。", "耳堪幾枕流，口但宜飲酒。", "門前泰華壓，老子一搔首。", "秋來四壁寂，草色上戶牖。", "好山喜笑人，客至但摇手。"]'),
('e228cd20-2907-423b-b985-b6364e63fbe6','雜詩  其三','羅公升','宋','宋诗','song-poetry','','[]','形驅世鞅縛，妄滅天刑逃。',72,'全唐诗/poet.song.247000.json','["形驅世鞅縛，妄滅天刑逃。", "我身不失我，榮辱誰能操。", "蔬肉等一戀，耕學兩不高。", "未應泉石癖，可笑州縣勞。", "秦人跨四海，不及源中桃。", "但看逸名姓，已足賢蕭曹。"]'),
('60d2a2e6-2c2d-43ee-8652-e226229cec04','秋夜有懷  其一','羅公升','宋','宋诗','song-poetry','','[]','今夕凉已透，開陽月初生。',60,'全唐诗/poet.song.247000.json','["今夕凉已透，開陽月初生。", "忽思會心友，談鋒隔江城。", "是非天意高，寵辱人事驚。", "衆賓亦笑語，我獨難爲情。", "回風避老樹，中宵有餘聲。"]'),
('d5212bb5-2c7c-4f07-9ac7-37d538f3d9b4','秋夜有懷  其二','羅公升','宋','宋诗','song-poetry','','[]','稍稍暝色添，悠悠遠山縮。',60,'全唐诗/poet.song.247000.json','["稍稍暝色添，悠悠遠山縮。", "秋聲何方起，餘韻入修竹。", "興來不知癡，橋外一筇獨。", "燈光小市閙，人語深院肅。", "惟應無歸雲，背向簷下宿。"]'),
('5efd29a1-aa24-4b7f-be70-bde1811e5bb1','散慵','羅公升','宋','宋诗','song-poetry','','[]','散慵陟嵐嶺，恰與落日平。',72,'全唐诗/poet.song.247000.json','["散慵陟嵐嶺，恰與落日平。", "天秋萬宇淡，盡見山水情。", "遥烟破衆寂，危花疑月明。", "川原自瀟灑，衣袂皆風聲。", "鑒空識本性，凭高失平生。", "蒼然暮色合，興盡心復驚。"]'),
('af69e9af-0936-4a92-b692-e69362150d4d','曉起','羅公升','宋','宋诗','song-poetry','','[]','危柯早得秋，羈鶴易知曉。',120,'全唐诗/poet.song.247000.json','["危柯早得秋，羈鶴易知曉。", "幽人带星起，古木叫孤鳥。", "簾影一丈高，曙色萬里杳。", "人稀蒼茫內，樹立浩蕩表。", "安知南征雲，不自厭紛擾。", "秋光接巖氣，終覺風味少。", "紅矜木蓉麗，白惜渚蓮夭。", "觀妄眼已空，觸物思還悄。", "賀公豈真狂，有激或成矯。", "歸登神聖臺，一笑萬緣了。"]'),
('3650fb57-58dd-4e83-a29f-11d29ef390b4','贈別詹厚齋','羅公升','宋','宋诗','song-poetry','','[]','閉門秋氣深，霜蟲伴書帷。',96,'全唐诗/poet.song.247000.json','["閉門秋氣深，霜蟲伴書帷。", "高軒御風至，我屋還有奇。", "十年幾離合，往夢不可思。", "豈期丘壑間，談此五日詩。", "肝腸洗舊染，刀圭得新醫。", "人間公等在，不必吾道衰。", "如何更輕別，莫計重逢時。", "霜餘出碩果，持用慰渴饑。"]'),
('09ca4bde-ade3-4650-9bc9-e085a8dba525','贈游仁翁','羅公升','宋','宋诗','song-poetry','','[]','南山有好鳥，來集鴻鵠行。',96,'全唐诗/poet.song.247000.json','["南山有好鳥，來集鴻鵠行。", "鳴聲日已都，六翮歲以長。", "雖云氣類集，習久跡已忘。", "所期逍遥遊，一息視八荒。", "三年稻粱少，去與鷹鸇翔。", "好音變饑嘯，鷙聲嗔饞腸。", "重來見鴻鵠，反噬氣益張。", "鴻鵠不汝尤，矰繳防汝傷。"]'),
('2c5b38d9-3b79-4ad1-a481-5c4116ce0eb4','道逢新婚者','羅公升','宋','宋诗','song-poetry','','[]','時危家如寄，生離恨終天。',84,'全唐诗/poet.song.247000.json','["時危家如寄，生離恨終天。", "稱家畢婚姻，豈必齊宋賢。", "白首未可期，樂此桃李年。", "畸人感雉飛，七載操斷絃。", "三年揚州夢，化作空中烟。", "大義古有制，私情豈云牽。", "命也我所安，撫事增悵然。"]'),
('a9af1051-bc22-4068-ab9c-624d20a38dc2','早起','羅公升','宋','宋诗','song-poetry','','[]','鼕鼕五鼓動，客子推枕起。',96,'全唐诗/poet.song.247000.json','["鼕鼕五鼓動，客子推枕起。", "餘燈明壁間，照我髪垂耳。", "呻吟與鼻息，徹曉聲未已。", "誰言吳越異，疾痛切吾體。", "向來參內篇，久已一生死。", "區區窮通者，未足置慍喜。", "渠方怒張髯，我亦笑彈指。", "珍重青原山，歲晚吾與爾。"]'),
('6b6377cc-d614-4b10-b376-e11fc654cc5e','題鄒安齋詩卷','羅公升','宋','宋诗','song-poetry','','[]','兵餘十八載，乃忽見此詩。',120,'全唐诗/poet.song.247000.json','["兵餘十八載，乃忽見此詩。", "乾坤發危涕，未論言語奇。", "古音乃泗磬，麗色藻鮫絲。", "想見堵牆人，傾倒落筆時。", "奈何清平調，變入寒笳吹。", "蒼茫同谷意，天遣放厥詞。", "墓檟忽可材，所患訪何遲。", "空餘兩家子，把卷驚合離。", "九原不可起，可起更可悲。", "祝君藏名山，小作千歲期。"]'),
('f3cfe5eb-475c-4e35-ae07-9b9f3a9c956f','夜月懷超然故臺','羅公升','宋','宋诗','song-poetry','','[]','中宵雨聲歇，好月滿我屋。',120,'全唐诗/poet.song.247000.json','["中宵雨聲歇，好月滿我屋。", "開門四無人，老樹立於獨。", "巡簷不成寐，送影過牆竹。", "賞弄情未央，矮屋礙遠目。", "故山有層臺，千里曠遊矚。", "主人三年別，坐使萬瓦覆。", "鵬程本逍遥，蟻穴自羈束。", "乾坤有興廢，豈必善者福。", "是身且非我，而况土與木。", "但聽雍門彈，勿效孟嘗哭。"]'),
('8e064088-e263-4f23-8c2b-e028bf4f3f83','冬至','羅公升','宋','宋诗','song-poetry','','[]','窮冬乃常燠，庭礎上雲氣。',96,'全唐诗/poet.song.247000.json','["窮冬乃常燠，庭礎上雲氣。", "索居共誰語，煮藥作冬至。", "客來寄枯棋，客去玩奇字。", "是中即了我，自得在不智。", "偷生輕日月，長短亦何計。", "惟應開闢事，頗得大易意。", "門前鳴騶急，窗外飛雨細。", "雲物吾不知，曉鐘一覺睡。"]'),
('422a9acd-859e-4858-874f-7be530098a45','李古城索狂醒道人詩','羅公升','宋','宋诗','song-poetry','','[]','狂風扇八區，一發不可息。',96,'全唐诗/poet.song.247000.json','["狂風扇八區，一發不可息。", "遂令地行人，顛倒忘南北。", "道人留醒眼，謂得大慧力。", "出門楚天高，萬里寄兩屐。", "袈裟且不著，况作軒冕劇。", "窮秋華峰哭，夜月牛渚笛。", "是中豈狂者，狂者自莫識。", "他年真醒時，爲汝說皇極。"]'),
('72f96606-6ee2-4d72-8705-2a340865d1b3','從軍留別天逸','羅公升','宋','宋诗','song-poetry','','[]','一閒五千日，功德高於山。',96,'全唐诗/poet.song.247000.json','["一閒五千日，功德高於山。", "如何天不借，驅向金革間。", "妖血醒人饑，馬足愁險艱。", "今宵觴詠處，已带風雪顔。", "皇穹未厭亂，肯放兩脚閒。", "東海邈山河，廬峰定天關。", "即往不可留，我去何當還。", "後夜夢君時，哀笳鬢成班。"]'),
('e38cea71-92a8-47e3-b116-25fcfc7ff368','春曉道中','羅公升','宋','宋诗','song-poetry','','[]','笳鳴雨聲歇，據鞍迎曉風。',84,'全唐诗/poet.song.247000.json','["笳鳴雨聲歇，據鞍迎曉風。", "桃花逞顔色，窈窕一川紅。", "經年用越地，殺氣浮太空。", "頗宜化工手，不到荆棘叢。", "鶑聲忽起予，夢落柳影中。", "緬懷習池賞，不減燕然功。", "橫槊豈無人，賦詩定誰工。"]'),
('dd898c8c-9847-4f1d-a086-750379861b5d','次韵嚴叔賢見寄','羅公升','宋','宋诗','song-poetry','','[]','威鳳翔九天，棲息惟十洲。',96,'全唐诗/poet.song.247000.json','["威鳳翔九天，棲息惟十洲。", "胡爲落世人，下與雞鶩遊。", "吟仙霄漢間，清夜瑶琴秋。", "餘音遇風至，不可言語求。", "黄塵隔辰晤，回首生暮愁。", "櫜弓定何日，春馭已莫留。", "柳營豈云遠，邈若青海頭。", "何當踏月來，羽衣嘯黄樓。"]'),
('25c7f31f-1b43-415f-aaa6-3105dcbee3c3','從軍興平','羅公升','宋','宋诗','song-poetry','','[]','廢墟起寒烟，饑鼠意自妥。',120,'全唐诗/poet.song.247000.json','["廢墟起寒烟，饑鼠意自妥。", "十年行脚處，重到無一可。", "乾坤鍾厄會，推擇乃及我。", "東皋兩犁手，長戟三歲荷。", "治絲慚益棼，杯水不救火。", "窮山高馬齒，華屋實野果。", "平生疏懶報，歲晚困羈鎖。", "有如醉行人，日暮路益左。", "未須說神仙，大福在無禍。", "但當求蒲團，不須夢狨坐。"]'),
('9a1109fc-03f5-4d9d-9b80-2f687893c5b9','從道益聲自清江送至樟鎮別後書懷','羅公升','宋','宋诗','song-poetry','','[]','故人難合并，貧路惜羈旅。',132,'全唐诗/poet.song.247000.json','["故人難合并，貧路惜羈旅。", "孤蓬遠追送，未怯危路阻。", "當年滕王城，跌宕欣得侶。", "朱顔侮華髪，笑口失愁緒。", "那知更世故，俠客變處女。", "西風凄破帽，細雨雜參請。", "羽書雖云急，飛斝未忍去。", "嗟予百憂集，俯仰輒齟齬。", "蕭然一匏笠，四海莫我處。", "斷崖揮手處，別意寫雙艣。", "夜闌江樹摇，尚想客凝佇。"]'),
('367b0f19-5313-49e4-8ef0-3c6ae3878270','有念','羅公升','宋','宋诗','song-poetry','','[]','方招東渚魂，又送北阡窆。',72,'全唐诗/poet.song.247000.json','["方招東渚魂，又送北阡窆。", "交游亦餘幾，日覺眼中欠。", "向來所憎者，一一皆可念。", "憂愁鬢先霜，形影吾自厭。", "春華已零落，秋木豈陽艷。", "緬懷郢人質，徒掛季子劍。"]'),
('11fe77a7-e9b2-434e-a66e-b9b6371eb396','喜雨','羅公升','宋','宋诗','song-poetry','','[]','三更飽甘雨，翛然凉意秋。',72,'全唐诗/poet.song.247000.json','["三更飽甘雨，翛然凉意秋。", "驚霆駕風至，氣欲掀我樓。", "溟濛劃軒豁，稻隴如潑油。", "兵凶歲相仍，糟糠甚珍羞。", "天公一反手，少緩带犢謀。", "諸賢自蒿目，百畝真吾憂。"]'),
('4aad18e1-8e11-4df8-9587-f09177b818aa','疏渠','羅公升','宋','宋诗','song-poetry','','[]','疏渠行活水，水鳴空院幽。',72,'全唐诗/poet.song.247000.json','["疏渠行活水，水鳴空院幽。", "堂坳地母小，中有萬里流。", "向來手拮据，華屋俄荒丘。", "猶餘愚溝迹，洗我中山羞。", "九河且平陸，起滅况一漚。", "相娛亦聊耳，南澗何多憂。"]'),
('99c8be73-b837-4be7-9ea1-ba3447e1f8c6','納凉','羅公升','宋','宋诗','song-poetry','','[]','氣至暑固當，境寂凉自生。',60,'全唐诗/poet.song.247000.json','["氣至暑固當，境寂凉自生。", "天河自如水，夜久山更明。", "古樹有莊色，新泉入幽聽。", "逃空空快事，喪虎不可停。", "飛螢過屋頂，一落如流星。"]'),
('643f2632-6dc9-4544-bd9b-9c335ed7fdba','閔雨有懷','羅公升','宋','宋诗','song-poetry','','[]','千疇晝生烟，稻本焦釜急。',120,'全唐诗/poet.song.247000.json','["千疇晝生烟，稻本焦釜急。", "化工哀遺黎，起死在呼吸。", "簷牙飛瀑亂，溝曲怒潮集。", "書生樂人樂，夜久倚杖立。", "遥知饑腸蘇，不但爽氣入。", "兵氣二十載，狐鼠舞城邑。", "向來被犁者，滄海餘一粒。", "潜虯尚無情，枯魚亦何及。", "終然天者定，未恨老簑笠。", "念彼荷戈人，山中甲裳濕。"]'),
('16a92835-9e04-43aa-ae0b-ac22ebfa77e6','冬蚊','羅公升','宋','宋诗','song-poetry','','[]','冬夜乃常燠，蚊鳴猶薨薨。',96,'全唐诗/poet.song.247000.json','["冬夜乃常燠，蚊鳴猶薨薨。", "客枕本無寐，驅馳困揮肱。", "向來炎歊中，意氣莫敢膺。", "群飛乘幽陰，各以嚙自矜。", "詩癯肉幾何，磨吮恐不勝。", "霜風日以勁，利觜那可憑。", "奈何逞餘毒，糜爛意未懲。", "先生忽睡著，汝亦終何能。"]'),
('cba6108e-e991-4e59-bc6c-aad3a52bc77e','丹房採蕨','羅公升','宋','宋诗','song-poetry','','[]','神丹有餘光，入地茁紫玉。',96,'全唐诗/poet.song.247000.json','["神丹有餘光，入地茁紫玉。", "氣鍾仙掌清，味壓婦臂俗。", "東風一夜雨，登俎間紅綠。", "淡羹意自古，酸藴香更酷。", "山人謝肉食，藉此慰便腹。", "薦新先北堂，誇示及小陸。", "府公厭腥腐，寧有啖此福。", "所以首陽翁，不復羨周粟。"]'),
('88f05d18-5a1c-44e0-9be7-adad85b46049','贈相字曾木訥','羅公升','宋','宋诗','song-poetry','','[]','倉公造文字，千古疲蠹簡。',108,'全唐诗/poet.song.247000.json','["倉公造文字，千古疲蠹簡。", "爾來記草青，頗覺浮僞損。", "老曾相心畫，乃復鑿混沌。", "毫端窺靈臺，口角出華衮。", "訥雖未成論，木亦不離本。", "西游觀青原，佳士競推挽。", "的應誇幼婦，不用愁御飯。", "道人衡氣機，筆墨付一莞。", "聊持無形字，示子非俗眼。"]'),
('6e066fa8-433c-4b90-9481-97aa3c776255','答戴用齋教諭','羅公升','宋','宋诗','song-poetry','','[]','學書早無成，學劍老可怕。',84,'全唐诗/poet.song.247000.json','["學書早無成，學劍老可怕。", "不如反初服，一鍤始學稼。", "雖煩遠公招，實恐惠子嚇。", "綸言若春風，枯朽歘變化。", "平生河汾策，肯出叔夜下。", "飛潜各努力，蘭菊異開謝。", "他年賣藥來，石鼎賦雪夜。"]'),
('cafcc4ae-b7f2-4f64-b005-8d45876de014','種藥','羅公升','宋','宋诗','song-poetry','','[]','治生吾未能，學圃豈不惡。',96,'全唐诗/poet.song.247000.json','["治生吾未能，學圃豈不惡。", "秋風雨如酥，畦土樹靈藥。", "荒茨出神奇，高下粲花萼。", "將期清百慮，豈獨健雙脚。", "平生林下心，五鼎視藜藿。", "常疑種玉誕，亦笑带經錯。", "黄金污吾鉏，矧肯白晝攫。", "歸還勞巵酒，辛苦同爲樂。"]'),
('b45bfeda-2ec5-48f9-922d-3089cb2db587','爲游叔蕃覓苦椎','羅公升','宋','宋诗','song-poetry','','[]','丘中有佳人，披褐抱白玉。',120,'全唐诗/poet.song.247000.json','["丘中有佳人，披褐抱白玉。", "百年老風雨，坐閲成毀速。", "霜餘乃脫穎，磊落隠者屋。", "平生苦硬姿，卓爾受命獨。", "虞翻終老辣，嚴挺笑軟熟。", "世情樂肥甘，有齒但食肉。", "封題欲遠贈，懼以蜇口瀆。", "的應山林味，雅稱藜藿咮。", "聊持詩百字，爲博珠一斛。", "我本看泉聲，茅齋添夜讀。"]'),
('4610d412-e2a9-4191-b1bd-012980eb2f5d','句','羅壽可','宋','宋诗','song-poetry','','[]','追思往事真堪恨，誤却南兵是蔡州。',16,'全唐诗/poet.song.247000.json','["追思往事真堪恨，誤却南兵是蔡州。"]'),
('206ea844-cb61-4e5c-8e5a-7f60b6f2d247','句','羅松野','宋','宋诗','song-poetry','','[]','驚舟出瞿塘，還有平流安。',12,'全唐诗/poet.song.247000.json','["驚舟出瞿塘，還有平流安。"]'),
('ed455b36-14b4-41cc-a08e-33f4cec30456','題唐顯孝饒娥墓  其一','程時登','宋','宋诗','song-poetry','','[]','悠悠孤憤倚中流，飽閲川陵四百秋。',64,'全唐诗/poet.song.247000.json','["悠悠孤憤倚中流，飽閲川陵四百秋。", "水際叢祠猶昨日，人間抔土幾荒丘。", "故鄉愛說饒饒姓，往事空傳柳柳州。", "滿目夕陽凝睇久，桐花飛落釣魚舟。"]'),
('af7fe4db-f9c8-48d3-9a16-5740119ec29f','題唐顯孝饒娥墓  其二','程時登','宋','宋诗','song-poetry','','[]','松陰庭戶枕清波，小立碑亭校舊訛。',64,'全唐诗/poet.song.247000.json','["松陰庭戶枕清波，小立碑亭校舊訛。", "一念綱常行宇宙，幾番風雨起山河。", "世間如此丈夫少，天下從渠女婦多。", "倚遍欄干千古意，登臨不敢更高歌。"]'),
('a84e2073-9dc6-46eb-8052-975632fe0125','金塔','黄叔美','宋','宋诗','song-poetry','','[]','金溪有金源，昔我未嘗造。',204,'全唐诗/poet.song.247000.json','["金溪有金源，昔我未嘗造。", "因逢吳道士，言此山水好。", "金僧來自蜀，所至事幽討。", "地名適相符，結茅遂棲老。", "一朝入石塔，千載錮其寶。", "白雲何漫漫，流水亦浩浩。", "相傳石井頭，鞋跡猶可考。", "安知斯塔內，歲久骨應槁。", "龕燈長不滅，落葉風自掃。", "山僧具茗酌，言話頗知道。", "請題壁間詩，茲行殊草草。", "所欣得二趙，登覽散中抱。", "日午餉田家，壺觴共傾倒。", "素心愜清賞，恨不避喧早。", "偶尋幽侶出，徵逐非所好。", "歸途霜月下，譙鼓更漸報。", "明朝人事乖，相望不可到。"]'),
('4e41d052-2c8e-4fd7-b2ff-28009588fa30','寶善堂爲薛玄卿題','黄叔美','宋','宋诗','song-poetry','','[]','人孰不有母，鮮能報其恩。',204,'全唐诗/poet.song.247000.json','["人孰不有母，鮮能報其恩。", "人孰不有弟，鮮能念同根。", "漢興尺布謠，鄭有誓泉言。", "所以憂世事，永歎鶺鴒原。", "緬懷寶善君，生子出孝門。", "幼習靜室業，實爲仁愛敦。", "百金買古宅，乃在清溪濆。", "堂前種荆樹，堂北長慈萱。", "時從道園中，駕彼白鶴軒。", "再拜母膝下，殷勤問寒暄。", "季也一相接，怡然煦春溫。", "溪魚識嘯歌，烏鳥沽盤餐。", "余適登斯堂，吳公有銘存。", "阿姪三五輩，削瓜酌清尊。", "秩然進退間，禮義何其尊。", "嗟今利奪人，骨肉相仇冤。", "蒼天信可問，薄俗難與論。"]'),
('10fcedd5-7d17-484e-989a-b0c25b0dfebd','周嘉會遠行','黄叔美','宋','宋诗','song-poetry','','[]','聞道周公子，今春過許州。',48,'全唐诗/poet.song.247000.json','["聞道周公子，今春過許州。", "百年看野史，雙鬢托孤舟。", "風土青山古，英雄憐火秋。", "豈無遺白淚，相對話江鷗。"]'),
('f58dfb24-dacd-4c6c-a4d6-9a3dab86e18f','登麻姑山','黄叔美','宋','宋诗','song-poetry','','[]','昔日登臨不用扶，於今白首見麻姑。',64,'全唐诗/poet.song.247000.json','["昔日登臨不用扶，於今白首見麻姑。", "此邦泉石何蕭爽，異代神仙知有無。", "七月山田紅稻熟，去年塵海碧蓮枯。", "信知冠蓋追遊地，羽客相逢到日晡。"]'),
('cd3c8fc1-acac-426a-9bbf-0008b3f52bc5','秋夜泛舟','何新之','宋','宋诗','song-poetry','','[]','飛星曳寒影，野水淡碧空。',72,'全唐诗/poet.song.247000.json','["飛星曳寒影，野水淡碧空。", "人生定何物，扁舟空影中。", "何年有宇宙，生此木末風。", "有力不向上，難到蓬萊宮。", "空攀棲鶻巢，搔首如飛蓬。", "俯仰慨今昔，此懷安可窮。"]'),
('267c273e-3262-4a92-a3a4-a3eda62946a5','題高房山夜山圖','張逢原','宋','宋诗','song-poetry','','[]','地位清高眼界寬，盡收風景入豪端。',64,'全唐诗/poet.song.247000.json','["地位清高眼界寬，盡收風景入豪端。", "廢宮臺榭和烟鎖，隔岸江山對月看。", "一水中分吳越近，層樓低接斗牛寒。", "有聲畫意吟難了，更把瑶琴膝上彈。"]'),
('7b378f3b-3718-467a-a9d7-59e4abcd6a69','勘災','王夢雷','宋','宋诗','song-poetry','','[]','散吏馳驅踏旱邱，沙塵泥土掩雙眸。',64,'全唐诗/poet.song.247000.json','["散吏馳驅踏旱邱，沙塵泥土掩雙眸。", "山中樹木減顔色，澗畔泉源絕細流。", "處處桑麻增太息，家家老幼哭無收。", "下官雖有憂民淚，一擔難肩萬姓憂。"]'),
('01303a33-2995-4e5f-ae70-8def120d375b','效長吉體','劉有慶','宋','宋诗','song-poetry','','[]','窮廬夜雪沒駝脊，黄沙號風冰結石。',88,'全唐诗/poet.song.247000.json','["窮廬夜雪沒駝脊，黄沙號風冰結石。", "燕姬二八髻垂漆，柔荑斜抱箜篌立。", "老羌踏歌歌勅勒，黄金流星酒杯窄。", "紅氍毹暖春雲濕。", "縷金團衣猩血滴，玉釵醉滑茝絃急。", "角聲滿空霜裂骨，十萬獰君掩襟泣。"]'),
('77e71ead-7857-4ca9-9926-a7d928d8fbf4','送楊長卿任贛州知事','劉有慶','宋','宋诗','song-poetry','','[]','望郡推章貢，斯遊趣不希。',48,'全唐诗/poet.song.247000.json','["望郡推章貢，斯遊趣不希。", "風清王儉幕，春滿老萊衣。", "鯽沼迎秋月，螺亭覽夕暉。", "政成如有句，肯寄北鴻飛。"]'),
('3b36eae5-6642-41a8-8371-6face4ca3220','鍾山','劉有慶','宋','宋诗','song-poetry','','[]','蟠龍垂顧飲江湄，卧護宗祧彼一時。',64,'全唐诗/poet.song.247000.json','["蟠龍垂顧飲江湄，卧護宗祧彼一時。", "馬渡已嗟南國蹙，猿驚何暇北山移。", "郊壇曾祝千年運，塔廟空留異代悲。", "北望中原形勢盡，太平草木亦熙熙。"]'),
('d2bdaa69-5c19-4e13-83c3-2f671a24cc4a','題柳隠圖','貢宗舒','宋','宋诗','song-poetry','','[]','垂楊過我屋頭青，門對茅峰遠世情。',32,'全唐诗/poet.song.247000.json','["垂楊過我屋頭青，門對茅峰遠世情。", "贏得行人閑著眼，却疑此處即淵明。"]'),
('0e978f8f-8d00-4e20-8f99-ae39cc4a5801','詠保母帖','王易簡','宋','宋诗','song-poetry','','[]','黄閍斷刻得者誰，雙松下殉方壺螭。',195,'全唐诗/poet.song.247000.json','["黄閍斷刻得者誰，雙松下殉方壺螭。", "其文記述保母李，云是大令之所爲。", "點畫安知尚年少，筆不可掣從兒時。", "當其翰墨託久計，異哉歲月如前期。", "爲憐樵人巧收拾，豈無行道猶嗟咨。", "殘磚裹送平原家，閲古衆帖奚獨遺。", "窮諏遠引商是非，具眼落落多傳疑。", "塵埃尺紙拂陳迹，聞君好事捲贈之。", "簡編無端發汲冢，陵谷何年沈峴碑。", "坐中賞識本易厭，世外隠伏勞旁窺。", "騷人勝士一朝玩，孝子慈孫千古悲。", "君不見鍾侯書法亦大奇，下穿墟墓求其師。"]'),
('936f2063-2334-4f04-9f2f-e924b6360ac7','九鎖山十詠  其一','王易簡','宋','宋诗','song-poetry','','[]','蕭灑殊庭西，玉室青孱顔。',60,'全唐诗/poet.song.247000.json','["蕭灑殊庭西，玉室青孱顔。", "華陽隠邃道，元蓋浮塵寰。", "紞紞天鼓鳴，爛爛巖屋斑。", "誰懸隔凡石，此已非人間。", "羣仙本容物，爲我開重關。"]'),
('74ba3669-cef8-40c3-b8ba-3535416efc2f','九鎖山十詠  其二','王易簡','宋','宋诗','song-poetry','','[]','風煙谷口亭，巖穴神仙宅。',60,'全唐诗/poet.song.247000.json','["風煙谷口亭，巖穴神仙宅。", "逕回閟天光，雲濕滴乳液。", "寶蓋遥當空，篝火忽奇迹。", "不見茹芝人，殘枰棄黑白。", "躋攀幸有逢，筋力何足惜。"]'),
('2dc7447f-6d4f-4ab1-bff0-218efa352fb6','九鎖山十詠  其三','王易簡','宋','宋诗','song-poetry','','[]','鳳兮爾何來，翽翽鳴高崗。',60,'全唐诗/poet.song.247000.json','["鳳兮爾何來，翽翽鳴高崗。", "山風度玉簫，竹實豐餱糧。", "至今嶙峋石，如作毛羽翔。", "深溪阻造極，懸磴聊褰裳。", "踟躕不忍下，樹杪青天長。"]'),
('7a084d4f-e229-410c-b930-52aae9717e50','九鎖山十詠  其四','王易簡','宋','宋诗','song-poetry','','[]','晴矼步清空，洞戶撫巀嶭。',60,'全唐诗/poet.song.247000.json','["晴矼步清空，洞戶撫巀嶭。", "何年出水龍，張口見齒舌。", "相傳此得名，靈骨蛻如雪。", "豈其風霆化，詰曲餘故穴。", "想當夜半歸，九鎖一時掣。"]'),
('17ebbdf4-e910-47f6-b9b5-a449a3d344db','九鎖山十詠  其五','王易簡','宋','宋诗','song-poetry','','[]','絕壁中嵌空，秀石下插地。',60,'全唐诗/poet.song.247000.json','["絕壁中嵌空，秀石下插地。", "緬懷玉局仙，於此冠蓋萃。", "雲泉儼昨游，卉木遺古意。", "青山日迎客，何者傳姓字。", "斯人千載名，攬勝乃餘事。"]'),
('b834fbce-1bf9-4346-8ce2-91bb731dcfcd','九鎖山十詠  其六','王易簡','宋','宋诗','song-poetry','','[]','古來得道人，一往無留蹤。',60,'全唐诗/poet.song.247000.json','["古來得道人，一往無留蹤。", "胡爲戀幽絕，努力抗祖龍。", "冠簪宛如刻，蘚蔓不敢封。", "形化影未滅，石堅誠可通。", "靈仙去已遥，聊爾驚凡庸。"]'),
('acaa0cc9-b164-449c-9003-1eeb3bac8a11','九鎖山十詠  其七','王易簡','宋','宋诗','song-poetry','','[]','行雲倏變滅，本作須臾期。',60,'全唐诗/poet.song.247000.json','["行雲倏變滅，本作須臾期。", "山靈護清氣，英英幻真姿。", "舊雨洗猶在，高風吹不移。", "觸石有動意，出岫無還時。", "扶桑如可薪，鍊此白玉芝。"]'),
('dbfde477-5eed-4053-8de3-3899fcc5cfb0','九鎖山十詠  其八','王易簡','宋','宋诗','song-poetry','','[]','嵐陰四圍合，澗水數折流。',60,'全唐诗/poet.song.247000.json','["嵐陰四圍合，澗水數折流。", "試手翻碧海，捲雨來青虬。", "靜躁爲人役，蓄泄同神謀。", "長歌亭上詩，飛仙不可留。", "倚欄天風寒，問信騎鯨游。"]'),
('605fe028-f2c1-4a4b-9d13-55175a21dc76','九鎖山十詠  其九','王易簡','宋','宋诗','song-poetry','','[]','天吳泣海枯，化石空山中。',60,'全唐诗/poet.song.247000.json','["天吳泣海枯，化石空山中。", "陵谷歷千變，倒倚蓬萊風。", "鐵壁立峭絕，縠波漾玲瓏。", "前巖寄游屧，大巧藏神功。", "素屏三十丈，畫手誰與同。"]'),
('9b4fbf6a-4052-4264-966b-db8745641182','九鎖山十詠  其一○','王易簡','宋','宋诗','song-poetry','','[]','泠泠珮行空，湛湛鏡無滓。',60,'全唐诗/poet.song.247000.json','["泠泠珮行空，湛湛鏡無滓。", "至潔漱巖骨，餘潤蒸石髓。", "山上真人居，鼎竈長不毀。", "猶聞洗藥香，漸作落花水。", "臨流且勿嘗，清音濯幽耳。"]'),
('e790aa5e-867e-46ab-9e5f-fb8dc07e2993','題高房山夜山圖','王易簡','宋','宋诗','song-poetry','','[]','高侯妙筆生夜光，李侯正倚斗牛旁。',32,'全唐诗/poet.song.247000.json','["高侯妙筆生夜光，李侯正倚斗牛旁。", "淒凉看盡吳山月，玉鏡臺前翠鳳凰。"]'),
('674ce65b-be70-4118-a9e5-5962bf4644a8','游寶林寺','王易簡','宋','宋诗','song-poetry','','[]','玄度存遺跡，玄英有舊詩。',48,'全唐诗/poet.song.247000.json','["玄度存遺跡，玄英有舊詩。", "城中獨高處，雪後最佳時。", "拂壁書行紀，逢僧問故祠。", "闌干頻徙倚，不奈朔風吹。"]'),
('6ccc4b00-a38d-43c0-acd5-d1ab0928e042','贈僧','葛慶龍','宋','宋诗','song-poetry','','[]','七軸蓮經供茗瓢，一龕繡佛挂松寮。',32,'全唐诗/poet.song.247000.json','["七軸蓮經供茗瓢，一龕繡佛挂松寮。", "舶香亦带魚龍氣，自采枝頭柏子燒。"]'),
('a05383e7-df42-439f-9431-4bd54489cde6','謝理得惠書','葛慶龍','宋','宋诗','song-poetry','','[]','五朵飛來漬剡藤，重重響似水泠泠。',32,'全唐诗/poet.song.247000.json','["五朵飛來漬剡藤，重重響似水泠泠。", "不教落在紅塵耳，讀與青松白鶴聽。"]'),
('4eee31f9-9c80-4b7e-976d-c91e7a563d5c','詠黄石公','葛慶龍','宋','宋诗','song-poetry','','[]','挾書律重火猶光，天下嚴搜不敢藏。',32,'全唐诗/poet.song.247000.json','["挾書律重火猶光，天下嚴搜不敢藏。", "圯上老人無見者，一編親寫授張良。"]'),
('d577807e-21b6-42a0-beb3-f571b2c5b2e5','筇杖','葛慶龍','宋','宋诗','song-poetry','','[]','白髪慵巾短短衣，閑行斜倚小筇枝。',32,'全唐诗/poet.song.247000.json','["白髪慵巾短短衣，閑行斜倚小筇枝。", "自家弄影猶癡絕，只似初騎竹馬時。"]'),
('c0de6bcb-574d-4d6c-9840-d6522c15abd4','題仙人洞并謝草堂方公所贈石匣  其一','葛慶龍','宋','宋诗','song-poetry','','[]','多謝林僧亦好奇，新遺石匣我酬詩。',32,'全唐诗/poet.song.247000.json','["多謝林僧亦好奇，新遺石匣我酬詩。", "鶴胎收却雲封裹，付囑山靈木客時。"]'),
('b9770be9-cefb-4043-84a0-040c59718c8d','題仙人洞并謝草堂方公所贈石匣  其二','葛慶龍','宋','宋诗','song-poetry','','[]','雲長鎮洞有時開，石匣終藏化鶴胎。',32,'全唐诗/poet.song.247000.json','["雲長鎮洞有時開，石匣終藏化鶴胎。", "千歲不須華表柱，飛鳴南向洞山來。"]'),
('4b002a2c-31f5-4b2b-8c40-8e0f26511e9f','游寶林寺','葛慶龍','宋','宋诗','song-poetry','','[]','坐如有待思依依，看竹迴廊出寺遲。',32,'全唐诗/poet.song.247000.json','["坐如有待思依依，看竹迴廊出寺遲。", "窅窅綠蔭清寂處，半窗斜日兩僧棋。"]'),
('1b138aad-f4c4-4f5f-b89d-1c555d353db5','陶庵精舍','殷彥卓','宋','宋诗','song-poetry','','[]','靜結羅浮屋，鄰鷄遠不聞。',72,'全唐诗/poet.song.247000.json','["靜結羅浮屋，鄰鷄遠不聞。", "秋到屋下田，井井皆黄雲。", "草堂久無夢，甘與麋鹿群。", "我聞彭澤令，恥爲二姓臣。", "一朝任去來，柴桑漉酒巾。", "披圖長歎息，古今多逸民。"]'),
('dc0c0ca6-a968-408a-9807-d4c4fcbdf6e7','水村歌','錢仲鼎','宋','宋诗','song-poetry','','[]','舟摇摇兮，風嫋嫋兮。',32,'全唐诗/poet.song.247000.json','["舟摇摇兮，風嫋嫋兮。", "波鱗鱗兮，鷗翩翩兮。", "扣舷漁歌兮，孰知其他兮。"]'),
('76ebfdd0-e0b1-45b6-b805-9efc217718b3','題趙鷗波高士圖','錢仲鼎','宋','宋诗','song-poetry','','[]','在昔洛陽，雪深丈餘。',90,'全唐诗/poet.song.247000.json','["在昔洛陽，雪深丈餘。", "士也高卧，來令尹車。", "今年吳淞，雪復何如。", "積素一色，鷗鷺有無。", "之子江臯，修亭是居。", "有琴有書，有酒有魚。", "賞靜獨眺，聊以自娛。", "挹茲清風，凜凜起予。", "此景此圖，再卷再舒。"]'),
('9ac75ad5-2276-4e89-80e4-9be06b93cf0e','題靜春堂集','錢仲鼎','宋','宋诗','song-poetry','','[]','閉門雪卧遠，詠史風情留。',216,'全唐诗/poet.song.247000.json','["閉門雪卧遠，詠史風情留。", "詩有三百篇，令子手所裒。", "汝翁秀儒林，殖學媲前修。", "六經窮窔奧，萬象工雕鎪。", "廣矣雅音正，悕矣騷情幽。", "照耀明月珠，珍重珊瑚鉤。", "一讀令人喜，再讀令人愁。", "李杜骨已朽，江湖名同流。", "憶昔託末契，東城得追游。", "平時少契闊，暇日多唱酬。", "櫟材自揣劣，藻思誰與儔。", "老我歲冉冉，霜鬢風飈飈。", "索居破茅屋，寒擁敝貂裘。", "夜來清夢飛，故繞松江頭。", "夢中不識路，修亭渺悠悠。", "粲然見梅花，落月香影浮。", "性情閲千古，感發交未休。", "神交赴冥冥，知我雙白鷗。"]'),
('8c00a03a-51c7-4077-a38d-4580f61ffb13','述懷','羅太瘦','宋','宋诗','song-poetry','','[]','淮海歸來二十年，結廬仍向舊山川。',64,'全唐诗/poet.song.247000.json','["淮海歸來二十年，結廬仍向舊山川。", "既無酒債貧休恨，浪得文名老尚傳。", "曉日輪蹄思柳外，春風羯鼓在花前。", "如今靜聽瓶笙韻，猶似當年咽管絃。"]'),
('c1ff972e-fa27-45ef-bb0e-2f547055fb9d','題鶴林宮','羅太瘦','宋','宋诗','song-poetry','','[]','暑往寒來迭世間，有誰十載駐朱顔。',64,'全唐诗/poet.song.247000.json','["暑往寒來迭世間，有誰十載駐朱顔。", "騎鯨客去天連水，跨鶴人歸月在山。", "爐火頓消情慾境，劍金須斷利名關。", "烟莎隨分巖前綠，猿馬不驚春意閒。"]'),
('2fbbf920-5966-412e-88b9-9d41f015bc56','題樑','顔丙','宋','宋诗','song-poetry','','[]','靈根不肯混凡柴，天意移將福地來。',32,'全唐诗/poet.song.247000.json','["靈根不肯混凡柴，天意移將福地來。", "向日親逢霹靂手，今朝果作棟樑材。"]'),
('dc3d7e9b-0666-4f01-8f4e-949bbc288f11','夾竹桃','湯清伯','宋','宋诗','song-poetry','','[]','芳姿勁節本來同，綠蔭紅妝一樣濃。',32,'全唐诗/poet.song.247000.json','["芳姿勁節本來同，綠蔭紅妝一樣濃。", "我若化龍君作浪，信知何處不相逢。"]'),
('d8d87cf3-2c54-4de4-a98d-bb24eb0302a8','草意','曾唯仲','宋','宋诗','song-poetry','','[]','輦路淒淒隔歲華，王孫望斷怨天涯。',32,'全唐诗/poet.song.247000.json','["輦路淒淒隔歲華，王孫望斷怨天涯。", "庭空煙雨無人管，那有閒情襯落花。"]'),
('a089abfd-f4bd-455b-98b5-2cd796c30bb3','感物  其一','艾性夫','宋','宋诗','song-poetry','','[]','中園植佳橘，插棘爲儲胥。',60,'全唐诗/poet.song.247000.json','["中園植佳橘，插棘爲儲胥。", "橘根陽未萌，棘枝已扶疏。", "終年高且深，勢盛凌橘孤。", "豈以雨露偏，良由習性殊。", "非類不可依，橘其防厥初。"]'),
('57250ac2-49b4-4420-b81b-c54b6e445730','感物  其二','艾性夫','宋','宋诗','song-poetry','','[]','老牧鞭群羝，長鳴度荒圃。',48,'全唐诗/poet.song.247000.json','["老牧鞭群羝，長鳴度荒圃。", "眈眈黄於菟，怒攫連四五。", "弱肉强之食，茲事由來古。", "天地果好生，生羊勿生虎。"]'),
('f5416e4b-b3cc-4ae7-b669-5e6cc90251ae','感物  其三','艾性夫','宋','宋诗','song-poetry','','[]','溪翁擷佳草，日恐饑其魚。',48,'全唐诗/poet.song.247000.json','["溪翁擷佳草，日恐饑其魚。", "霜枯野水落，獱獺搜無餘。", "翁歸束稿人，寘彼溪之隅。", "責以警長夜，翁計何其愚。"]'),
('e29e8863-da7c-4627-ad92-a2473273244d','感物  其四','艾性夫','宋','宋诗','song-poetry','','[]','有山莫栽桃，有地宜種竹。',60,'全唐诗/poet.song.247000.json','["有山莫栽桃，有地宜種竹。", "此竹豈不佳，清陰蔽茅屋。", "朝有孤鳳翔，暮有白鶴宿。", "桃花艷春風，蜂蝶趁麄俗。", "花謝不復來，相媚一餉足。"]'),
('ef4e5be7-70a1-4eb1-b0e3-7b02e172e9cb','古意  其一','艾性夫','宋','宋诗','song-poetry','','[]','折柳繫離船，船行柳條短。',24,'全唐诗/poet.song.247000.json','["折柳繫離船，船行柳條短。", "頼有枝上花，飄泊隨君遠。"]'),
('fd4b3dd9-5699-4be7-88f7-b924a6620549','古意  其二','艾性夫','宋','宋诗','song-poetry','','[]','采蓮莫采花，采花損空房。',24,'全唐诗/poet.song.247000.json','["采蓮莫采花，采花損空房。", "留房結青子，種作明年香。"]'),
('2b2f3d7f-9cf4-4e71-a1de-85ccfdd3ba6b','古意  其三','艾性夫','宋','宋诗','song-poetry','','[]','匆匆采桑女，花雨濕襜袖。',24,'全唐诗/poet.song.247000.json','["匆匆采桑女，花雨濕襜袖。", "春風十二絃，生世未觸手。"]'),
('02d06037-fb8d-493f-9eaf-d142df19e1d7','古意  其四','艾性夫','宋','宋诗','song-poetry','','[]','浣衣輕浣布，布縷不如絲。',24,'全唐诗/poet.song.247000.json','["浣衣輕浣布，布縷不如絲。", "絲堅猶易穿，布弱從可知。"]'),
('8ea751ca-c953-4e39-b487-6accac09da44','古意  其五','艾性夫','宋','宋诗','song-poetry','','[]','佳人買明鏡，意重輕千金。',36,'全唐诗/poet.song.247000.json','["佳人買明鏡，意重輕千金。", "結以雙羅带，欲照蕩子心。", "蕩子渺不歸，鏡影春雲深。"]'),
('2fa832fc-0b1a-4291-9cbb-3e750d9febe1','古意  其六','艾性夫','宋','宋诗','song-poetry','','[]','賤妾燕子身，銜泥巢君堂。',48,'全唐诗/poet.song.247000.json','["賤妾燕子身，銜泥巢君堂。", "遊子黄鵠志，辭家猶南翔。", "采花爲誰容，襲蘭爲誰香。", "安得小心風，寄子雙明璫。"]'),
('f41b2239-9946-449a-a899-9992bff193a9','雜言  其一','艾性夫','宋','宋诗','song-poetry','','[]','蒼梧閟弓劍，阿閣無祥禽。',84,'全唐诗/poet.song.247000.json','["蒼梧閟弓劍，阿閣無祥禽。", "魯叟已長喟，矧敢求之今。", "區區蓮勺人，伯氣方浸淫。", "紀年侈嘉瑞，作物誠何心。", "隠顯殆偶然，豈必聞韶音。", "黄河千丈渾，歲月亦已深。", "矯首不可俟，甪里芝山陰。"]'),
('126b11ad-5b6b-4c7f-99f1-8828205b1037','雜言  其二','艾性夫','宋','宋诗','song-poetry','','[]','勛華不並世，揖遜無餘傳。',72,'全唐诗/poet.song.247000.json','["勛華不並世，揖遜無餘傳。", "緬彼巢與津，佳兵豈其天。", "履霜一何微，坤冰一何堅。", "誰謂知幾人，尚俟觀伊川。", "斧衮了不公，正閏雜紀年。", "豈擬王仲淹，而愧魯仲連。"]'),
('882a580e-004f-4733-979a-596c4592a0c1','雜言  其三','艾性夫','宋','宋诗','song-poetry','','[]','燕趙多佳人，珠華衒天街。',84,'全唐诗/poet.song.247000.json','["燕趙多佳人，珠華衒天街。", "鄭魯有游女，折楊弄青梅。", "春風趁姿媚，諧笑爭徘徊。", "幽閨有貧醜，修潔不自媒。", "縫布以爲裙，斷荆以爲釵。", "𧤺沙事機杼，蓬沓蒙烟埃。", "誰將好德心，爲爾停漸臺。"]'),
('426b1451-53d1-4a56-9652-788e834498ce','雜言  其四','艾性夫','宋','宋诗','song-poetry','','[]','枯桐斵山骨，絃以冰蠶絲。',72,'全唐诗/poet.song.247000.json','["枯桐斵山骨，絃以冰蠶絲。", "信指發孤調，悠然造希夷。", "揚以寄吾歡，抑以寫吾悲。", "悲歡生我心，無庸他人知。", "我若有黄金，不鑄鍾子期。", "寄語伯牙翁，絕絃良可嗤。"]'),
('00d5d997-3839-41be-8037-f0ca0bd87fba','牧童','艾性夫','宋','宋诗','song-poetry','','[]','櫛髪吹松陰，坦腹睨岩石。',48,'全唐诗/poet.song.247000.json','["櫛髪吹松陰，坦腹睨岩石。", "細雨整短蓑，斜陽擫長笛。", "採花艷兩髻，挾草暖雙腋。", "款款跨牛歸，蒼山暮烟碧。"]'),
('dfd3d458-7f97-4572-8df0-2f25971ca225','題東坡蔗滓窠石','艾性夫','宋','宋诗','song-poetry','','[]','空洞如虛拳，擁腫類奇癭。',48,'全唐诗/poet.song.247000.json','["空洞如虛拳，擁腫類奇癭。", "槎牙老樹身，相依以爲命。", "智士能用屈，榴皮勝毛穎。", "先生倒啗餘，此正入佳境。"]'),
('75380ec4-57ae-4a5e-8604-989b788f54e3','憫盆松','艾性夫','宋','宋诗','song-poetry','','[]','物生天地間，細大各有容。',48,'全唐诗/poet.song.247000.json','["物生天地間，細大各有容。", "偉哉霄漢姿，厄此盆盎中。", "嗟吁爾橐駝，局促吾蒼龍。", "駝兮顧我笑，可憫豈獨松。"]'),
('5dd9cf42-01ea-498e-983b-cdfd35ece7db','貓犬歎','艾性夫','宋','宋诗','song-poetry','','[]','飯貓奉魚肉，憐惜同寢處。',88,'全唐诗/poet.song.247000.json','["飯貓奉魚肉，憐惜同寢處。", "飼犬雜糠籺，呵斥出庭戶。", "犬行常低循，貓坐輒箕踞。", "愛憎了不同，拘肆固其所。", "虛堂夜搜攪，忽報犬得鼠。", "問貓爾何之，翻甕竊醢脯。", "犬雖出位終愛主，貓兮素餐烏用汝。"]'),
('aa325283-225a-408a-9f3c-925c78f483a4','答釋子問詩法','艾性夫','宋','宋诗','song-poetry','','[]','汝家有子蘭，詩體能入選。',76,'全唐诗/poet.song.247000.json','["汝家有子蘭，詩體能入選。", "爾後島可輩，往往以律變。", "選律固無擇，語意忌庸淺。", "大音尚和平，至味貴悠遠。", "歸歟事斯語，妙理千萬變。", "歐稱九僧今不見，退之擬過紅樓院。"]'),
('80974dc9-5a12-41fc-b7b4-d169b7b10b99','諸公賦東園兄銅雀硯甚夸余獨不然然蘇長公詩銘梅都官長句皆爾如謂舉世爭稱鄴瓦堅一枚不換百金頒不及鴛鴦飛乃有科斗情入用固爲貴論古難與并之類是已敢併爲之反騷','艾性夫','宋','宋诗','song-poetry','','[]','臨洮健兒衷甲衣，曹家養兒乘禍機。',224,'全唐诗/poet.song.247000.json','["臨洮健兒衷甲衣，曹家養兒乘禍機。", "匹夫妄作九錫夢，鬼蜮敢學神龍飛。", "負鼎而趍不遄死，築臺尚欲儲歌舞。", "但知銅雀望西陵，不覺妖狐叫墟墓。", "分香賣履吁可憐，所志止在兒女前。", "竟令山陽奉稚子，出爾反爾寧無天。", "陳留作賓向司馬，包羞更出山陽下。", "國亡臺廢天厭之，何事人猶拾殘瓦。", "古來觀物當觀人，虞琴周鼎絕世珍。", "區區陶甓出漢賊，矧可使與斯文親。", "歙溪龍尾誇子石，端州鴝眼真蒼璧。", "好奇不惜買千金，首惡寧容汙寸墨。", "書生落筆驅風雷，要學魯史誅姦回。", "請君唾去勿復用，銅雀猶在吾當摧。"]'),
('58c1b65e-3f3a-4174-8bae-964a16e4c50c','天下第二鐘歌','艾性夫','宋','宋诗','song-poetry','','[]','瀕江破寺如膠舟，大鏞露立寒颼颼。',200,'全唐诗/poet.song.247000.json','["瀕江破寺如膠舟，大鏞露立寒颼颼。", "金繩鐵紐作斷綆，土花苔碧生欒頭。", "我來摩挲考歲月，僂指落落三百秋。", "想當營度欲鼓火，野鬼夜哭山精愁。", "鑄之以紹威六州之鐵，釁之以景升千斤之牛。", "載之以長河萬斛之艦，貯之以齊雲百尺之樓。", "風高一撞撼天地，世更幾變宜追蠡。", "眼中驚見已無雙，天下才稱爲第二。", "庚庚古扁磨蒼珉，徐郎妙墨吹玄雲。", "聲光喑啞盡埋沒，宇宙顛倒方紛紜。", "昭陵石馬化爲土，于上蒲牢幸存古。", "山僧作屋穩蓋藏，他日岐陽求石鼓。"]'),
('0efa719a-e100-4a05-8cb2-1fb0f88ef421','題危見心所藏陳常庵水月障及松鶴蘆雁各一首  其一','艾性夫','宋','宋诗','song-poetry','','[]','陳郎筆勢并州剪，十幅生綃秋綠遠。',64,'全唐诗/poet.song.247000.json','["陳郎筆勢并州剪，十幅生綃秋綠遠。", "老蟾欲作騎鯨遊，推墮玉盤波底轉。", "謫仙濡袍窺采石，東坡醉客歌赤壁。", "兩翁已矣愛者誰，我欲扁舟擫長笛。"]'),
('4eb321b4-6d9c-411e-8c29-accad7523ded','題危見心所藏陳常庵水月障及松鶴蘆雁各一首  其二','艾性夫','宋','宋诗','song-poetry','','[]','墨池幻出虬龍蟠，徂徠山頭烟雨寒。',64,'全唐诗/poet.song.247000.json','["墨池幻出虬龍蟠，徂徠山頭烟雨寒。", "胎禽獨立衣縞縞，骨瘦西風拾瑶草。", "靈根琥珀三千年，紫皇勅賜青城仙。", "乘軒竊祿正自惡，何似歸來一丘壑。"]'),
('8a47f76b-fba5-47f2-a50c-0cd49c88be15','題危見心所藏陳常庵水月障及松鶴蘆雁各一首  其三','艾性夫','宋','宋诗','song-poetry','','[]','風吹黄沙石磧冷，霜葦無聲弄寒影。',64,'全唐诗/poet.song.247000.json','["風吹黄沙石磧冷，霜葦無聲弄寒影。", "兵塵隔斷衡陽雲，溪藤捲送瀟湘景。", "蘆花雪老菰米秋，芙蓉露下天悠悠。", "阿奴呼起字不斷，寫出萬斛江南愁。"]'),
('3c69a790-0c15-4901-93b8-c4ea69a476fb','贈福希範遊','艾性夫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','伽梨點破長蘿綠，瓣香問信黄梅熟。',114,'全唐诗/poet.song.247000.json','["伽梨點破長蘿綠，瓣香問信黄梅熟。", "筇雲笠雪霜色寒，法宇歸來詩滿腹。", "春風破曉來打門，行矣廬山與天竺。", "天空雲遠意未盡，却上天台恣遊目。", "吾聞天台石橋滑如竹，千僧萬僧畏涉足。", "請師了此一大事，一洗世間凡眼肉。", "浮杯試罷海風高，歸就梅花結吟屋。"]'),
('d8068cb2-6386-4b5b-a73b-f815795dc2d1','贈後山僧謙自牧遊','艾性夫','宋','宋诗','song-poetry','','[]','爲僧不遊醯甕雞，遊不名山沮澤龜。',128,'全唐诗/poet.song.247000.json','["爲僧不遊醯甕雞，遊不名山沮澤龜。", "見山無詩僧亦俗，詩不高古猶無詩。", "吾謙年少鍾老氣，髪根甫斷撥雲去。", "歸來笠雪兩肩寒，已覺囊中有佳句。", "一枝瘦杖萬里心，策策尚欲窮幽尋。", "湖光山綠上下竺，谷花溪月東西林。", "我亦愛山行不得，把酒高歌壯行色。", "爲語春風九里松，題詩野客今頭白。"]'),
('c7ec8d91-bbe4-44d9-be0b-3274738fba8b','嘆屩詞','艾性夫','宋','宋诗','song-poetry','','[]','履穿無下嘆東郭，桃椎尚欠居士屩。',64,'全唐诗/poet.song.247000.json','["履穿無下嘆東郭，桃椎尚欠居士屩。", "是誰業屨捆秋芒，絕勝編棨便行脚。", "花泥溶溶草露滴，山石齒齒苔烟碧。", "江南林壑天下奇，不識春申珠履客。"]'),
('ba3e67a1-8266-4754-811b-2fbf0dba8d82','臨邛道士招魂歌','艾性夫','宋','宋诗','song-poetry','','[]','錦襪生塵脫紅玉，瓊蟾夜抱金娥哭。',160,'全唐诗/poet.song.247000.json','["錦襪生塵脫紅玉，瓊蟾夜抱金娥哭。", "芙蓉露瘦寒花鈿，鳷鵲樓空冷銀燭。", "輕鸞小鳳橫紫簫，彩雲密漾青霞綃。", "桂心沁入鎖子骨，蕊宮貝闕天都遥。", "玉床夢斷心欲死，獨抱秋衾嚥香髓。", "方瞳白羽青簡書，駕月騎風渡瑶水。", "瓊樓碧戶翠霧香，紫蘭結佩紅薇囊。", "雲車仙子不可識，芳卿寄謝真荒唐。", "蔗漿不飲啼寒淚，不悟齊人少翁詭。", "安得天上蓬萊宮，却著人間馬嵬鬼。"]'),
('33330342-fc82-4b01-aabe-72cc1acbb5c8','別離詞  其一','艾性夫','宋','宋诗','song-poetry','','[]','郎從江上買行舟，妾對江楓生晚愁。',32,'全唐诗/poet.song.247000.json','["郎從江上買行舟，妾對江楓生晚愁。", "雁雲不斷楚天碧，望郎怕上水邊樓。"]'),
('1d74cbb2-5c5c-4acc-a1bd-44dc5d2a2f0e','別離詞  其二','艾性夫','宋','宋诗','song-poetry','','[]','渡江桃葉郎莫歌，巴西竹枝愁更多。',32,'全唐诗/poet.song.247000.json','["渡江桃葉郎莫歌，巴西竹枝愁更多。", "黄塵百丈水花黑，把酒勸郎無渡河。"]'),
('ce2e729a-2e6e-41d5-ab4c-38d0d62f8327','丫頭巖詩載牆壁間無慮數十百首形容蓋有盡之者矣輒復寄興以俟採詩者擇焉  其一','艾性夫','宋','宋诗','song-poetry','','[]','色盛人自憐，色衰人見棄。',83,'全唐诗/poet.song.247000.json','["色盛人自憐，色衰人見棄。", "人心不可憑，女色焉足恃。", "未笄化爲石，不願從夫婿。", "厭華喜質如梁鴻，布衣操臼當相從。", "君不見漢家天子劉文叔，郭后容衰亦遭逐。", "何如山頭化石不嫁老亦足。"]'),
('cd63e3a9-86c4-4d18-88e5-53547a5d88a7','丫頭巖詩載牆壁間無慮數十百首形容蓋有盡之者矣輒復寄興以俟採詩者擇焉  其二','艾性夫','宋','宋诗','song-poetry','','[]','女色無醜妍，入宮皆見妬。',83,'全唐诗/poet.song.247000.json','["女色無醜妍，入宮皆見妬。", "蛾眉等芻蛹，嬉笑藏刀鋸。", "未笄化爲石，不願長門去。", "國風直待歌螽斯，委身事主妾不辭。", "君不見趙王如意今日死，明日佳人亦投厠。", "何如山頭化石千歲老無子。"]'),
('91569b82-b5b9-4085-ba5e-bbff917ca9ac','題曾逵臣草蟲','艾性夫','宋','宋诗','song-poetry','','[]','蝘蜓走昂頭，螳蜋怒張臂。',76,'全唐诗/poet.song.247000.json','["蝘蜓走昂頭，螳蜋怒張臂。", "走欲捕生怒欲制，筆活能融兩蟲意。", "無人飯汝金砂紅，糜肌粉肉牢守宮，草間敢爾誇豪雄。", "捕蟬幸脫黄雀舌，輕鬬懸知腰股折，力微謹勿當車轍。"]'),
('ddce6b78-f7f2-40db-b63e-0b842205022b','書馬使君所藏草蟲','艾性夫','宋','宋诗','song-poetry','','[]','晉陵草蟲妙天下，一幅千金不當價。',64,'全唐诗/poet.song.247000.json','["晉陵草蟲妙天下，一幅千金不當價。", "誰將此本送使君，蜂蝶數輩蔬一根。", "此蔬雅淡無色香，嗟汝蜂蝶空疏狂。", "人間桃李千萬樹，有翅奈何不飛去。"]'),
('d0908d7f-e449-46c3-a3d2-dfa6007907c4','山谷跋楊妃齒痛圖謂多食側生致動摇其左車是殆不然因爲翻案天寶遺事云時羅公遠進藥明皇自和飲妃故併及之','艾性夫','宋','宋诗','song-poetry','','[]','蜀帝化子規，啼血思還家。',104,'全唐诗/poet.song.247000.json','["蜀帝化子規，啼血思還家。", "玉環苦微疢，寄汝呼痛牙。", "物類相殊或相托，悲鳴一夜梨花落。", "三郎玉柙已成塵，半匕金罌誰和藥。", "紫駝翠釜不生兵，何與涪南新側生。", "人間極寵皆禍兆，莫把妖魂幻飛鳥。", "平生誤識安祿山，馬嵬欲死先齒寒。"]'),
('29a21116-b823-48fa-b365-81fa4c0b2a94','雁塔','艾性夫','宋','宋诗','song-poetry','','[]','君不見春初淮白魚，秋深黄雀兒。',103,'全唐诗/poet.song.247000.json','["君不見春初淮白魚，秋深黄雀兒。", "川潜山泊誰得知，災身不幸甘且肥。", "官饕弗渠赦，竟作一網打。", "頭顱千百奉苞苴，猩紅熊白風斯下。", "吾生亦何好，獨坐味頗厚。", "急符星火督虞人，覆巢空類無遺噍。", "寧逢江南射生手，莫遇雁門饞太守。"]'),
('acb593aa-6881-49a4-82ea-97583e18fa3e','荷葉','艾性夫','宋','宋诗','song-poetry','','[]','愛蓮盡愛花，而我獨愛葉。',132,'全唐诗/poet.song.247000.json','["愛蓮盡愛花，而我獨愛葉。", "水仙剪圓碧，萬柄相倚疊。", "風掀翠釜舉，露浥鮫珠曄。", "不必滿川紅，香氣自薰浹。", "龜魚蔭凉影，鷺鷗憩別業。", "潔可包龍城賈客之飯，清可製三閭修士之衣。", "大可載太乙真人之卧，高可蓋桐江神女之歸。", "醉仙捲作碧玉盞，歌妓携來綠雲扇。", "有時聽雨隔窗眠，湖聲十里錢塘晚。"]'),
('878e8118-21d1-478e-8f38-1a394cf50bfb','題葉氏分綠亭','艾性夫','宋','宋诗','song-poetry','','[]','山亭種花厭脂粉，純種芭蕉三百本。',64,'全唐诗/poet.song.247000.json','["山亭種花厭脂粉，純種芭蕉三百本。", "一心生意展不盡，四面蟠根培自穩。", "捲舒風日閃流翠，滉滉清陰浸窗戶。", "煩君凈拭湘竹牀，著我橫眠聽秋雨。"]'),
('45873c2e-8777-4690-8d56-51bc47940bd8','棠渡初雪','艾性夫','宋','宋诗','song-poetry','','[]','雪風吹凍冰人鬚，老梅著花明矮籬。',64,'全唐诗/poet.song.247000.json','["雪風吹凍冰人鬚，老梅著花明矮籬。", "黄蘆蕭蕭白雁落，野樹歷歷青猿啼。", "旗亭有酒味苦短，地爐濕薪烟粗煖。", "五陵狎客不下樓，紅金火閣玻璃盌。"]'),
('04aac3f5-34d8-4404-9116-cc401079bd84','古鏡詞','艾性夫','宋','宋诗','song-poetry','','[]','人生兩瞳子，爛爛岩下電。',115,'全唐诗/poet.song.247000.json','["人生兩瞳子，爛爛岩下電。", "見盡天下人，不見自己面。", "古哉容成侯，作我眼外眼。", "我老得君照，君老還我見。", "蘚花繞背字痕青，彷彿陽冰八分篆。", "神光一點未埋沒，尤物千年幾流轉。", "君不見揚子江心水如練，年年鑄入凝陰殿。", "後來血染江水渾，至今端午人閉門。"]'),
('9db064a6-6839-4a4a-a328-423c208da02d','次韻曠翁四時村居樂  其一','艾性夫','宋','宋诗','song-poetry','','[]','欲晴欲雨天溟濛，林塘淡蕩摇春風。',64,'全唐诗/poet.song.247000.json','["欲晴欲雨天溟濛，林塘淡蕩摇春風。", "遊絲落絮鬬飛舞，野花芳草爭青紅。", "南園北園桑柘綠，村前村後啼布穀。", "蠶姑把葉祝絲多，田翁拜社祈年熟。"]'),
('b2c4d312-ce44-4859-a34c-5c7a22231a11','次韻曠翁四時村居樂  其二','艾性夫','宋','宋诗','song-poetry','','[]','藕花分房菱出角，瓜實纍纍蔓籬落。',64,'全唐诗/poet.song.247000.json','["藕花分房菱出角，瓜實纍纍蔓籬落。", "稻田水多翁不愁，日抱筠筐曬山藥。", "清溪濯暑生布裳，石薷煮透山泉香。", "涯南老屋頗宜夏，草窗瓦枕松風凉。"]'),
('38c5b73f-cfe1-4cfa-83ec-37c0f6da4fec','次韻曠翁四時村居樂  其三','艾性夫','宋','宋诗','song-poetry','','[]','雁雲漠漠梧桐秋，風露颯颯生平疇。',64,'全唐诗/poet.song.247000.json','["雁雲漠漠梧桐秋，風露颯颯生平疇。", "芭蕉葉黄夜氣濕，老壁屈曲行蝸牛。", "林外炊烟暗青樹，牆頭凉月驚鳴杵。", "柴門犬吠人語多，刈熟歸來碧天暮。"]'),
('41c3ddd6-49af-4f55-810b-aab43ed08c99','次韻曠翁四時村居樂  其四','艾性夫','宋','宋诗','song-poetry','','[]','黄雞懶啼霜月低，青羽亂啄梅花飛。',64,'全唐诗/poet.song.247000.json','["黄雞懶啼霜月低，青羽亂啄梅花飛。", "烏犍怯寒不出圈，白犬耐凍時穿籬。", "老松墮枝供武火，枯蒲織蓆遮窗破。", "一窩容膝煖即休，不問甕中天幾大。"]'),
('514fc1a4-b2d6-40be-b4fd-552c9a8b9d21','木綿布歌','艾性夫','宋','宋诗','song-poetry','','[]','吳姬織綾雙鳳花，越女製綺五色霞。',192,'全唐诗/poet.song.247000.json','["吳姬織綾雙鳳花，越女製綺五色霞。", "犀薰麝染脂粉氣，落落不到山人家。", "蜀山橦老鵠銜子，種我南園趁春雨。", "淺金花細亞黄葵，綠玉苞肥壓青李。", "吐成秋繭不用繰，回看春箔真徒勞。", "烏鏐笴滑脫茸核，竹弓弦緊彈雲濤。", "挼挲玉筯光奪雪，紡絡冰絲細如髪。", "津津貧女得野蠶，軋軋寒機緯霜月。", "布成奴視白㲲氈，價重唾取青銅錢。", "何須致我爐火上，便覺挾纊春風前。", "衣無美惡煖則一，木棉裘敵天孫織。", "飲散金山弄玉簫，風流未遜揚州客。"]'),
('d93824db-aa50-4296-a744-bf4dd7db8aa0','題雲錦劉從甫水竹雲山亭','艾性夫','宋','宋诗','song-poetry','','[]','玻璃冷浸清湘玉，白衣暖護秋屏綠。',64,'全唐诗/poet.song.247000.json','["玻璃冷浸清湘玉，白衣暖護秋屏綠。", "淮南公子有勝情，收拾四美歸吾亭。", "問君亭中更何有，解事家人頻送酒。", "客來醉賞不得歸，拍闌朗誦亭中詩。"]'),
('dc7bf5a6-64b5-4eef-83cc-1ee4633c380f','解棋','艾性夫','宋','宋诗','song-poetry','','[]','兩雄相持機不發，一著輸先智相軋。',176,'全唐诗/poet.song.247000.json','["兩雄相持機不發，一著輸先智相軋。", "退守皆虞虎穴空，通和不肯鴻溝割。", "危枰已屬墮甑裏，巧勢爭看强弩末。", "疲思嘿嘿鬼神寂，密運茫茫天地闊。", "悍雞趁鬬不暇咮，駿馬爭馳各忘秣。", "矰禽睥睨欲高舉，罝兔迷離思遠脫。", "死中求生背水陣，灰冷復焚餘燭跋。", "白登倏報沛公走，閼與俄聞趙師活。", "傍觀駭服算入妙，對局虛驕氣方奪。", "人生勝負何可期，生達難欺死諸葛。", "推枰一笑拍闌干，滿袖松風凉潑潑。"]'),
('3f85fb79-2d46-4b2f-82ed-52ee8f3705da','題陳摶題壁圖','艾性夫','宋','宋诗','song-poetry','','[]','長松梢梢老烟霧，瀑泉飛落千丈布。',160,'全唐诗/poet.song.247000.json','["長松梢梢老烟霧，瀑泉飛落千丈布。", "樹精摇手不敢呵，雅是仙人熟眠處。", "睡蛇未死驚起來，風吹野服冠崔嵬。", "雙髽窣窣磨老瓦，墨汁湑湑翻莓苔。", "一翁擁篲供掃壁，一翁聳膊觀落筆。", "欲寫未寫方昂頭，野趣含秋正蕭瑟。", "先生壯志神龍驤，欲跨八表提天綱。", "市衢呼酒沃俠客，豈肯老死蒼山傍。", "忽來馿上聽鳴鏑，中原王氣開皇極。", "心事西峰一首詩，真人自在陳橋驛。"]'),
('076a9885-bec0-4de1-91d7-9f77c9e66121','酬春湖史履庸惠四皓圖','艾性夫','宋','宋诗','song-poetry','','[]','有客有客吾春湖，踏霜打門呼老夫。',192,'全唐诗/poet.song.247000.json','["有客有客吾春湖，踏霜打門呼老夫。", "寒溫粗了不暇坐，兩手奉我商山圖。", "皓首龐眉髪如漆，千古高人誰畫出。", "疏行大字各題詩，頗類涪翁老年筆。", "綺里季，夏黄公，春風拍浮酒兩鍾。", "仰天但覺宇宙窄，麾麈一掃塵凡空。", "東園甪里更蕭散，石鼎茶瓢風日晚。", "琵琶不作兒女悲，橫琴靜送飛鴻遠。", "周家遺民方避秦，留侯眼高識天人。", "翩翩小出奠危社，落落高舉連青雲。", "感君持贈慰枯槁，玉雪輝輝見諸老。", "何當乘鶴參翱翔，風露清凉咽瑶草。"]'),
('fb2e006f-a3d8-4619-af16-cc372daa32eb','浣紗曲','艾性夫','宋','宋诗','song-poetry','','[]','浣紗如妾心，皎然照冰雪。',104,'全唐诗/poet.song.247000.json','["浣紗如妾心，皎然照冰雪。", "秋聲入絡緯，炯炯織霜月。", "裁衣嫁作梁鴻婦，白髪相看如此布。", "不學西施矜媚嫵，妝成欲覓君王顧。", "忘却土城山下路，貪向銅龍溪邊住。", "明朝吳騎猛如虎，獻入娃宮作俘虜。", "含羞短製衣楚楚，忍學翩翩鶴翎舞。"]'),
('3230a81a-130f-4620-9ad5-1f94a444b046','田家詞','艾性夫','宋','宋诗','song-poetry','','[]','大兒荷鍤去疏麻，小兒提筐來採茶，翁自决水灌秧芽。',40,'全唐诗/poet.song.247000.json','["大兒荷鍤去疏麻，小兒提筐來採茶，翁自决水灌秧芽。", "今年續食不可望，一夜老風摇麥花。"]'),
('d48e9f42-3e64-44a5-9e06-d77d78f06f8c','昭君出塞圖','艾性夫','宋','宋诗','song-poetry','','[]','長門寫遍泥金帖，春風暗老如花靨。',160,'全唐诗/poet.song.247000.json','["長門寫遍泥金帖，春風暗老如花靨。", "臂紗尚護紅守宮，妾命君恩盡如葉。", "一朝結束嫁荒陲，一馬前導五馬隨。", "老奚并轡相笑語，雙袖自抱琵琶啼。", "邊風吹碎心如夢，雲長只有孤鴻送。", "早知氈帳是羊車，却把黄金博青冢。", "向來玉鎖摇銅環，咫尺不得窺天顔。", "祇今墮在萬里外，日光那到祁連山。", "女色自矜還自悞，畫史欺君君莫怒。", "甘向匈奴作婦翁，而翁首禍羞千古。"]'),
('83a29996-4c9a-4722-938c-bbff7a45552a','與觹軸工鄭老','艾性夫','宋','宋诗','song-poetry','','[]','君不見世南人間行秘書，撐腸拄腹搜不枯。',134,'全唐诗/poet.song.247000.json','["君不見世南人間行秘書，撐腸拄腹搜不枯。", "眼空千古不留物，更用芸香祛蠹魚。", "又不見王家樓中五百車，錦奩玉軸籤紅牙。", "夜生光怪射東壁，神鬼錯愕相驚嗟。", "無形之書不復見，有形之書今亦鮮。", "吳儂鞭馬馳京塵，何曾著眼雞林人。", "弓刀自带封侯相，黄金不博青藜杖。", "請翁少待三十年，怕有米家書畫船。"]'),
('e6b59f2a-b4b2-4644-8a45-1cd4622a4715','舊有歙硯雅宜墨鑱賤號于陰以亂亡去十餘年矣忽見之村學堂中睨視間有艴然持之却走者如恐予之取也因作此以遺硯','艾性夫','宋','宋诗','song-poetry','','[]','冰蠶吐絲寒玉蒼，老龍磨角玄雲香，半生食汝充饑腸。',124,'全唐诗/poet.song.247000.json','["冰蠶吐絲寒玉蒼，老龍磨角玄雲香，半生食汝充饑腸。", "正爾悒悒傷弓亡，一日到眼驚餘皇，欲呼未見誰鬣長。", "庸奴自愧取不臧，艴然持之走蓋藏。", "嗚呼得失安可常，我不善保遺渠殃，苟能藏之殃而祥。", "但隨牛後失所當，枯竹尚作神龍驤。", "安得石精變化飛墮桑君旁，塞翁失馬心清凉。"]'),
('b736737b-54e6-402f-9d58-17c5588dfc9d','雪吟效禁體并去一切熟事','艾性夫','宋','宋诗','song-poetry','','[]','群仙碎翦明河水，須臾變換人間世。',144,'全唐诗/poet.song.247000.json','["群仙碎翦明河水，須臾變換人間世。", "重陰漠漠不分天，萬里茫茫更無地。", "回飛慢舞忽交急，清壑汙渠受平施。", "虛光眩轉混晝夜，終日縱橫絕聲氣。", "埋深矮屋火無功，捲入空簷風挾勢。", "無同那得羽相似，怪見惟驚犬群吠。", "調和稚子割蜜脾，澀縮山翁鳴屐齒。", "禿蒼捕雀花兩眼，戲客捏獅紅十指。", "徑須醉賞臘前三，紛紛盡是明年米。"]'),
('bd0dc277-a834-4648-a40b-f0045c56d3d3','題陳所翁爲葉半隠作全龍邀同賦','艾性夫','宋','宋诗','song-poetry','','[]','鴟夷飲江共曉汲，麈尾拂屏翻墨汁。',152,'全唐诗/poet.song.247000.json','["鴟夷飲江共曉汲，麈尾拂屏翻墨汁。", "密雲黯黯扶天來，黑風冥冥吹海立。", "濤奔浪駭恣神怪，驚起蒼龍九淵蟄。", "鬚髯怒插霜戟寒，鱗甲光摇春雨濕。", "身蟠遠勢欲萬里，吻渴滄溟歸一吸。", "僧繇汗背葉公走，祇合庸奴事供給。", "所翁湖海陳元龍，小傍皇華在原隰。", "酒酣作畫特餘事，大手能旋倚天笠。", "只恐通神風雨急，抉破天門夜飛入，明日山翁倚屏泣。"]'),
('98de669e-d489-465b-993e-630a96789354','題趙大年奉議小景','艾性夫','宋','宋诗','song-poetry','','[]','江頭古樹片葉無，槎牙老龍爪角枯。',64,'全唐诗/poet.song.247000.json','["江頭古樹片葉無，槎牙老龍爪角枯。", "風含雪意天欲晚，凍棲不動鴝鵒滿。", "翩翩四翼來何遲，睥睨欲泊無空枝。", "寫生貴活意獨到，明朝嘈雜聽渠噪。"]'),
('965a184f-c4ef-47f2-99ea-1b95a88136ea','煎後山峰上人新茶','艾性夫','宋','宋诗','song-poetry','','[]','揀芽穰穰鷹爪黄，活火濈濈魚眼湯。',64,'全唐诗/poet.song.247000.json','["揀芽穰穰鷹爪黄，活火濈濈魚眼湯。", "掃花席地白日靜，穿簾透戶春風香。", "喚醒松根渴睡漢，五更清夢從渠短。", "泠泠灌頂欲通仙，稽首法雲甘露椀。"]'),
('2582617c-3f06-4493-953d-eca745de6eec','蒲蓆歌','艾性夫','宋','宋诗','song-poetry','','[]','君不見象牀金縷黄龍鬚，翠幃茸毯紅氍毹。',155,'全唐诗/poet.song.247000.json','["君不見象牀金縷黄龍鬚，翠幃茸毯紅氍毹。", "凝香燕寢環瓊姝，美物作惡常須臾。", "能令王孫泣路隅，富貴不到山中臞。", "霜空雁落寒陵膚，西溪女郎織春蒲。", "作蓆眼眼涵清腴，髪僧方丈供橫鋪。", "蒼烟翠霧不可摹，摩挲溫厚便鶴軀。", "高眠齁齁忘朝晡，遠夢颯颯生江湖。", "楮衾竹榻蒲爲徒，觀美不足安有餘。", "更生九節壽老夫，百年與爾同卷舒，清風傲兀超几蘧。"]'),
('bac7b75a-66c6-47dc-8cf1-d08b1fd3ad94','嚴氏古琴','艾性夫','宋','宋诗','song-poetry','','[]','蒼梧弓劍俱塵土，一片枯桐尚傳古。',64,'全唐诗/poet.song.247000.json','["蒼梧弓劍俱塵土，一片枯桐尚傳古。", "有絃彈入碧虛寒，彩鳳應來獸應舞。", "物真物贋不必論，立名幸有古意存。", "南風不作民正慍，我欲抱渠招帝魂。"]'),
('c2043655-a35d-48f9-88b1-c2bdde3519e4','禱雨積烟山之龍潭有應','艾性夫','宋','宋诗','song-poetry','','[]','神鑱鬼鑿深無底，誰敢然犀照秋水。',64,'全唐诗/poet.song.247000.json','["神鑱鬼鑿深無底，誰敢然犀照秋水。", "蒼生望霖龍不起，蠟丸箋心聒龍耳。", "髯張尾戰珠脫腹，仰天噓氣陽侯哭。", "銅瓶偷湫未及屋，黑雲崩山雨如竹。"]'),
('38bfbd4b-74c4-4fa8-8d70-fd380efa631e','射虎行贈張生','艾性夫','宋','宋诗','song-poetry','','[]','深村落日啼寒烏，中有十數黄於菟。',114,'全唐诗/poet.song.247000.json','["深村落日啼寒烏，中有十數黄於菟。", "飽吞猘狗未足醉，時失行客驚相呼。", "蒼髯老翁百夫勇，蹶張强弩金僕姑。", "潜機夜半發乘矢，黄髯白額殲其渠。", "寢皮食肉爭賞快，入穴取子無留餘。", "嗚呼山中猛虎今已無，人間苛虎誰驅除。", "老翁負弩先辟易，此虎咆哮角而翼。"]'),
('cddb480c-d038-43ca-8e2b-32ef5121483c','題明皇醉歸圖','艾性夫','宋','宋诗','song-poetry','','[]','金車山重牛難挽，五花嘶出長春苑。',160,'全唐诗/poet.song.247000.json','["金車山重牛難挽，五花嘶出長春苑。", "太官供頓宴驪山，三郎沉醉歸來晚。", "酩酊馬上扶者誰，秀眉照眼兩國姨。", "紅香把臂手亦軟，三馬相倚不敢馳。", "黄門擁道盡端美，錦衫繡帽春風起。", "解酲尚恐需餘尊，捧把玉巵行復止。", "最後一馬壽王妃，鸞扇夾侍雙瓊姬。", "酣酣嘿嘿意自遠，恨不醑我漁陽兒。", "圖陳無逸今安有，却作醉徒供畫手。", "昭陵百戰大山河，凉州幾甕葡萄酒。"]'),
('d738b242-d436-4d27-bb24-f2f233640d23','兒餒嗔郎罷妻寒怨藁砧唐眉山詩也戲爲箋之','艾性夫','宋','宋诗','song-poetry','','[]','父天不可嗔，夫君不宜怨。',88,'全唐诗/poet.song.247000.json','["父天不可嗔，夫君不宜怨。", "要知古聖賢，貴在素貧賤。", "父常煮字不成飯，夫常織文不成絹，衣粗布衣齕藜莧。", "去耕原上田，往種陌上桑。", "穫雲秋穗重，繰雪春絲長。", "汝溫汝飽官征忙，翁出校書爲汝償。"]'),
('85973511-23dc-45e3-ba36-28a89509803a','賦壬一姪孫破硯','艾性夫','宋','宋诗','song-poetry','','[]','山翁手持青石骨，疑是元賓瘞中物。',96,'全唐诗/poet.song.247000.json','["山翁手持青石骨，疑是元賓瘞中物。", "支牀搗練應不然，中裂何由半存沒。", "冰池既决不可隄，鏡面已破那能規。", "達人不必顧墮甑，好事大率逢轟碑。", "寒蟬飽飲供曉滴，盡了山中病磨墨。", "太和磔裂三千年，何處人間有完璧。"]'),
('ae40904e-b08b-4938-ae18-a75640a06645','與圖書工羅翁','艾性夫','宋','宋诗','song-poetry','','[]','木天荒寒風雨黑，夜氣無人驗東壁。',114,'全唐诗/poet.song.247000.json','["木天荒寒風雨黑，夜氣無人驗東壁。", "天球大玉生土花，虞歌魯頌誰能刻。", "翁持鐵筆不得用，小試印材蒸栗色。", "我今白首正逃名，運與黄楊俱受厄。", "藏鋒少竢時或至，精藝終爲人愛惜。", "固不必附名黨錮碑，亦不必寄姓麻姑石。", "江湖詩板待翁來，傳與鷄林讀書客。"]'),
('de244f1d-5af5-4157-9b32-82fc50d82878','杉樹牌晚憩','艾性夫','宋','宋诗','song-poetry','','[]','倦童呼不諾，久客坐長歎。',48,'全唐诗/poet.song.247000.json','["倦童呼不諾，久客坐長歎。", "野色歸烟暝，秋聲入雨寒。", "閲人江樹老，經火路牌殘。", "近郭魚羹飯，招呼作晚餐。"]'),
('f54574a8-0648-4b73-993f-3c93930c2379','客歸','艾性夫','宋','宋诗','song-poetry','','[]','髪僧行脚倦，歸計上心忙。',48,'全唐诗/poet.song.247000.json','["髪僧行脚倦，歸計上心忙。", "秋老蟬聲短，江空雁影長。", "乾坤無了日，霜露感殊鄉。", "遥想梅花未，還家定雪香。"]'),
('84e7da48-7f5b-4041-a1c9-28ae7289a019','過石泉寺','艾性夫','宋','宋诗','song-poetry','','[]','蘚壁作怪畫，石泉操古琴。',48,'全唐诗/poet.song.247000.json','["蘚壁作怪畫，石泉操古琴。", "藤多山木老，僧瘦道根深。", "白鵠隨人飯，青猿抱佛吟。", "經過恨不數，带雨度遥岑。"]'),
('86bb4b75-2415-4546-9c82-635bcc506943','雪盡','艾性夫','宋','宋诗','song-poetry','','[]','雪盡孤峰瘦，家貧老夢寒。',48,'全唐诗/poet.song.247000.json','["雪盡孤峰瘦，家貧老夢寒。", "春鞭雙影動，歲節五更殘。", "努力三餐飯，滋身九轉丹。", "時危從道喪，不敢棄儒冠。"]'),
('9eadc3dd-52b1-4680-a666-3a15041e11ba','吳種柳枉教輒復奉答','艾性夫','宋','宋诗','song-poetry','','[]','天地窮東野，江湖困子長。',48,'全唐诗/poet.song.247000.json','["天地窮東野，江湖困子長。", "逢人雙白眼，衒俗小紅裳。", "舊句傳楓冷，新吟带柳香。", "還能相料理，亦足慰淒凉。"]'),
('d54575a7-f7cd-4312-adac-9a16b3800c5b','平塘陶使君挽歌','艾性夫','宋','宋诗','song-poetry','','[]','今代平塘老，前身靖節翁。',48,'全唐诗/poet.song.247000.json','["今代平塘老，前身靖節翁。", "死知隨物化，貧與不官同。", "仕國棠陰在，休亭蕙帳空。", "容人方竹馬，楚些已西風。"]'),
('508c1bcf-fa38-489e-8108-88cb42c40180','飯客','艾性夫','宋','宋诗','song-poetry','','[]','菜剪堯時韭，羹羞晉代蓴。',48,'全唐诗/poet.song.247000.json','["菜剪堯時韭，羹羞晉代蓴。", "家寒多食淡，客好不嫌貧。", "一夜小窗雨，百年華髪人。", "明朝未須去，老別最傷神。"]'),
('ff598734-3f6b-4988-b454-76fe7de13f58','謝呂雲叔餉墨','艾性夫','宋','宋诗','song-poetry','','[]','蒼蒼烏玉笏，歲歲到山翁。',48,'全唐诗/poet.song.247000.json','["蒼蒼烏玉笏，歲歲到山翁。", "君眼何曾白，吾顔自覺紅。", "一生磨不死，萬事寫成空。", "回首柯山路，凄凉不復東。"]'),
('fa622df1-9ffd-4d28-9de5-c082c945de51','丁亥冬大雪十數作鄧清曠以苦寒吟見寄','艾性夫','宋','宋诗','song-poetry','','[]','十雪勢未已，一冬天積陰。',48,'全唐诗/poet.song.247000.json','["十雪勢未已，一冬天積陰。", "背風留更久，入夜落偏深。", "禾稼連冰柱，天花幻玉林。", "遥憐五峰老，尚寄苦寒吟。"]'),
('ccaa6964-640f-4bca-8158-13edfe3ccfcc','病中即事','艾性夫','宋','宋诗','song-poetry','','[]','支身惟首健，隨事與心違。',48,'全唐诗/poet.song.247000.json','["支身惟首健，隨事與心違。", "病久藥爲飯，寒深火是衣。", "矮窗看日度，遠夢傍雲飛。", "可比梅花瘦，呼童試折歸。"]'),
('e7986027-8526-4d78-9f0e-bbb4d5e8fa77','正覺僧榻','艾性夫','宋','宋诗','song-poetry','','[]','贊公分半榻，卧近竹西樓。',48,'全唐诗/poet.song.247000.json','["贊公分半榻，卧近竹西樓。", "四壁寒蛩夜，一山黄葉秋。", "夢隨三鼓動，月尚半窗留。", "零亂芭蕉影，禪衣爛不收。"]'),
('d3b4f5a3-e834-4899-857a-f3d5b1d57cf2','哭林止庵','艾性夫','宋','宋诗','song-poetry','','[]','止庵諸老行，今日九原人。',48,'全唐诗/poet.song.247000.json','["止庵諸老行，今日九原人。", "頭爲談經白，家因好客貧。", "欲銘貞曜墓，來哭廣成真。", "俯仰南湖月，瑶琴鎖碧塵。"]'),
('6a76f9b7-bc93-4128-b5ea-41a6a3767101','日永','艾性夫','宋','宋诗','song-poetry','','[]','日永駒難過，庭空雀亦無。',48,'全唐诗/poet.song.247000.json','["日永駒難過，庭空雀亦無。", "花招蜂出早，草礙蟻行迂。", "蕉葉露臺掌，水光天影圖。", "下簾便道靜，烟篆起茶爐。"]'),
('88aa2ac8-bddc-4337-b910-b8faad678a71','癸巳小至','艾性夫','宋','宋诗','song-poetry','','[]','舌在貧何害，脾清瘦不妨。',48,'全唐诗/poet.song.247000.json','["舌在貧何害，脾清瘦不妨。", "天心半夜子，道脈一分陽。", "山色春秋老，梅花天地香。", "半爐煨芋火，意味頗悠長。"]'),
('3931ca1f-53ca-4268-8229-daf413712a6e','盡日','艾性夫','宋','宋诗','song-poetry','','[]','盡日坐谷口，看雲生嶺頭。',48,'全唐诗/poet.song.247000.json','["盡日坐谷口，看雲生嶺頭。", "蟬聲偏占晚，菊色欲專秋。", "江碧水心淡，葉紅溪樹愁。", "乾坤萬萬古，流轉一虛舟。"]'),
('e1a8b39b-2720-4d09-abb6-785f2eb5fc34','次韻秋心','艾性夫','宋','宋诗','song-poetry','','[]','短髪白已盡，寒花黄到今。',48,'全唐诗/poet.song.247000.json','["短髪白已盡，寒花黄到今。", "秋清山見骨，年老樹留心。", "獨鶴離騷怨，虛泉大雅音。", "冥鴻不知處，引睇暮雲深。"]'),
('d29d4e18-7f5d-41ae-88c3-09a2583855c1','秋陰','艾性夫','宋','宋诗','song-poetry','','[]','老蟬吟漸懶，愁蚓思無窮。',48,'全唐诗/poet.song.247000.json','["老蟬吟漸懶，愁蚓思無窮。", "數點菊花雨，一溪茅屋風。", "苔衣秋井綠，楓纈曉山紅。", "急索鶉裘補，寒先及老翁。"]'),
('8fce6777-d164-49d2-8f1d-05cb559e2d5c','番城晚眺','艾性夫','宋','宋诗','song-poetry','','[]','獨眺秋愈遠，孤城日漸曛。',48,'全唐诗/poet.song.247000.json','["獨眺秋愈遠，孤城日漸曛。", "地平浮楚澤，天闊見吳雲。", "風靜漁歌合，波摇雁影分。", "未應陵谷變，不得問番君。"]'),
('3b13c427-09db-4704-b055-c6d6524298c3','道中  其一','艾性夫','宋','宋诗','song-poetry','','[]','共僧分晚供，呼渡立橋東。',48,'全唐诗/poet.song.247000.json','["共僧分晚供，呼渡立橋東。", "雁背西風緊，漁梁落照紅。", "雲添疏樹影，葉補敗船篷。", "舊日津亭酒，黄壚蔓草中。"]'),
('0942287b-0555-49d2-b294-7bc1975e8b79','道中  其二','艾性夫','宋','宋诗','song-poetry','','[]','覓宿村溪遠，逢人面目生。',48,'全唐诗/poet.song.247000.json','["覓宿村溪遠，逢人面目生。", "習移多佩犢，氣怒鬬呼鷹。", "天闊秋陰重，風高夜柝驚。", "遲明懷宿飽，股慄履春冰。"]'),
('f2c46bd7-51b3-41a1-97be-910b230535df','有感','艾性夫','宋','宋诗','song-poetry','','[]','江漢亡維楫，山林困蒺藜。',48,'全唐诗/poet.song.247000.json','["江漢亡維楫，山林困蒺藜。", "頭顱春雪重，心緒晚雲低。", "掛樹蛇留蛻，踰垣虎印蹄。", "遥憐伯勞燕，辟地各東西。"]'),
('cae68525-afa4-4b62-a082-1c26ff8769fd','謝吳子與惠詩','艾性夫','宋','宋诗','song-poetry','','[]','解后西風野菊黄，別來冉冉歷三霜。',64,'全唐诗/poet.song.247000.json','["解后西風野菊黄，別來冉冉歷三霜。", "未償詩債如山重，曾結交盟引夢長。", "老病終年親藥裹，清談何日倒書囊。", "聞君讀罷多娛樂，萱草春深棣萼芳。"]'),
('4dff467f-da1f-4f1b-a07f-4d5b4d1800dc','冬夜抄詩作','艾性夫','宋','宋诗','song-poetry','','[]','筆債窮年老髪僧，硯寒還復夜敲冰。',64,'全唐诗/poet.song.247000.json','["筆債窮年老髪僧，硯寒還復夜敲冰。", "西堂夢後無靈運，夔府歸來有少陵。", "諸老文章凡幾變，千年風雅欠中興。", "矮窗燭暗成惆悵，忽見梅花月一稜。"]'),
('92a20a6b-a513-44ce-93bd-a9d61f2c2a59','送客至靈谷','艾性夫','宋','宋诗','song-poetry','','[]','仙林路細出山腰，靈谷峰高入紫霄。',64,'全唐诗/poet.song.247000.json','["仙林路細出山腰，靈谷峰高入紫霄。", "立石借爲題字壁，倒松因作度溪橋。", "雨花濕地人歸晚，烟草迷川馬去遥。", "記得玄都種桃處，黯然分袂各魂銷。"]'),
('9f32d3b9-31e1-4fd3-8289-a5a8956ee8ad','重贈星翁陳跛子','艾性夫','宋','宋诗','song-poetry','','[]','拄拐蹣跚鬢雪明，向來小范亦分羹。',64,'全唐诗/poet.song.247000.json','["拄拐蹣跚鬢雪明，向來小范亦分羹。", "十年不見疑先死，一旦相逢似再生。", "儘亂亦收詩卷上，長貧猶挾命書行。", "試言何物妖星照，是處青山白骨橫。"]'),
('e33142bc-acd4-4b59-9ecc-df345c00bb52','舊廬毀於亂十年矣吾老他寓每不能再葺戊子冬良異聚芸人之資自構小堂因以勉之','艾性夫','宋','宋诗','song-poetry','','[]','舊址相傳五世昌，寒蕪忍墮十年荒。',64,'全唐诗/poet.song.247000.json','["舊址相傳五世昌，寒蕪忍墮十年荒。", "老吾衰落空懷土，幸汝辛勤自肯堂。", "袖裏莫忘無恤簡，牆頭猶有孔明桑。", "地靈舊日鍾文氣，且要扶持此脈長。"]'),
('54a60d1a-ab55-4da4-b640-ddb136a4eb73','桂花','艾性夫','宋','宋诗','song-poetry','','[]','秋樹婆娑風露凉，老蟾落子種虛堂。',64,'全唐诗/poet.song.247000.json','["秋樹婆娑風露凉，老蟾落子種虛堂。", "胚渾天地中央色，漏泄神仙上界香。", "貧裏忽驚添粟滿，老來不動買花狂。", "带愁莫上黄樓去，歸隠淮山興味長。"]'),
('b6cda197-f5b4-4763-9640-5e970e4264fa','酬鄰僧惠古杭蘆管兔毫','艾性夫','宋','宋诗','song-poetry','','[]','黄蘆笠澤剪秋雨，褐兔中山俘飽霜。',64,'全唐诗/poet.song.247000.json','["黄蘆笠澤剪秋雨，褐兔中山俘飽霜。", "千里能隨雲衲遠，數君肯顧草廬荒。", "無情書傳方高閣，何處塵埃有畫牆。", "留與素翁修菊譜，寒花吹入墨雲香。"]'),
('2d20b4f7-ec04-4d5d-aedc-c2c3a75bfaed','義馬冢','艾性夫','宋','宋诗','song-poetry','','[]','訴得冤伸意始休，敝帷埋骨幾經秋。',64,'全唐诗/poet.song.247000.json','["訴得冤伸意始休，敝帷埋骨幾經秋。", "獸心猶辦死報主，人面却甘生事仇。", "作傳自應班豫讓，論功何止及留侯。", "世間義字無人識，寫在荒丘馬冢頭。"]'),
('ad61d762-8fd5-47f4-8b1c-e9c7e1165cb9','題艾溪','艾性夫','宋','宋诗','song-poetry','','[]','睦城西下柳陰陰，以艾名溪古到今。',64,'全唐诗/poet.song.247000.json','["睦城西下柳陰陰，以艾名溪古到今。", "鼻祖桑弧蓬矢地，耳孫喬木故家心。", "應無別姓爭墩住，曾有高人對客吟。", "欲向原頭拜宗老，西風落日暮雲深。"]'),
('2838d369-6d4a-4ac0-83f7-44e4b71f8bb7','與雪舟楊子圓十五年不相聞一日辱和猥句更號皓隠因復奉寄','艾性夫','宋','宋诗','song-poetry','','[]','羞把長裾事走趨，已將身世混樵漁。',64,'全唐诗/poet.song.247000.json','["羞把長裾事走趨，已將身世混樵漁。", "畏途咫尺如千里，老友多年欠一書。", "最喜山人題皓隠，莫教帝畫到幽居。", "欲尋載雪舟邊路，來爲槃翁賦遂初。"]'),
('54ecca31-9740-491b-9448-8ccf9925d108','寄清曠鄧隠夫','艾性夫','宋','宋诗','song-poetry','','[]','去年菊裏辱經過，秋思蕭蕭又草坡。',64,'全唐诗/poet.song.247000.json','["去年菊裏辱經過，秋思蕭蕭又草坡。", "兵火東南關氣數，交游湖海隔風波。", "書緣辟亂經年少，詩想憂時近日多。", "倘有鱗鴻幸相寄，青燈無奈憶君何。"]'),
('8508b9f2-1e15-45f8-abfb-89f3147ee179','次大五姪問移家韻','艾性夫','宋','宋诗','song-poetry','','[]','投老移家僻塢來，滿林秋露洗黄埃。',64,'全唐诗/poet.song.247000.json','["投老移家僻塢來，滿林秋露洗黄埃。", "飯纔種麥須堪飽，衣旋培桑未可裁。", "萬古乾坤如傳舍，一生風雪歎江梅。", "相看喜有青田鶴，肯與詩筒日往回。"]'),
('19b26e12-9fa0-415f-a8ae-a83942a2e14f','移家寄諸丈','艾性夫','宋','宋诗','song-poetry','','[]','十弓荒圃百弓山，縛草編茅屋兩間。',64,'全唐诗/poet.song.247000.json','["十弓荒圃百弓山，縛草編茅屋兩間。", "雞甕不知天廣大，鶴巢已覺地寬閒。", "勝心擾擾雙蝸角，畏路巖巖九虎關。", "退一步行差得計，野雲深處即商顔。"]'),
('4a99fd44-33c9-448e-b45e-a2650838ac51','再答諸丈見和二首  其一','艾性夫','宋','宋诗','song-poetry','','[]','神龜爲我作天山，合住清泉白石間。',64,'全唐诗/poet.song.247000.json','["神龜爲我作天山，合住清泉白石間。", "歲月短梭人易老，詩書高閣士方閑。", "秋鴻社燕炎凉勢，滄海桑田夢覺關。", "近屋虬松三百尺，時時相對各蒼顔。"]'),
('5825244b-e1ec-4ca7-9424-75fdff13c44b','再答諸丈見和二首  其二','艾性夫','宋','宋诗','song-poetry','','[]','肯爲劉安賦小山，幾時雞犬過雲間。',64,'全唐诗/poet.song.247000.json','["肯爲劉安賦小山，幾時雞犬過雲間。", "命窮無用三千字，蹄蹶難供十二閑。", "薄酒程頭多隔縣，故人蹤跡半陽關。", "何當共嚼西巖雪，嗅取梅花一破顔。"]'),
('e775bcc4-dcfe-49b9-b40a-4de108b036e6','遊古汴趙氏溪園','艾性夫','宋','宋诗','song-poetry','','[]','不起樓臺作熱官，小園回合抱溪灣。',64,'全唐诗/poet.song.247000.json','["不起樓臺作熱官，小園回合抱溪灣。", "露漙花靨春紅濕，烟護松髯晚翠寒。", "已向掌中旋宇宙，正須胸次著雲山。", "可能再爲蒼生出，鶴怨猿啼攪夜闌。"]'),
('1c8e4b6c-2819-48e7-b317-fdcb9069d47b','次吳壽翁溪園韻寄題','艾性夫','宋','宋诗','song-poetry','','[]','營營誰肯卧滄洲，喜有高人此枕流。',64,'全唐诗/poet.song.247000.json','["營營誰肯卧滄洲，喜有高人此枕流。", "得水最多知地勝，種花無數欲春留。", "圖傳笠澤三分畫，夢繞黄淤十里秋。", "料得江楓吟未了，載詩應汗謫仙牛。"]'),
('90e06976-750a-443a-a6cd-736de41f956f','拜五世祖妣墓','艾性夫','宋','宋诗','song-poetry','','[]','敬脈人人似飲泉，掃松羅拜喜爭先。',64,'全唐诗/poet.song.247000.json','["敬脈人人似飲泉，掃松羅拜喜爭先。", "頌琴不朽終流慶，石仲相看莫計年。", "滄海桑田誰料此，秋風宰樹幸依然。", "五陵莫說驪山下，愁絕求羊一穗烟。"]'),
('8f109bf3-9e7f-4286-b446-5ec027177c54','辟亂逢故人','艾性夫','宋','宋诗','song-poetry','','[]','亂裏相逢各自忙，少依松影話凄凉。',64,'全唐诗/poet.song.247000.json','["亂裏相逢各自忙，少依松影話凄凉。", "古來尚有種桃處，今去當傳辟穀方。", "馬蹴黄塵遮日暗，鬼吹青燐隔林光。", "海田未必非天數，空對西風老淚滂。"]'),
('e3b9aefa-9d81-4278-93b3-d7e47bb51f21','題友人歸隠圖','艾性夫','宋','宋诗','song-poetry','','[]','買山長說欲棲身，畫得圖成隠始真。',64,'全唐诗/poet.song.247000.json','["買山長說欲棲身，畫得圖成隠始真。", "半枕虛堂生草夢，一溪流水種桃人。", "但知樵客當辭漢，莫與漁郎說避秦。", "早晚相從弄明月，細聽喚鐵響蒼筠。"]'),
('dda4f0e9-8c60-4573-9e9f-929294f76ec2','意行','艾性夫','宋','宋诗','song-poetry','','[]','意行行到野人家，門带清溪石徑斜。',64,'全唐诗/poet.song.247000.json','["意行行到野人家，門带清溪石徑斜。", "落日輕烟山可畫，短籬頹塹菊能花。", "歸遲悞客頻敲竹，坐久勞人再煮茶。", "那得寬閒無點事，日搔短髪問桑麻。"]'),
('56c59db3-f04a-4775-b2db-07a5f1d55589','庚寅二月朔積雪初霽過和山見雪深堂瑞香盛開回過烟雨村則庭中花更早亦未歇也得數語錄似二花主人','艾性夫','宋','宋诗','song-poetry','','[]','烟雨庭前錦繖張，一般穠郁雪深堂。',64,'全唐诗/poet.song.247000.json','["烟雨庭前錦繖張，一般穠郁雪深堂。", "偶扶晴日孤筇出，連挹春風兩屋香。", "供佛省燒蒼柏子，薰書不藉綠芸囊。", "冰霜儘厄芳心在，自與梅花是雁行。"]'),
('8e97e07f-b2e0-4b23-aabe-97ffccc15715','廢貢院爲米廩過之值盤厫','艾性夫','宋','宋诗','song-poetry','','[]','擔夫勇似踏槐忙，衛卒嚴於夾棘防。',64,'全唐诗/poet.song.247000.json','["擔夫勇似踏槐忙，衛卒嚴於夾棘防。", "千古文章成畫餠，萬人場屋忽敖倉。", "籍存尚或思班爵，禮廢寧容併去羊。", "立盡斜陽還獨笑，功名自古夢黄粱。"]'),
('fd560e87-7eab-4977-9594-7a2c5e52c331','示子良異','艾性夫','宋','宋诗','song-poetry','','[]','霜雪林頭又綠稠，乾坤生意幾時休。',64,'全唐诗/poet.song.247000.json','["霜雪林頭又綠稠，乾坤生意幾時休。", "人情葵扇炎凉態，世路瞿塘上下舟。", "鱉跛未輸蚿百足，茅封不敵橘千頭。", "細看不似吾儒業，一片書田或有秋。"]'),
('2f7837a9-e3fc-401f-839a-3d89721d8e49','贈數學姜兄','艾性夫','宋','宋诗','song-poetry','','[]','向來塗抹趁春妍，老去棲遲歎雪顛。',64,'全唐诗/poet.song.247000.json','["向來塗抹趁春妍，老去棲遲歎雪顛。", "一倍法靈君說數，三生緣定我隨天。", "正須花外羈奔馬，莫向橋南聽杜鵑。", "見說侯封容易覓，紫茸靴袴錦鞍韉。"]'),
('13467fcf-89a6-40c7-b3bf-5f1f23c451c0','贈談數陳改之','艾性夫','宋','宋诗','song-poetry','','[]','投老江南黄葉村，菊花時節雨昏昏。',64,'全唐诗/poet.song.247000.json','["投老江南黄葉村，菊花時節雨昏昏。", "矮窗孤夢正欹枕，拄杖一聲誰打門。", "三字頭銜康節數，一編心易華山孫。", "吾年漸似璜溪老，尚把靈光許獨存。"]'),
('107bc220-d356-4c66-a7c4-368b6fe95281','謝惠楮衾','艾性夫','宋','宋诗','song-poetry','','[]','厚於布被擁公孫，清似荷衣伴屈原。',64,'全唐诗/poet.song.247000.json','["厚於布被擁公孫，清似荷衣伴屈原。", "捲送春雲香入夢，剪成秋水淡無痕。", "五更葭琯噓寒谷，一榻梅花近雪村。", "直作黄紬紋錦看，日高睡穩不開門。"]'),
('c64323e3-d19c-4ada-beba-5f52e731d51f','觀潮','艾性夫','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','按節波神逆水來，魚龍掀舞鬬崔嵬。',64,'全唐诗/poet.song.247000.json','["按節波神逆水來，魚龍掀舞鬬崔嵬。", "浪高峰頂青天雪，風助江聲白晝雷。", "勢欲上時掀海立，怒無泄處觸山回。", "世間亡國知多少，誰似靈胥恨未灰。"]'),
('a85fffe1-413e-42cd-9674-8d21504cad91','悼亡  其一','艾性夫','宋','宋诗','song-poetry','','[]','秋瑟凄凉忽斷絃，自礱山石誌新阡。',64,'全唐诗/poet.song.247000.json','["秋瑟凄凉忽斷絃，自礱山石誌新阡。", "稍閒即病身無福，竟死難醫命有天。", "會績忍看燒燭淚，遺簪聊抵買花錢。", "最慚誤看劉蕡策，辜汝相依四十年。"]'),
('24d09104-1397-4cf4-a3c6-94219b67fac6','悼亡  其二','艾性夫','宋','宋诗','song-poetry','','[]','死生最怕墮危機，亂世全身正自稀。',64,'全唐诗/poet.song.247000.json','["死生最怕墮危機，亂世全身正自稀。", "滿地干戈殊不定，蓋棺丘隴未爲非。", "鹿門不共龐公隠，鳳褐誰縫杜老衣。", "愁絕梧楸烟雨地，藁砧百歲擬同歸。"]'),
('30e8252d-4aaa-413b-952e-ce31594e9cd8','人名詩戲效王半山  其一','艾性夫','宋','宋诗','song-poetry','','[]','重耳盈盈岸柳黄，九齡冉冉澗松蒼。',64,'全唐诗/poet.song.247000.json','["重耳盈盈岸柳黄，九齡冉冉澗松蒼。", "梅開小白添新雪，鴉引童烏弄夕陽。", "樵唱轉低春谷永，雁聲不斷暮雲長。", "奔泉渾作山濤響，濺入懸巖百藥香。"]'),
('d17165d5-7507-4b03-aa5a-db4d2d8cad5f','人名詩戲效王半山  其二','艾性夫','宋','宋诗','song-poetry','','[]','偶來安石坐林塘，因得棲筠受晚凉。',64,'全唐诗/poet.song.247000.json','["偶來安石坐林塘，因得棲筠受晚凉。", "歸鳥衝烟方陸續，寒花經雨尚黄香。", "雲如仙客蹤無定，風作山賓語自長。", "師古不成書謾讀，樂天深結退居房。"]'),
('7fbba946-da91-40d5-ab46-77d0d85c3d27','湖陰故人家','艾性夫','宋','宋诗','song-poetry','','[]','水痕落盡見晴沙，步入湖陰處士家。',64,'全唐诗/poet.song.247000.json','["水痕落盡見晴沙，步入湖陰處士家。", "梅一兩花春尚小，雁三五字日初斜。", "百年耆舊多思洛，五夜精魂半夢華。", "珍重瑶琴莫輕拂，西風江上沸蘆笳。"]'),
('76ce0471-a5ae-4781-a61e-083ee8267f91','撚髭','艾性夫','宋','宋诗','song-poetry','','[]','細撚寒髭縷縷霜，未須惆悵惜流光。',64,'全唐诗/poet.song.247000.json','["細撚寒髭縷縷霜，未須惆悵惜流光。", "近山歸鷺分明白，過雨斜陽淺淡黄。", "春入桑榆花影瘦，門無車馬草心長。", "暮年一卷參同契，覓得安神不老方。"]'),
('4ecd02fd-eacb-4bbc-9f9d-51cc7062d249','賦太和寺同根紅白梅','艾性夫','宋','宋诗','song-poetry','','[]','雪影蕭蕭带晚霞，胭脂灼灼傍鉛華。',64,'全唐诗/poet.song.247000.json','["雪影蕭蕭带晚霞，胭脂灼灼傍鉛華。", "孤山夜合連枝木，一樹春分二色花。", "牛繼馬來幾換骨，鶴乘鸞去忽通家。", "向來逋老題詩處，曾有紅裙拂碧紗。"]'),
('e4beee50-39bd-4255-8d34-3b3483711c5f','滕王閣','艾性夫','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','木老江空雁陣秋，闌干倚盡思悠悠。',64,'全唐诗/poet.song.247000.json','["木老江空雁陣秋，闌干倚盡思悠悠。", "舞衫歌扇落春夢，山雨浦雲牽暮愁。", "半壁夕陽千古在，幾朝王氣一時休。", "獻陵無樹供寒雀，信是勞生枉白頭。"]'),
('85cab925-25ff-488c-9a22-43aec9792256','贈繩伎','艾性夫','宋','宋诗','song-poetry','','[]','絕藝當場萬目傾，兩竿朽索半空橫。',64,'全唐诗/poet.song.247000.json','["絕藝當場萬目傾，兩竿朽索半空橫。", "反提雙女摩肩過，仰射孤鴻信脚行。", "膽似子龍身裏滿，體如飛燕掌中輕。", "弄潮已歎吳兒險，更有人從死處生。"]'),
('0e6b7ab3-ceba-4fb2-8af9-226e6bb61e3e','日食','艾性夫','宋','宋诗','song-poetry','','[]','誰撤天門虎豹扃，群妖食日上青冥。',64,'全唐诗/poet.song.247000.json','["誰撤天門虎豹扃，群妖食日上青冥。", "一眉不及黄昏月，萬目驚看白晝星。", "絕響無人槌敗鼓，洗光何地激滄溟。", "仰天凝注需陽復，寂歷西風老淚零。"]'),
('9e1689b6-8a1e-4b93-8e15-87e8dd91fb9d','穆陵大禮圖','艾性夫','宋','宋诗','song-poetry','','[]','丹青百丈鵝溪絹，縹軸南郊大禮圖。',64,'全唐诗/poet.song.247000.json','["丹青百丈鵝溪絹，縹軸南郊大禮圖。", "官隸威儀猶是漢，山河風景已非吳。", "秋陰汾水年年雁，月黑連昌夜夜狐。", "輦路莫驚荒草暗，鮧膏燈滅出金鳬。"]'),
('d6f20eba-fc1a-41c2-9b27-b29a3ffb8265','史氏鐵笛','艾性夫','宋','宋诗','song-poetry','','[]','蘄川老竹未爲奇，橫截凉州黑玉枝。',64,'全唐诗/poet.song.247000.json','["蘄川老竹未爲奇，橫截凉州黑玉枝。", "陽燧無烟山鬼鑄，蓬壺乘月浪仙吹。", "一聲響裂千崖石，九曲亭標二老詩。", "俗耳從前聽不得，壁塵蛛網故多時。"]'),
('acb3e86c-ade6-4a17-9bb2-3eb305463765','苦雨喜晴早作散步','艾性夫','宋','宋诗','song-poetry','','[]','寂歷山房久杜門，清晨踏碎碧苔紋。',64,'全唐诗/poet.song.247000.json','["寂歷山房久杜門，清晨踏碎碧苔紋。", "池經宿雨添三尺，花怯春寒瘦一分。", "滿地月凉翻竹露，隔溪風細度松雲。", "近來生計隨緣足，半畝荒畦手自耘。"]'),
('dcdc2420-a463-49ce-ba28-2d64f52c5d59','歸大五姪天覺硯','艾性夫','宋','宋诗','song-poetry','','[]','脈暖猶涵老蘚斑，眼花仍带淚痕潸。',64,'全唐诗/poet.song.247000.json','["脈暖猶涵老蘚斑，眼花仍带淚痕潸。", "厄於劫火元無恙，意在斯文豈苟完。", "一片墨光留手澤，渾家黄色上眉間。", "只消半滴冰蜍水，漲起滿村烟雨寒。"]'),
('51a5eaa9-3a22-4d17-851e-5a266dda7900','留城','艾性夫','宋','宋诗','song-poetry','','[]','夜半遼東白鶴歸，舊來巢處立多時。',64,'全唐诗/poet.song.247000.json','["夜半遼東白鶴歸，舊來巢處立多時。", "門關落日千家靜，旗颭秋風萬馬嘶。", "文堰石臺空有讖，畫堂翠幕更無詩。", "悠悠往事俱塵土，只有寒流是古溪。"]'),
('e285f6a7-6cd9-410f-ac9a-f8f330965697','題洪崖仙壇','艾性夫','宋','宋诗','song-poetry','','[]','樹精不死卧松關，呵護仙翁舊禁壇。',64,'全唐诗/poet.song.247000.json','["樹精不死卧松關，呵護仙翁舊禁壇。", "天闊難尋騎去鶴，井香疑有煉成丹。", "山如辟穀秋逾瘦，屋尚凌虛夏亦寒。", "行遍蒼崖無石髓，空和凉月倚闌干。"]'),
('41497970-0573-49c2-9920-d99eb1a1cd83','寒食後','艾性夫','宋','宋诗','song-poetry','','[]','寒具油乾火已新，流觴水暖酒初醺。',64,'全唐诗/poet.song.247000.json','["寒具油乾火已新，流觴水暖酒初醺。", "薔薇半樹花孤注，杜宇一聲春二分。", "薄晚草心先浥露，久晴山意欲生雲。", "老來尚費閒精力，自種窗前辟蠹芸。"]'),
('cb16ed03-2a78-4808-80d7-e93f596dfa77','簡敬軒何行叟覓墨','艾性夫','宋','宋诗','song-poetry','','[]','兵塵漠漠暗窮山，零落難尋墮水丸。',64,'全唐诗/poet.song.247000.json','["兵塵漠漠暗窮山，零落難尋墮水丸。", "見說陳玄老居士，獨留何遜舊詩壇。", "快刀肯截烏龍角，破硯猶存紫馬肝。", "一笑磨人磨未了，曉窗搔首雪霜寒。"]'),
('55fa0e84-7bd1-4ed7-a50c-097ad118cd53','老竹','艾性夫','宋','宋诗','song-poetry','','[]','蒼黄瘦硬立頹垣，疑是栽時第一根。',64,'全唐诗/poet.song.247000.json','["蒼黄瘦硬立頹垣，疑是栽時第一根。", "早歲孤君惟二子，暮年千畝盡諸孫。", "雨鞭老迸蒼龍骨，霜節寒封古蘚痕。", "消得培滋號尊者，把詩題作野人軒。"]'),
('293fe9ba-125c-4c77-973f-e4e7b74fc7b7','題賤容','艾性夫','宋','宋诗','song-poetry','','[]','骨多肉少與梅同，老向江南風雪中。',64,'全唐诗/poet.song.247000.json','["骨多肉少與梅同，老向江南風雪中。", "萬事羞稱司馬好，一生不送退之窮。", "偶貪識字頭先白，稍欲工竽面即紅。", "說與丹青莫饒筆，肩山只合付何充。"]'),
('3e3c491a-ff0d-43f6-afcc-f4de8f298d2d','除夕感興','艾性夫','宋','宋诗','song-poetry','','[]','黔烏縞兔鬬飛梭，春樹流年憶踏歌。',64,'全唐诗/poet.song.247000.json','["黔烏縞兔鬬飛梭，春樹流年憶踏歌。", "掃白了無燒藥法，守玄不及力田科。", "人於淡處交情耐，梅到枯時生意多。", "寂歷風簾捲山雪，醉眠不問夜如何。"]'),
('0b97a15d-541c-49b6-8d3b-ba6be6302876','枕上','艾性夫','宋','宋诗','song-poetry','','[]','畫蘭重補紙牀屏，支石橫眠道氣清。',64,'全唐诗/poet.song.247000.json','["畫蘭重補紙牀屏，支石橫眠道氣清。", "杜宇不啼春一半，落花如夢雨三更。", "老心暗覓餘年健，萬感偏從靜夜生。", "最憶寶蓮山下月，照人扶醉聽吹笙。"]'),
('b6c0e6f8-c890-4669-98ac-d248a5b2be4b','題古洪周君會梅閣','艾性夫','宋','宋诗','song-poetry','','[]','此花不受俗人知，爲汝移家亦絕奇。',64,'全唐诗/poet.song.247000.json','["此花不受俗人知，爲汝移家亦絕奇。", "至冷淡中參古意，極高明處見南枝。", "棟簾相望滕王屋，風月重添水部詩。", "夢入梨雲香不斷，有人携笛倚闌吹。"]'),
('e2a8339f-398d-459d-97b0-32975950f002','老梅','艾性夫','宋','宋诗','song-poetry','','[]','摇落荒村野水涯，貌枯神澤骨槎牙。',64,'全唐诗/poet.song.247000.json','["摇落荒村野水涯，貌枯神澤骨槎牙。", "一生知歷幾多雪，絕好只消三兩花。", "萬木尊爲諸老行，孤根淡似道人家。", "兒時見汝今頭白，正擬相看度歲華。"]'),
('864999b5-06d1-479a-b12f-b799e311c8d2','哭菊存蕙山二兄','艾性夫','宋','宋诗','song-poetry','','[]','黄臺瓜蔓已淒凉，五雁飄零不著行。',64,'全唐诗/poet.song.247000.json','["黄臺瓜蔓已淒凉，五雁飄零不著行。", "一脈僅餘三老在，半年又哭兩兄亡。", "菊園霜熟秋香寂，蕙帳雲寒春夢長。", "愁絕吟魂招不得，西樓風雨憶連牀。"]'),
('8ac7d7c8-7944-473f-8470-94210603ac8e','哭環州先生  其一','艾性夫','宋','宋诗','song-poetry','','[]','閒却秋洲野釣磯，誰知遠出是危機。',64,'全唐诗/poet.song.247000.json','["閒却秋洲野釣磯，誰知遠出是危機。", "一篙贛水虛舟急，千里詩魂半夜歸。", "前月僕來書尚健，一生志與命相違。", "親庭已老兒方幼，最爲先生淚滿衣。"]'),
('631e2eb7-e5a8-430e-ba3b-09d67fcb5f6c','哭環州先生  其二','艾性夫','宋','宋诗','song-poetry','','[]','曾隨計吏上青霄，折翅歸來困一瓢。',64,'全唐诗/poet.song.247000.json','["曾隨計吏上青霄，折翅歸來困一瓢。", "湖海十年烏繞樹，功名兩字鹿眠蕉。", "山圖不及生前買，詩板姑留死後雕。", "地下修文應未惡，寒蛩虛館雨蕭蕭。"]'),
('79305d2c-a918-4738-bec0-b9dc0efda21f','檢歷即事','艾性夫','宋','宋诗','song-poetry','','[]','古來繫日欠長繩，節物相催老自驚。',64,'全唐诗/poet.song.247000.json','["古來繫日欠長繩，節物相催老自驚。", "歲裏春爲花早計，蟄前雷是雪先聲。", "移家燕子商量熟，開國蜂王去就輕。", "最憶長安三月事，有誰重賦麗人行。"]'),
('37703ea8-4a2e-42d0-99cb-1a5f7f091ee8','七夕對雨','艾性夫','宋','宋诗','song-poetry','','[]','門無轍跡草偏青，屋带秋山意轉清。',64,'全唐诗/poet.song.247000.json','["門無轍跡草偏青，屋带秋山意轉清。", "打夢易驚棋雹響，載愁不去酒船輕。", "幸無簾幕妨雲影，尚欠芭蕉贈雨聲。", "欲送星鸞過橋去，夜深河漢未分明。"]'),
('0e2fb6f6-6654-4cc9-b390-4c96b22dbf5a','重宿芳草渡','艾性夫','宋','宋诗','song-poetry','','[]','曾卧江樓聽雨聲，蕭疏又似送歸程。',64,'全唐诗/poet.song.247000.json','["曾卧江樓聽雨聲，蕭疏又似送歸程。", "正如老馬倦行路，忽有鵓姑啼晚晴。", "繞屋種花春爛漫，隔窗無樹月分明。", "蒼頭不管人眠熟，連報嚴城打五更。"]'),
('dc310921-f3a2-4425-add1-dca0e569d9bf','宿洪巖寺','艾性夫','宋','宋诗','song-poetry','','[]','形枯面冷住山人，彷彿錢塘老惠勤。',64,'全唐诗/poet.song.247000.json','["形枯面冷住山人，彷彿錢塘老惠勤。", "寺窶不充黄粟飯，佛寒添繡碧苔紋。", "秋聲茅屋三間雨，野色松巖幾樹雲。", "嚼菜薰香清語久，一燈明滅夜將分。"]'),
('d18d8f2a-8eae-487c-ae86-23297143bea5','看鏡','艾性夫','宋','宋诗','song-poetry','','[]','自摩寒鏡看頭顱，短髪蕭蕭不受梳。',64,'全唐诗/poet.song.247000.json','["自摩寒鏡看頭顱，短髪蕭蕭不受梳。", "天地風霜吾輩老，江湖烟雨故人疏。", "道窮分命真如紙，世亂功名不要書。", "縱有黄金難鑄錯，一編殘易伴犁鋤。"]'),
('a41959ae-a2b7-43b6-84b6-1e08906b3674','中齒忽折','艾性夫','宋','宋诗','song-poetry','','[]','老醜移形轉可吁，凋零已到骨之餘。',64,'全唐诗/poet.song.247000.json','["老醜移形轉可吁，凋零已到骨之餘。", "似因潄石磨成磷，幸免投梭折得疏。", "根笋尚如兒齔短，醫師欲實火田虛。", "喜無乾胏勞吾决，含咀猶能味古書。"]'),
('dac7255a-983c-400a-82f7-cabdb3913230','除日立春','艾性夫','宋','宋诗','song-poetry','','[]','歲如舊政方書滿，春與故人同惠來。',64,'全唐诗/poet.song.247000.json','["歲如舊政方書滿，春與故人同惠來。", "白髪最愁新歷換，清談且博笑顔開。", "屠蘇卯酒紅生暈，細菜辛盤翠作堆。", "但覓年年各强健，不妨日日小徘徊。"]'),
('5dc4ffc6-9e10-4145-8ceb-e8c4f9baa931','竹杖','艾性夫','宋','宋诗','song-poetry','','[]','一枝九節稱身長，扶得衰翁氣力强。',64,'全唐诗/poet.song.247000.json','["一枝九節稱身長，扶得衰翁氣力强。", "色點湘妃紅淚雨，骨凝王屋紫藤霜。", "結交最與芒鞋密，寄友應含蓽撥香。", "獨有探梅時節苦，相隨江路雪茫茫。"]'),
('4f0a4346-8df7-4c17-875b-67df306d954e','詠眠窩','艾性夫','宋','宋诗','song-poetry','','[]','獨榻孤扉木几雙，小窩可受北風降。',64,'全唐诗/poet.song.247000.json','["獨榻孤扉木几雙，小窩可受北風降。", "带霜楓葉寒供火，隨月梅梢瘦入窗。", "夢熟不知衾似鐵，睡醒何用酒盈缸。", "近山最有松聲好，卧聽空潮上浙江。"]'),
('b94f3a5f-59c2-41d9-893a-b0b8016e8cea','哭北谷羅先生','艾性夫','宋','宋诗','song-poetry','','[]','死到先生世道衰，忍彈雙淚看銘碑。',64,'全唐诗/poet.song.247000.json','["死到先生世道衰，忍彈雙淚看銘碑。", "動隨天去心無愧，視得官輕事敢爲。", "他日史書廉太守，四方人哭老宗師。", "不知精爽歸何處，定在梅花自在時。"]'),
('a97bea56-30f6-44f7-a9d7-b6bee4840e90','凉棚','艾性夫','宋','宋诗','song-poetry','','[]','數柱伶俜不架椽，密鋪松髪厚如氈。',64,'全唐诗/poet.song.247000.json','["數柱伶俜不架椽，密鋪松髪厚如氈。", "御風難覓深蓬島，障日聊成矮木天。", "肥瓠引藤高浥露，閒花借蔭省澆泉。", "熱時搆汝凉時撤，不是疏恩勢使然。"]'),
('124c17cd-082e-4f61-a2ee-79f2b7ead32d','郡樓九日','艾性夫','宋','宋诗','song-poetry','','[]','虹影初消雨脚收，憑高聊復散牢愁。',64,'全唐诗/poet.song.247000.json','["虹影初消雨脚收，憑高聊復散牢愁。", "烟橫三市蜂房屋，塵掩重門燕子樓。", "黄菊自隨陶令節，白雲那管漢時秋。", "雁飛不盡乾坤大，安得相從汗漫遊。"]'),
('20a4f3b8-b0b5-4b0f-bf1f-5e04b8165423','文節謝公挽歌','艾性夫','宋','宋诗','song-poetry','','[]','不甘摇尾乞人憐，視死如歸氣浩然。',64,'全唐诗/poet.song.247000.json','["不甘摇尾乞人憐，視死如歸氣浩然。", "千古六經俱掃地，獨公一柱肯擎天。", "乾坤萬劫英雄盡，文節雙高日月懸。", "惆悵老身空有淚，玉亭無路薦寒泉。"]'),
('ac35e504-e331-4a27-af8d-db8ca52af9f4','謝屏山吳顯父惠歙硯','艾性夫','宋','宋诗','song-poetry','','[]','蒼玉光寒篆紫烟，重重封裹到梅邊。',64,'全唐诗/poet.song.247000.json','["蒼玉光寒篆紫烟，重重封裹到梅邊。", "得君一片歙溪石，即我終身綿上田。", "少達必穿維翰鐵，儘窮共守子雲玄。", "老坡莫遣窮居後，遠在茶坑鳳咮前。"]'),
('5504db12-41fd-4e7d-a7dc-19f699499c14','立春日雪','艾性夫','宋','宋诗','song-poetry','','[]','曉爐香劑已燒殘，漫捲棨簾倚藥欄。',64,'全唐诗/poet.song.247000.json','["曉爐香劑已燒殘，漫捲棨簾倚藥欄。", "鞭底土牛方轉燠，石邊鹽虎忽凝寒。", "有人剪綵娛羔酒，獨我煎茶續菜盤。", "冰沍硯池呵未泮，東風到底入毫端。"]'),
('b83f77ba-1de3-4bc4-a15f-73328f17dbdb','雪銷','艾性夫','宋','宋诗','song-poetry','','[]','紅日行天熨絳綃，一番陽長便陰消。',64,'全唐诗/poet.song.247000.json','["紅日行天熨絳綃，一番陽長便陰消。", "青山又現本來面，瘦竹方伸久折腰。", "枯沼暗通泉細細，晴簷忽聽雨蕭蕭。", "獨憐點入吟翁鬢，費盡東風不肯銷。"]'),
('459b0863-6d93-4465-9cdb-100bdd0cbc59','糴踴感興','艾性夫','宋','宋诗','song-poetry','','[]','筆耕長餒拙生涯，何用撐腸著五車。',64,'全唐诗/poet.song.247000.json','["筆耕長餒拙生涯，何用撐腸著五車。", "甚欲療饑難煮字，可憐不飽費炊砂。", "老慚乞米修竿牘，貧欲休糧種棗瓜。", "夢裏不知時世換，買珠猶自說京華。"]'),
('acba3c70-ef8f-46bd-b817-c02cc0d36618','落梅','艾性夫','宋','宋诗','song-poetry','','[]','翠羽嘈嘈喚夢回，羅浮峰下小徘徊。',64,'全唐诗/poet.song.247000.json','["翠羽嘈嘈喚夢回，羅浮峰下小徘徊。", "霜風昨夜捲晴雪，山路今朝無碧苔。", "尚有瘦香供玉笛，不將餘片點妝臺。", "少須鼎實明人眼，却带江南烟雨來。"]'),
('66396def-fc4c-4508-9f77-31d152816a9c','歲菊','艾性夫','宋','宋诗','song-poetry','','[]','不逐登高老孟嘉，同來守歲阿戎家。',64,'全唐诗/poet.song.247000.json','["不逐登高老孟嘉，同來守歲阿戎家。", "能將秋圃風霜骨，直作寒梅輩行花。", "香稱屠蘇浮臘蟻，色侵幡勝插雲鴉。", "老夫細把金英擷，獨擬明朝早供茶。"]'),
('2e92e09f-d62e-46aa-9a57-721b3217958a','江上','艾性夫','宋','宋诗','song-poetry','','[]','江上春肥衰草生，林梢烟暖乳鳩鳴。',64,'全唐诗/poet.song.247000.json','["江上春肥衰草生，林梢烟暖乳鳩鳴。", "青山與我一面雅，白鳥令人雙眼明。", "雲凈有時看雨泣，水平無處覓溪聲。", "折芳弄翠渾閒冗，時與樵漁錯雜行。"]'),
('8d03b220-83f6-488f-95dc-de465ee7b8db','偶成','艾性夫','宋','宋诗','song-poetry','','[]','似是輪囷老蠹魚，尚饒蘭露入銅蜍。',64,'全唐诗/poet.song.247000.json','["似是輪囷老蠹魚，尚饒蘭露入銅蜍。", "詩亡正恐魯無史，士賤豈容秦有書。", "世味幾時回橄欖，秋山隨地著蘧廬。", "多情樵客能相問，莫有餘閒賦子虛。"]'),
('523a5666-6a52-4e1f-9fe2-8ce121cf3e5d','即事','艾性夫','宋','宋诗','song-poetry','','[]','一片輕鴻度小坡，半泓淺碧浸叢莎。',64,'全唐诗/poet.song.247000.json','["一片輕鴻度小坡，半泓淺碧浸叢莎。", "黑雲垂地雨聲急，黄葉滿林秋意多。", "短髪未冬先有雪，懶心如井不生波。", "孤砧已報寒消息，欠問眠鷗覓芰荷。"]'),
('236848da-8f08-4369-a098-959da15940df','過長林書羅文恭公碑陰','艾性夫','宋','宋诗','song-poetry','','[]','人家落落墮荒丘，碑带蒼苔獨自留。',64,'全唐诗/poet.song.247000.json','["人家落落墮荒丘，碑带蒼苔獨自留。", "博陸脊梁浮日月，中郎銘筆法春秋。", "一抔誰下尋墳馬，片石今供礪角牛。", "惟有斜陽閒照管，肯和鴉影上螭頭。"]'),
('169a5f02-43bd-4c49-8239-6a6d2164a9ed','失題','艾性夫','宋','宋诗','song-poetry','','[]','格磔聲高午夢殘，扊扅歌罷酒杯乾。',64,'全唐诗/poet.song.247000.json','["格磔聲高午夢殘，扊扅歌罷酒杯乾。", "漫天飛去楊花亂，著雨歸來燕子寒。", "世味淡如和蠟嚼，春山好在带雲看。", "近來習性渾成懶，抄盡陶詩獨倚闌。"]'),
('5bc75c24-3c91-4174-aa0e-204c3b037a92','深冬','艾性夫','宋','宋诗','song-poetry','','[]','凍透松邊屋兩間，孤牀盤礴數更闌。',64,'全唐诗/poet.song.247000.json','["凍透松邊屋兩間，孤牀盤礴數更闌。", "無情風雪偏欺老，經亂衣裘不禦寒。", "春意一爐紅榾柮，故人兩坐綠蒲團。", "敲冰自換甆瓶水，浸取梅花仔細看。"]'),
('9627d345-7831-4e44-a878-25d6898e2db3','安南貢象','艾性夫','宋','宋诗','song-poetry','','[]','錦韉寶勒度南雲，到處叢觀暗驛塵。',64,'全唐诗/poet.song.247000.json','["錦韉寶勒度南雲，到處叢觀暗驛塵。", "人喜此生初見象，我憂今世不生麟。", "半年傳舍勞供億，德色中朝動搢紳。", "粉飾太平焉用此，只消黄犢一犁春。"]'),
('a64639c4-85d3-4c1b-b664-7c53b115e3a8','贈廣信醫博士陳雲泉','艾性夫','宋','宋诗','song-poetry','','[]','見說雲泉深又深，定知巢入海棠林。',64,'全唐诗/poet.song.247000.json','["見說雲泉深又深，定知巢入海棠林。", "君醫尚副窮時願，吾道全孤壯歲心。", "藥籠有方玄白髪，莧腸無分服黄金。", "近來覓得安身法，諸老先生夜氣箴。"]'),
('cf2b31aa-ccc9-4cd1-8304-17fb36ef6fad','郡中逢桐廬方冰鑑相士','艾性夫','宋','宋诗','song-poetry','','[]','七里灘頭曾識面，五峰城裏又逢君。',64,'全唐诗/poet.song.247000.json','["七里灘頭曾識面，五峰城裏又逢君。", "人間一瞬白駒日，世事幾番蒼狗雲。", "奇骨誰當侯萬里，匹夫那可帥三軍。", "試憑冰鑑從頭問，細雨青燈過夜分。"]'),
('29a96ae5-5343-4611-b67c-c7bcdaef341a','觀放鸕鷀','艾性夫','宋','宋诗','song-poetry','','[]','烏鬼淋漓受指呼，江魚終日爲人敺。',64,'全唐诗/poet.song.247000.json','["烏鬼淋漓受指呼，江魚終日爲人敺。", "扼吭不及能言鴨，哇肉幾同反哺烏。", "暫滿空喉如癭大，竟無半尾塞腸枯。", "少寬頸組方謀飽，水冷沙寒日已晡。"]'),
('6d9e5903-04de-4d79-aa68-da16f280449c','臨汝書院落成諸公有詩用韻','艾性夫','宋','宋诗','song-poetry','','[]','魚躍鳶飛喜落成，鵝湖鹿洞共崢嶸。',64,'全唐诗/poet.song.247000.json','["魚躍鳶飛喜落成，鵝湖鹿洞共崢嶸。", "世無孔孟乾坤熄，學到周程日月明。", "議論高虛終害道，聖賢平實不爭名。", "光風霽月元無跡，分付庭前草自生。"]'),
('26f457d9-0d3b-49eb-9b97-3c9b9f877e34','追和晦庵先生十梅韻  其一','艾性夫','宋','宋诗','song-poetry','','[]','貞姿抱冰雪，粲粲楚江濱。',24,'全唐诗/poet.song.247000.json','["貞姿抱冰雪，粲粲楚江濱。", "照水淡寒影，寄人生遠春。"]'),
