('186a1a1a-06ce-4c45-b883-534aeca56d49','與林止庵葉半隠分賦郡中古跡得魯公祠右軍墨池  其二','艾性夫','宋','宋诗','song-poetry','','[]','昏昏水氣吐玄雲，自是先生筆有神。',32,'全唐诗/poet.song.247000.json','["昏昏水氣吐玄雲，自是先生筆有神。", "不洗從來姿媚態，可憐北面衛夫人。"]'),
('c20b39ae-042f-41f0-b006-475d42c92ee3','孺子亭','艾性夫','宋','宋诗','song-poetry','','[]','斷草寒烟故宅荒，高風千古映湖光。',32,'全唐诗/poet.song.247000.json','["斷草寒烟故宅荒，高風千古映湖光。", "獨憐漢帝徵車重，不及陳蕃八尺牀。"]'),
('7c5be297-f607-4682-a5b4-021399fcd8d0','木芙蓉','艾性夫','宋','宋诗','song-poetry','','[]','露冷紅酥不带愁，湘蘭楚菊共清修。',32,'全唐诗/poet.song.247000.json','["露冷紅酥不带愁，湘蘭楚菊共清修。", "靈均死去無人問，閒却滄江一片秋。"]'),
('f342c155-8779-45c6-8628-4c73247cf51d','漫興  其一','艾性夫','宋','宋诗','song-poetry','','[]','支離矮屋護松陰，半刻清閒直萬金。',32,'全唐诗/poet.song.247000.json','["支離矮屋護松陰，半刻清閒直萬金。", "蟋蟀叫回秋夢薄，一方凉月道人心。"]'),
('d0b8dc04-d55c-4f9f-bc01-b3c1f7a64380','漫興  其二','艾性夫','宋','宋诗','song-poetry','','[]','荒畦整整復斜斜，不種春風兒女花。',32,'全唐诗/poet.song.247000.json','["荒畦整整復斜斜，不種春風兒女花。", "却笑過牆蝴蝶亂，懶隨野老問桑麻。"]'),
('3bb09528-9e94-4260-a465-c9831d18309b','漫興  其三','艾性夫','宋','宋诗','song-poetry','','[]','凍耳蕭蕭天欲霜，冬深門巷意蒼凉。',32,'全唐诗/poet.song.247000.json','["凍耳蕭蕭天欲霜，冬深門巷意蒼凉。", "一筇徑爲梅花出，獨立斜陽影正長。"]'),
('9e343b54-8b48-438a-965f-362c33b26e1b','富陽出陸','艾性夫','宋','宋诗','song-poetry','','[]','露漙芳草綠茸茸，淡靄輕烟古畫中。',32,'全唐诗/poet.song.247000.json','["露漙芳草綠茸茸，淡靄輕烟古畫中。", "行盡葡萄三十里，海山青處日初紅。"]'),
('5c88a305-7820-458f-b9bd-d535ff42c7d7','留客','艾性夫','宋','宋诗','song-poetry','','[]','棨櫚葉碎風索索，枇杷子熟烟冥冥。',32,'全唐诗/poet.song.247000.json','["棨櫚葉碎風索索，枇杷子熟烟冥冥。", "黄鸝三請我未出，白酒一樽君小停。"]'),
('1d9c1d62-319d-4fac-894e-a3f9a0abae34','經語詩戲效唐子西  其一','艾性夫','宋','宋诗','song-poetry','','[]','山徑之蹊去去賒，篳門圭竇是誰家。',32,'全唐诗/poet.song.247000.json','["山徑之蹊去去賒，篳門圭竇是誰家。", "其生色也草交翠，彼美人兮蓮正花。"]'),
('6b86fdb5-1328-4e54-b5ac-83737f8dce51','經語詩戲效唐子西  其二','艾性夫','宋','宋诗','song-poetry','','[]','源泉混混出虛巖，桑者閒閒人已蠶。',32,'全唐诗/poet.song.247000.json','["源泉混混出虛巖，桑者閒閒人已蠶。", "剪韭不妨千取百，種瓜且喜二生三。"]'),
('141bb984-53f8-4bfb-bba2-fc0f6121337f','偶題','艾性夫','宋','宋诗','song-poetry','','[]','窗涵山影月初斜，門傍溪橋柳半遮。',32,'全唐诗/poet.song.247000.json','["窗涵山影月初斜，門傍溪橋柳半遮。", "獨客不眠春起早，一簾香雪嗅梨花。"]'),
('82ed495a-47ca-4907-95aa-815a531c3321','深村','艾性夫','宋','宋诗','song-poetry','','[]','索居無遠興，晚憩傍深村。',48,'全唐诗/poet.song.247000.json','["索居無遠興，晚憩傍深村。", "磵澀水爭道，桑空草托根。", "斷橋回老馬，熟果聚饑猿。", "解后僧同話，歸來人掩門。"]'),
('b5be8c54-8cd6-4273-9466-49a3f9f5b62b','秋村','艾性夫','宋','宋诗','song-poetry','','[]','稻黄雁入蔗境，水落鷺過屠門。',28,'全唐诗/poet.song.247000.json','["稻黄雁入蔗境，水落鷺過屠門。", "一片寒烟晚景，數聲牧笛秋村。"]'),
('1efd0705-bf1b-4640-8cdf-bfb54a8fb4c7','陳庭翠水竹清處','艾性夫','宋','宋诗','song-poetry','','[]','晴波漾文綺，風篁弄家聲。',60,'全唐诗/poet.song.247000.json','["晴波漾文綺，風篁弄家聲。", "居然三市中，著此一段清。", "幽人自地偏，淡趣由天成。", "洗耳日以靜，抱節日以貞。", "從君得三絕，與我增雙明。"]'),
('16e15224-9d1e-4f64-8441-53feb2f2becc','贈族子治鬼疾','艾性夫','宋','宋诗','song-poetry','','[]','瞠獰電目頭蒙倛，兩手握斷青桃枝。',107,'全唐诗/poet.song.247000.json','["瞠獰電目頭蒙倛，兩手握斷青桃枝。", "丹符落火六丁走，白晝破柱神雷飛。", "何物尸蟲作妖魅，敢上天庭聒天耳。", "坐俘心腹三彭仇，生馘膏肓雙孺子。", "君不見大巫擒鬼先擒王，質蹻猥瑣不足當。", "請君爲我祓不祥，疾驅威霆行鬼方，餘力熙河鉏鬼章。"]'),
('3e01a2ab-176f-4a49-b1b1-8b938f7d6454','鬚語眉','艾性夫','宋','宋诗','song-poetry','','[]','只爲長供撚斷吟，蕭疏早受雪霜侵。',32,'全唐诗/poet.song.247000.json','["只爲長供撚斷吟，蕭疏早受雪霜侵。", "羨君閑冗渾無用，留得童烏尚到今。"]'),
('f3e088c1-093f-47d6-ab93-613bdcde6566','眉答鬚','艾性夫','宋','宋诗','song-poetry','','[]','平生不皺偶偷閑，故得吟眉聳兩山。',32,'全唐诗/poet.song.247000.json','["平生不皺偶偷閑，故得吟眉聳兩山。", "若使與君相併白，應無詩句落人間。"]'),
('cfa81162-0f1b-4a67-a3ad-e450734c2dd9','晞髪','艾性夫','宋','宋诗','song-poetry','','[]','射透秋林曉日紅，謾晞衰髪竹籬東。',64,'全唐诗/poet.song.247000.json','["射透秋林曉日紅，謾晞衰髪竹籬東。", "舊曾過膝今垂耳，老已成翁反似童。", "辛苦一生多沐雨，蕭颾幾縷易梳風。", "歲寒萬綠凋零盡，春在梅花白雪中。"]'),
('d30212c6-1647-4946-add6-bd201be21f1c','年踰古希鬚髪併白惟眉玄如初','艾性夫','宋','宋诗','song-poetry','','[]','種種閑愁先上眉，愁應白早不應遲。',32,'全唐诗/poet.song.247000.json','["種種閑愁先上眉，愁應白早不應遲。", "定知白了愁誰管，直到無愁是白時。"]'),
('91bc3599-7709-49e5-ac2d-013a9647e4ad','定氣','艾性夫','宋','宋诗','song-poetry','','[]','朝三亦可不必怒，角左幾何烏用爭。',32,'全唐诗/poet.song.247000.json','["朝三亦可不必怒，角左幾何烏用爭。", "不多不少飯一龠，無敗無成棋半枰。"]'),
('c8148280-0066-45fa-bc3c-e97b3afbef18','張宛丘寄衣曲  其一','艾性夫','宋','宋诗','song-poetry','','[]','衷甲葱河不記春，何須更比小郎身。',32,'全唐诗/poet.song.247000.json','["衷甲葱河不記春，何須更比小郎身。", "只消狹剪征衫去，塞雪邊風最瘦人。"]'),
('22a0f90a-22db-4355-b55c-fdcf2717478d','張宛丘寄衣曲  其二','艾性夫','宋','宋诗','song-poetry','','[]','要識關雎樂不淫，勿疑漢上有題衿。',32,'全唐诗/poet.song.247000.json','["要識關雎樂不淫，勿疑漢上有題衿。", "思無邪是觀詩法，一笑先生欠古心。"]'),
('49aa8ae1-384e-44da-8bf2-3069245a07ac','金銅仙人辭漢歌','艾性夫','宋','宋诗','song-poetry','','[]','劍光瀝盡文成血，野鳥啼墮樓居月。',96,'全唐诗/poet.song.247000.json','["劍光瀝盡文成血，野鳥啼墮樓居月。", "茂陵玉碗土花青，不注天漿餐玉屑。", "金仙百尺寒亭亭，千人萬人挽不行。", "委身只識秋風客，肯與漢賊求長生。", "柏梁臺邊鬼摇扇，露盤驚破銅花片。", "孤瞠泣斷灞城秋，兩漢正無忠義傳。"]'),
('aff77033-4249-4d25-8d72-a231249a5177','老圃送瓜因爲邵平具案  其一','艾性夫','宋','宋诗','song-poetry','','[]','筠籃滿貯綠離離，白髪村翁手自提。',32,'全唐诗/poet.song.247000.json','["筠籃滿貯綠離離，白髪村翁手自提。", "能學園人憐杜老，也分蒲鴿到花溪。"]'),
('6e32cdaa-977b-4b7b-bb5f-e84ba6b617ad','老圃送瓜因爲邵平具案  其二','艾性夫','宋','宋诗','song-poetry','','[]','食叨千戶竊侯封，不仕爲高仕死忠。',32,'全唐诗/poet.song.247000.json','["食叨千戶竊侯封，不仕爲高仕死忠。", "臨難歸來圖苟活，種瓜何及種桃翁。"]'),
('f22724db-8339-4a5b-96b5-5ef1e0cd9f12','贈鄰僧遊杭','艾性夫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','道潜五月過臨平，師又挑雲把瘦藤。',64,'全唐诗/poet.song.247000.json','["道潜五月過臨平，師又挑雲把瘦藤。", "飽聽西湖蓮葉雨，密傳靈鷲雪峰燈。", "空城潮打三千丈，荒殿烟寒十二層。", "愁絕舊時行脚處，而今分付與閑僧。"]'),
('8bdc4da3-ff44-40bb-8e44-7f0fefcd93c3','贈僧','艾性夫','宋','宋诗','song-poetry','','[]','利門名路兩何憑，百歲風前短焰燈。',32,'全唐诗/poet.song.247000.json','["利門名路兩何憑，百歲風前短焰燈。", "只恐爲僧僧不了，爲僧心了總輸僧。"]'),
('329b6f86-792a-431d-be24-0a2aa13454d4','贈頭陀僧','艾性夫','宋','宋诗','song-poetry','','[]','自說年深別石橋，遍遊靈跡熟南朝。',64,'全唐诗/poet.song.247000.json','["自說年深別石橋，遍遊靈跡熟南朝。", "已知世路皆虛幻，不覺空門是寂寥。", "滄海附船浮浪久，碧山尋塔上雲遥。", "如今竹院藏衰老，一點寒燈弟子燒。"]'),
('68f1fe46-5c31-497b-8325-7ce7f94cf23c','贈古崖復上人游','艾性夫','宋','宋诗','song-poetry','','[]','高僧如雲不受縛，烏藤五尺陪行脚。',64,'全唐诗/poet.song.247000.json','["高僧如雲不受縛，烏藤五尺陪行脚。", "幾年陳迹旋磨牛，一日橫空出籠鶴。", "江山悠遠天宇闊，眼力窮時吟吻渴。", "含新嚥秀入清脾，蔬笋敢污甘露鉢。"]'),
('e02b0b7e-a895-4a96-84fb-3c94e9ccfac4','贈畫魚李生','艾性夫','宋','宋诗','song-poetry','','[]','李生畫魚天下無，得心應手神爲徒。',64,'全唐诗/poet.song.247000.json','["李生畫魚天下無，得心應手神爲徒。", "虛堂素壁掃塵土，遠趣一筆移江湖。", "青魚洋洋翻荇带，鱖魚獵獵穿蒲稗。", "醉來屢欲呼霜刀，爲我樽前斫新鱠。"]'),
('27d21ec0-85de-4b96-99c6-2282e48720d3','贈新中郭四翁','艾性夫','宋','宋诗','song-poetry','','[]','幾人到得白頭翁，生老痾沉是始終。',64,'全唐诗/poet.song.247000.json','["幾人到得白頭翁，生老痾沉是始終。", "濁穢腥羶除壽算，慳貪嫉妬轉昏蒙。", "有憎有愛難超世，無慾無情定脫空。", "幸有天堂地獄路，聖凡迷悟總由公。"]'),
('71aff302-b348-4c77-bab0-f446c2e9f281','危見心携示別去寄謝','艾性夫','宋','宋诗','song-poetry','','[]','好客來今雨，長吟出古風。',48,'全唐诗/poet.song.247000.json','["好客來今雨，長吟出古風。", "詩神君獨富，文鬼我方窮。", "湖海飄零外，乾坤感慨中。", "相逢難衮衮，取別竟匆匆。"]'),
('13369ae2-4ad4-4f10-9951-50b592a5d1f4','酬楊簿正父子和詩  其一','艾性夫','宋','宋诗','song-poetry','','[]','落落冥鴻惜羽毛，黄塵不把涴青袍。',64,'全唐诗/poet.song.247000.json','["落落冥鴻惜羽毛，黄塵不把涴青袍。", "關西夫子經猶在，水北山人價自高。", "吾道不昌該氣數，密林雖寂少風濤。", "半園花木能招隠，早晚相從問種桃。"]'),
('672bb02e-911c-4ae0-9eb6-cfb4a0beb25e','酬楊簿正父子和詩  其二','艾性夫','宋','宋诗','song-poetry','','[]','誰把蛩吟過草堂，燁然引玉照奚囊。',64,'全唐诗/poet.song.247000.json','["誰把蛩吟過草堂，燁然引玉照奚囊。", "喜看彪固能聯筆，愧殺曹劉有短牆。", "千古風騷幾絕響，一壺冰雪忽增光。", "客來謾寄山中稿，莫笑梅花只淡妝。"]'),
('5cfde48c-6a8b-495f-ad6f-3576851eb160','酬庭翠陳善夫','艾性夫','宋','宋诗','song-poetry','','[]','家在文昌古堰西，紅蕖環映碧漣漪。',64,'全唐诗/poet.song.247000.json','["家在文昌古堰西，紅蕖環映碧漣漪。", "飽鍾天地清脾氣，厭作江湖近體詩。", "雪繭草書香不斷，玉壺冰壑夢相隨。", "自憐未到參禪處，欠問彭城老祖師。"]'),
('f6f56881-45c4-4aa7-aeb5-e83ddb7d2b0a','答諸友','艾性夫','宋','宋诗','song-poetry','','[]','霜葉吹紅鶴影孤，雨苔封綠屐痕疏。',64,'全唐诗/poet.song.247000.json','["霜葉吹紅鶴影孤，雨苔封綠屐痕疏。", "風才敲竹便疑客，雁不入山難寄書。", "自有乾坤心最大，稍無根柢學皆虛。", "閉門未了研朱事，多謝梅花慰索居。"]'),
('62acf47e-4587-42fa-aad4-0957ccd0ef26','客有問擇術者戲答','艾性夫','宋','宋诗','song-poetry','','[]','君不見三家市頭洒削翁，鼎食侈與王公同。',72,'全唐诗/poet.song.247000.json','["君不見三家市頭洒削翁，鼎食侈與王公同。", "又不見萬金海上屠龍手，須捷纍纍事饑走。", "人言有藝人不貧，誰知藝高貧殺人。", "向來擇術吾已錯，勸君只學相牛莫相鶴。"]'),
('b682cd80-2c5e-4728-aab0-164b10604aa6','謝了心聰上人以惡詩入逡巡碑','艾性夫','宋','宋诗','song-poetry','','[]','繭紙鉛華字字新，不須刀筆勒堅珉。',64,'全唐诗/poet.song.247000.json','["繭紙鉛華字字新，不須刀筆勒堅珉。", "分明能守玄中白，彷彿難知贋與真。", "懷素草書爭媚嫵，韓湘奇術鬬逡巡。", "正慚野語多流落，幻作橫碑更累人。"]'),
('29aa26fc-c964-49c0-8524-d297d1f2a577','用言客談奉謝  其一','艾性夫','宋','宋诗','song-poetry','','[]','倦遊太史牛馬走，作賦先生亦烏有。',96,'全唐诗/poet.song.247000.json','["倦遊太史牛馬走，作賦先生亦烏有。", "杞國天摧只自驚，梁園瓠落知誰要。", "青津碧荻寒不枯，園丘紫柰天下無。", "嵩南太華夢可到，仙人鴻寶今無書。", "霜煎雪逼梅花少，不向春風怨枯槁。", "萬古乾坤蒼狗雲，一天風雨黄雞曉。"]'),
('93cb143b-4903-4d9c-8b26-ef640c5cc6a2','用言客談奉謝  其二','艾性夫','宋','宋诗','song-poetry','','[]','門外黄塵透日飛，山中白髪得春遲。',64,'全唐诗/poet.song.247000.json','["門外黄塵透日飛，山中白髪得春遲。", "一身冠屨聊存古，半語詩書不入時。", "佳橋盡從中路變，蒼松獨到歲寒知。", "黑牛白犢今無驗，空遣閑愁上兩眉。"]'),
('eacd57ec-e33d-4cb4-be02-0d040d8a3f65','楊柳騷','艾性夫','宋','宋诗','song-poetry','','[]','縷縷柔條不奈春，爲誰憔悴把眉顰。',32,'全唐诗/poet.song.247000.json','["縷縷柔條不奈春，爲誰憔悴把眉顰。", "年來江上多離別，不信垂楊管得人。"]'),
('0999e5c1-5bf9-4ec1-b2ce-34dfbdffc671','落葉','艾性夫','宋','宋诗','song-poetry','','[]','清霜槁千林，黄葉欲萬舞。',24,'全唐诗/poet.song.247000.json','["清霜槁千林，黄葉欲萬舞。", "一夜北窗眠，瀟瀟聽乾雨。"]'),
('efd8cbf3-4231-43e0-ada3-d68f29711bd3','寒燈作花','艾性夫','宋','宋诗','song-poetry','','[]','寒釭融白脂，凍焰結紅豆。',24,'全唐诗/poet.song.247000.json','["寒釭融白脂，凍焰結紅豆。", "草有問字人，明朝能載酒。"]'),
('b3d0c5f0-f4d9-40cf-978c-9a1bbbe8023e','滌硯','艾性夫','宋','宋诗','song-poetry','','[]','淙淙瀑布泉，濯濯刷絲石。',48,'全唐诗/poet.song.247000.json','["淙淙瀑布泉，濯濯刷絲石。", "坐令黟川漆，漲作梁州黑。", "以涅定不緇，欲玄終尚白。", "適與吾道同，持歸試新墨。"]'),
('b55fe55c-76b2-4040-b487-edd178454dd9','餘干問舟','艾性夫','宋','宋诗','song-poetry','','[]','烏桕林頭月上弦，黄蘆磯下水平天。',64,'全唐诗/poet.song.247000.json','["烏桕林頭月上弦，黄蘆磯下水平天。", "十年客路多隨雁，一樹秋聲總是蟬。", "江闊亂分漁火細，灘空長漱岸沙圓。", "丁寧說與梢人去，若過芝山且繫船。"]'),
('49467cde-ab32-449d-9d3b-eaed95210bd9','洞泉觀楊梅屋寮','艾性夫','宋','宋诗','song-poetry','','[]','孤嶼如螺出水心，松蒼竹翠結寒陰。',64,'全唐诗/poet.song.247000.json','["孤嶼如螺出水心，松蒼竹翠結寒陰。", "不因鍾磬穿雲響，誰信神仙入洞深。", "早日羽衣人盡老，春風摇草路重尋。", "徑須著我梅邊屋，聽講南華弄玉琴。"]'),
('45a17f7e-a4db-483c-98a1-9934ecbdea03','賦鐵柱','艾性夫','宋','宋诗','song-poetry','','[]','淮川鎖支祁，民免其魚苦。',76,'全唐诗/poet.song.247000.json','["淮川鎖支祁，民免其魚苦。", "誰謂旌陽翁，功可配神禹。", "小試青蛇鋒，橫絕長蛟膂。", "聚彼數州鐵，鑄此千尺柱。", "沉江壓餘妖，妥首敢掀舞。", "波濤永息民按堵，只恐人間有周處。"]'),
('561fd02a-beaf-44b1-ae82-162826bd07d1','六和塔浙江亭廟山皆宰執待罪之所併作一絕','艾性夫','宋','宋诗','song-poetry','','[]','國門西出小徘徊，中使傳宣遽勒回。',32,'全唐诗/poet.song.247000.json','["國門西出小徘徊，中使傳宣遽勒回。", "南渡山河天一角，不知待罪合誰來。"]'),
('8ad8d944-9151-4ac6-b96b-c8d00028aa2c','項羽廟','艾性夫','宋','宋诗','song-poetry','','[]','容心絕少忌心多，背楚疑增自倒戈。',64,'全唐诗/poet.song.247000.json','["容心絕少忌心多，背楚疑增自倒戈。", "羞渡烏江依故老，竟乘烏騅泣嬌娥。", "一生負氣止如此，大義虧人爭奈何。", "莫唱送迎山下曲，恐渠驚是漢軍歌。"]'),
('eff9e2b3-9783-46e2-ac2f-a53b6583e758','古歙道中','艾性夫','宋','宋诗','song-poetry','','[]','疊翠峰前聽踏歌，十年脚債又經過。',64,'全唐诗/poet.song.247000.json','["疊翠峰前聽踏歌，十年脚債又經過。", "長因買硯迂途遠，每爲看山費日多。", "別渚清流團宿鷺，小橋紅影動秋荷。", "新安夫子知何在，滿目祠亭鎖薜蘿。"]'),
('318ca098-ba4c-4174-8cbf-acf5094e29db','山中曲  其一','艾性夫','宋','宋诗','song-poetry','','[]','久雨作惡春事老，乍晴可人山路長。',32,'全唐诗/poet.song.247000.json','["久雨作惡春事老，乍晴可人山路長。", "紫冰摇摇菌耳濕，黄雪糝糝松花香。"]'),
('6c528f11-190f-48f9-96cf-c07ceec5b97f','山中曲  其二','艾性夫','宋','宋诗','song-poetry','','[]','深山無人風自語，古澗觸石泉爭鳴。',32,'全唐诗/poet.song.247000.json','["深山無人風自語，古澗觸石泉爭鳴。", "殘花時墮一兩片，好鳥忽啼三五聲。"]'),
('4dbc8f6c-3ee4-4e35-bc17-2033d174f295','補易水歌效郭青山','艾性夫','宋','宋诗','song-poetry','','[]','朝隨寒雲度陰山，暮指落月槌函關。',205,'全唐诗/poet.song.247000.json','["朝隨寒雲度陰山，暮指落月槌函關。", "函關牡鑰泥爲丸，陰山俠客鐵作肝。", "秦如虎狼生羽翰，飛食六國俱創殘。", "生角雨粟憐吾丹，舍生取義我則安。", "古劍錯落黄金鐶，劍光苦短不足看。", "雕弓矢矯烏犀盤，弓弦易折不足彎。", "右携地圖墨漫漫，左提髑髏血斑斑。", "祖龍見此生歡顔，便可快意須臾間。", "我以至易圖至難，聽我抵掌歌酒闌。", "歌曰風蕭蕭兮易水寒，壯士一去兮不復還。", "又進而歌曰壯士一去兮不復還，不意咸陽殿上有柱尚可環。", "無且藥囊利鏌干，我志不遂節則完。"]'),
('224fdfb3-8c28-4717-937c-a2c593c5911f','夏畦','艾性夫','宋','宋诗','song-poetry','','[]','清晨步蔬畦，生意慘不綠。',48,'全唐诗/poet.song.247000.json','["清晨步蔬畦，生意慘不綠。", "烈哉三足烏，覆此五鼎餗。", "呼童吸深清，且勿荒我菊。", "一片雲有心，停陰作花屋。"]'),
('449bb177-32d3-4f50-b378-f4d9e2c53737','春山','艾性夫','宋','宋诗','song-poetry','','[]','春山不可畫，烟雨近江樓。',48,'全唐诗/poet.song.247000.json','["春山不可畫，烟雨近江樓。", "藤老依松活，泉迂避石流。", "懶雲低渡竹，細草亂沿溝。", "欲打巴禽去，家居聽亦愁。"]'),
('51961f80-2395-4f91-be77-f65c7e52c2f4','寒山  其一','艾性夫','宋','宋诗','song-poetry','','[]','緊峭江風結凍雲，棨簾不暖撥灰人。',32,'全唐诗/poet.song.247000.json','["緊峭江風結凍雲，棨簾不暖撥灰人。", "山中幸有梅花曆，開到南枝便是春。"]'),
('6e3f1f7d-ddd8-4b80-afab-697420314283','寒山  其二','艾性夫','宋','宋诗','song-poetry','','[]','山影飄摇落雁風，寒歌斷續釣魚翁。',32,'全唐诗/poet.song.247000.json','["山影飄摇落雁風，寒歌斷續釣魚翁。", "一溪霜葉如猩血，奪盡斜陽十里紅。"]'),
('ee073510-1311-4245-ba7e-23ee3147d0fc','山礬代山谷改評','艾性夫','宋','宋诗','song-poetry','','[]','刻玉瓏鬆萬萬葩，暖香薰透小窗紗。',32,'全唐诗/poet.song.247000.json','["刻玉瓏鬆萬萬葩，暖香薰透小窗紗。", "水仙未可呼爲弟，此是春風第一花。"]'),
('a6164436-322d-466c-b11d-fa19d434506b','吊老松','艾性夫','宋','宋诗','song-poetry','','[]','合梁清廟棟明堂，棄擲終身古道傍。',64,'全唐诗/poet.song.247000.json','["合梁清廟棟明堂，棄擲終身古道傍。", "大節不容秦點污，孤根能與宋存亡。", "山空百丈龍蛇影，泉沁千年琥珀香。", "韋偃畢宏今不見，誰將老骨寫風霜。"]'),
('5c443c38-8a24-4d51-aacf-dd07aa0ca41a','玄都韓植蘭楚香','艾性夫','宋','宋诗','song-poetry','','[]','玄都舊日神仙宅，種桃羞殺劉賓客。',80,'全唐诗/poet.song.247000.json','["玄都舊日神仙宅，種桃羞殺劉賓客。", "只今仙子韓家湘，不遣牡丹開頃刻。", "春風九畹花繞屋，冶紫妖紅失顔色。", "盲風怪雨三千年，湘水芳魂招不得。", "翩然散入碧虛寒，乾坤萬里離騷國。"]'),
('05d04e43-7f7c-4b9c-b69e-93f42ab01254','盤圃張伯誠餉柑','艾性夫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','髯奚叩門踏枯葉，手持子敬相問帖。',80,'全唐诗/poet.song.247000.json','["髯奚叩門踏枯葉，手持子敬相問帖。", "筠籃包送洞庭秋，照眼錯落黄金毬。", "含漿似注甘露鉢，好與文園止消渴。", "問渠幾日辭霜枝，化作□□□□□。", "道上應無公遠嗅，定中安定王家□。"]'),
('fd9b8dcc-5dc9-4d9e-bb95-fdd5dcdca96f','種韭','艾性夫','宋','宋诗','song-poetry','','[]','深培膏土玉釵長，細擺春風碧带香。',32,'全唐诗/poet.song.247000.json','["深培膏土玉釵長，細擺春風碧带香。", "莫笑庾郎滋味薄，只渠便是太官羊。"]'),
('099bc263-8aef-493c-9745-11aed9666aa4','從和山聰上人覓竹','艾性夫','宋','宋诗','song-poetry','','[]','龍光長老有大竹，肯爲東坡斫兩竿。',32,'全唐诗/poet.song.247000.json','["龍光長老有大竹，肯爲東坡斫兩竿。", "可是孟郊家具少，請師分我碧琅玕。"]'),
('44683496-221c-49ea-be4c-2e535437af34','鴨責鷺','艾性夫','宋','宋诗','song-poetry','','[]','物生天地間，謀食各從類。',103,'全唐诗/poet.song.247000.json','["物生天地間，謀食各從類。", "平疇我所家，方逐魚蝦細。", "爾鷺非吾徒，引頸乃旁睨。", "纖鱗動微影，忽已落長喙。", "潔白徒外觀，貪墨實素志。", "徘徊飽未休，陰攫殊得計。", "我本能言者，責汝合思義。", "君不見左右望而罔市利，有私龍斷人所棄。"]'),
('9631685b-c11b-4092-be22-4bc50f7fda40','鷺答鴨','艾性夫','宋','宋诗','song-poetry','','[]','□勿生天地，營己合有私。',103,'全唐诗/poet.song.247000.json','["□勿生天地，營己合有私。", "魚蝦性所嗜，丁獨令爾肥。", "□□賦我形，延頸正有需。", "吾頸高可跂，吾休頸可飛。", "吾喙長可啄，吾目光可窺。", "是皆爾所短，胡乃責我爲。", "我亦號雪客，污我我有辭。", "君不見秦亡其鹿共逐時，高材疾足先得之。"]'),
('579a7170-4a41-4835-8916-7da263f2fa90','蟋蟀','艾性夫','宋','宋诗','song-poetry','','[]','不從草際伴啼螀，偏逐西風入我牀。',64,'全唐诗/poet.song.247000.json','["不從草際伴啼螀，偏逐西風入我牀。", "心事甚如愁欲訴，秋吟直與夜俱長。", "一年時節蟲聲早，半樹梧桐月影凉。", "憶得重胡衰柳下，健兒籠汝鬬斜陽。"]'),
('3545a608-1d43-4d02-9e67-972e2f66b60c','燕去十年復來巢','艾性夫','宋','宋诗','song-poetry','','[]','雙燕窺簾認主人，十年不見忽過門。',64,'全唐诗/poet.song.247000.json','["雙燕窺簾認主人，十年不見忽過門。", "烏衣故國今何在，蒼籙遺民老幸存。", "芹沼不香驚綠暗，草堂無語對黄昏。", "從今不必依王謝，只好尋常烟雨村。"]'),
('99a1e413-dfad-47a6-86d4-715c525be8a9','錢塘聞子規  其一','艾性夫','宋','宋诗','song-poetry','','[]','汴水淒凉已百年，長因啼鳥一潸然。',32,'全唐诗/poet.song.247000.json','["汴水淒凉已百年，長因啼鳥一潸然。", "天津橋上無人聽，尚喜錢塘有杜鵑。"]'),
('b0f8bf76-e0ff-4822-8264-3121c159e6f6','錢塘聞子規  其二','艾性夫','宋','宋诗','song-poetry','','[]','中原戢戢盡遺黎，日夜江頭候六飛。',32,'全唐诗/poet.song.247000.json','["中原戢戢盡遺黎，日夜江頭候六飛。", "來此苦啼真有意，會須勸得翠華歸。"]'),
('c9c32b95-2770-490a-a428-aee1608a29aa','病中聞雁有感','艾性夫','宋','宋诗','song-poetry','','[]','我病無眠守夜闌，汝來何暮尚雲端。',64,'全唐诗/poet.song.247000.json','["我病無眠守夜闌，汝來何暮尚雲端。", "去鄉萬里關河隔，带月一聲風露寒。", "口腹累人菰米飯，弟兄何處荻花灘。", "營門射手桑弓健，止好冥冥惜羽翰。"]'),
('b8a01b51-4736-4c48-9cfb-1bd96231f229','憫蟹','艾性夫','宋','宋诗','song-poetry','','[]','落穽都緣奔火明，林然多足不支傾。',64,'全唐诗/poet.song.247000.json','["落穽都緣奔火明，林然多足不支傾。", "是誰貽怒到公等，憐汝無腸受鼎烹。", "支解肯供浮白醉，殻空竟棄外黄城。", "江湖好是橫行處，草淺泥污過一生。"]'),
('034efa0a-ca47-450b-b73e-9653c2f5d4c3','古驛','艾性夫','宋','宋诗','song-poetry','','[]','舊時鄰曲各東西，野蔓荒藤壓樹低。',32,'全唐诗/poet.song.247000.json','["舊時鄰曲各東西，野蔓荒藤壓樹低。", "過盡路牌無客影，一岡秋雨鷓鴣啼。"]'),
('d55af4c5-3580-4b6f-924d-d5f18991c161','上藍寺吸江樓','艾性夫','宋','宋诗','song-poetry','','[]','拔地連雲百尺樓，長風斷雁十分秋。',64,'全唐诗/poet.song.247000.json','["拔地連雲百尺樓，長風斷雁十分秋。", "絕無山硋天空闊，獨與江鄰水拍浮。", "潭底老龍眠屋影，雨餘雌霓跨簾鈎。", "愁來莫倚闌干北，一縷烽烟是汴州。"]'),
('6300d3a5-0149-4a3a-896f-886ead71b8fd','葛溪驛','艾性夫','宋','宋诗','song-poetry','','[]','疏雨微雲隔岸山，亂花芳草曲江干。',32,'全唐诗/poet.song.247000.json','["疏雨微雲隔岸山，亂花芳草曲江干。", "誰家簾幕臨官道，一陣東風燕子寒。"]'),
('5917e9d5-5c16-466c-966d-be8a0d1811ee','秋堂','艾性夫','宋','宋诗','song-poetry','','[]','虛幌濕朝露，枯琴寒夜泉。',48,'全唐诗/poet.song.247000.json','["虛幌濕朝露，枯琴寒夜泉。", "苔多應占地，林闕欲分天。", "香細浮烟短，蓬穿漏日圓。", "黄花慰貧老，滿眼粲金錢。"]'),
('836a9a3c-530d-4f0d-9cfa-fb770387a049','題陳朝玉愛竹軒','艾性夫','宋','宋诗','song-poetry','','[]','陰森窗外萬琅玕，盡日吟翁此倚闌。',64,'全唐诗/poet.song.247000.json','["陰森窗外萬琅玕，盡日吟翁此倚闌。", "曾借春風閑管勾，喜從劫火報平安。", "四時青眼相看易，三世同盟耐久難。", "千古溪林遺事在，不妨標致共高寒。"]'),
('7b122763-0bbd-4d45-a827-5129a543f30d','出東門  其一','艾性夫','宋','宋诗','song-poetry','','[]','驅車出東門，悵望東門道。',72,'全唐诗/poet.song.247000.json','["驅車出東門，悵望東門道。", "折蘭贈所思，所贈非所好。", "豈無千丈紅，相媚一餉好。", "終然失所性，不肯寘懷抱。", "秋風日以高，玄髪日以縞。", "携蘭種幽谷，珮服從吾老。"]'),
('df4abae7-edbe-4937-9c27-79380cc04e70','出東門  其二','艾性夫','宋','宋诗','song-poetry','','[]','驅車出東門，客問將何之。',72,'全唐诗/poet.song.247000.json','["驅車出東門，客問將何之。", "遺我黄鵠羽，舉我栗木枝。", "勿謂一羽輕，橫翔以相期。", "勿訝一木微，謹畏堪自持。", "一拜感客意，再拜領客辭。", "何以報知己，奉之千歲龜。"]'),
('35aa11f5-42dc-4168-b581-be8b3d61d79d','秋屏閣','艾性夫','宋','宋诗','song-poetry','','[]','西山和影浸空江，落木無烟带夕陽。',32,'全唐诗/poet.song.247000.json','["西山和影浸空江，落木無烟带夕陽。", "立盡闌干秋思遠，風鴉雲雁兩三行。"]'),
('cde83f33-c130-43ad-8cca-119a5f2d29c4','漁家','艾性夫','宋','宋诗','song-poetry','','[]','水浸秋空夜色晴，柳根三五釣船輕。',32,'全唐诗/poet.song.247000.json','["水浸秋空夜色晴，柳根三五釣船輕。", "不知長笛在何處，忽趁月明吹一聲。"]'),
('d07b7e3b-979a-4273-9ff2-79d99f9c2094','岳武穆葬西湖故宅爲學宮  其一','艾性夫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老秦舉□媚□金，枉死如公恨最深。',32,'全唐诗/poet.song.247000.json','["老秦舉□媚□金，枉死如公恨最深。", "地下紅旗應北指，西湖埋骨不埋心。"]'),
('995bd246-fd9a-4183-95ed-72f777814269','岳武穆葬西湖故宅爲學宮  其二','艾性夫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','故園今日館英游，大耻俱忘總可羞。',32,'全唐诗/poet.song.247000.json','["故園今日館英游，大耻俱忘總可羞。", "料得精魂長扼腕，無人講學到春秋。"]'),
('2aa858f3-ead3-4ac4-901b-483bc8707462','秋丁卧堰合樓','艾性夫','宋','宋诗','song-poetry','','[]','憶得年時此倚闌，日邊指點說吳山。',64,'全唐诗/poet.song.247000.json','["憶得年時此倚闌，日邊指點說吳山。", "舟移半夜成虛夢，人負斯樓亦厚顔。", "槐古不知花幾度，城頹空護屋三間。", "追思往事渾無寐，寂歷虛簷月半彎。"]'),
('33995584-dd6d-4c24-b27d-eb8b5c00e13a','薦福寺','艾性夫','宋','宋诗','song-poetry','','[]','細看莫莫堂前月，似是寥寥五祖燈。',64,'全唐诗/poet.song.247000.json','["細看莫莫堂前月，似是寥寥五祖燈。", "曾有虎來聽法去，更無碑可付雷轟。", "修廊半是題詩壁，遊客多於住院僧。", "我亦飄零歸未得，竹牀分卧看雲生。"]'),
('4c92c5b1-8da9-4ce3-ae4f-25ecb1bbce4f','蕭寺秋夜','艾性夫','宋','宋诗','song-poetry','','[]','藤護頹垣石靠門，竹罏香穗篆餘熏。',64,'全唐诗/poet.song.247000.json','["藤護頹垣石靠門，竹罏香穗篆餘熏。", "醉來終夜不知雨，夢覺四山都是雲。", "半局棋枯僧入定，一聲松響鶴離群。", "缺權癩可風流盡，招隠歸來有此君。"]'),
('7cc08526-270f-4096-8e88-aab5ccdd6a90','登六和塔','艾性夫','宋','宋诗','song-poetry','','[]','崒峍浮圖插翠微，長連山影浸江湄。',64,'全唐诗/poet.song.247000.json','["崒峍浮圖插翠微，長連山影浸江湄。", "地高直見海窮處，天近先知日上時。", "香繞五雲宮裏夢，墨濃千佛頂頭詩。", "無風最喜鈴相語，切莫丁寧說秀支。"]'),
('44aefa5f-3bd2-40c6-bc91-69eedff7caa5','雜興五首  其一','艾性夫','宋','宋诗','song-poetry','','[]','玉兔不可罝，金烏不可籠。',84,'全唐诗/poet.song.247000.json','["玉兔不可罝，金烏不可籠。", "蜉蝣問鶴年，槿花笑松風。", "郿塢不救卓，銅山終餓通。", "玉兒誤東昏，綠珠累石崇。", "誰信貪心苦，俄成旋踵空。", "既無九轉丹，又非千歲翁。", "榮枯同一夢，螻蟻大槐中。"]'),
('3d68aa70-6d4d-4bc9-91f3-629dfad78494','雜興五首  其二','艾性夫','宋','宋诗','song-poetry','','[]','雲路不可梯，天河不可航。',72,'全唐诗/poet.song.247000.json','["雲路不可梯，天河不可航。", "人間心不足，意外事難量。", "瑶水宴周穆，月宮遊明皇。", "干戈驚駿足，鼙鼓駭霓裳。", "豈不窮歡樂，那知成禍殃。", "神仙竟何益，撫卷空凄凉。"]'),
('f6086162-70f3-4cdf-8abc-a1fe64818093','雜興五首  其三','艾性夫','宋','宋诗','song-poetry','','[]','蠶絲自纏縛，蛛網費經營。',60,'全唐诗/poet.song.247000.json','["蠶絲自纏縛，蛛網費經營。", "智巧同役役，得喪何不平。", "益人者損己，害物乃利生。", "一抱仰天愧，一甘就鑊烹。", "禍淫與福善，此理未分明。"]'),
('8f9d4527-debf-4048-8be2-c20dd15bf090','雜興五首  其四','艾性夫','宋','宋诗','song-poetry','','[]','蟻國槐爲穴，蜂衙蜜作房。',60,'全唐诗/poet.song.247000.json','["蟻國槐爲穴，蜂衙蜜作房。", "採花與旋磨，辛苦知尊王。", "胡爲梟獍生，思食父母腸。", "彼微有尊卑，此大相滅亡。", "物情有不齊，使我心憂傷。"]'),
('12754384-3536-4341-8127-524eca2cfbd3','雜興五首  其五','艾性夫','宋','宋诗','song-poetry','','[]','孤鳳不食粟，舉世無琳琅。',60,'全唐诗/poet.song.247000.json','["孤鳳不食粟，舉世無琳琅。", "渴去飲湘水，饑來卧首陽。", "雲天遲羽翼，歲晚飽風霜。", "棲棲豈不苦，羞與燕雀翔。", "安得九成樂，來儀薰風廊。"]'),
('4f4b3bca-8dbb-4759-8da2-d6a1bce9e806','樓中故書連被兵盡亡去','艾性夫','宋','宋诗','song-poetry','','[]','樓無長物只遺編，直當山翁負郭田。',64,'全唐诗/poet.song.247000.json','["樓無長物只遺編，直當山翁負郭田。", "累世相傳俱掃地，斯文忽喪豈非天。", "不歸老子茶腸裏，知墮誰家醤瓿邊。", "我固道窮書更厄，西風危涕倍潸然。"]'),
('10d77187-4853-4751-a049-be9735273296','醫僧洪淡寮見示金剛經解集驗方村寺清規皆自著也詩以歸之','艾性夫','宋','宋诗','song-poetry','','[]','不作人間肉食僧，霜髭茁茁骨稜稜。',64,'全唐诗/poet.song.247000.json','["不作人間肉食僧，霜髭茁茁骨稜稜。", "釋經妙在一轉語，療病良於三折肱。", "處寺有規能縛律，即心是佛不傳燈。", "胸中歷歷前朝事，說到西頭氣拂膺。"]'),
('1349fcbd-19f4-4b16-9118-4ed1da6c53a6','書東坡詩案','艾性夫','宋','宋诗','song-poetry','','[]','風刺成章昔有之，姦人捃拾欲何爲。',64,'全唐诗/poet.song.247000.json','["風刺成章昔有之，姦人捃拾欲何爲。", "先生定以名招禍，自古何曾獄勘詩。", "下石幾令無地死，誣金獨幸有天知。", "明朝謫向黄州去，又是東坡覓句時。"]'),
('80226759-f0ea-4c47-b652-c597d3138c7a','送環洲先羅憲卿','艾性夫','宋','宋诗','song-poetry','','[]','馬耳蕭蕭雪擁裘，亂山南下是處州。',64,'全唐诗/poet.song.247000.json','["馬耳蕭蕭雪擁裘，亂山南下是處州。", "自從天地生吟骨，何處江山無脚頭。", "空有夢隨東野去，可無言送子長遊。", "白雲在望頻回首，珍重歸期記麥秋。"]'),
('f76651ba-155e-4a80-9c58-b469ac079998','山樓秋夜','周嵩','宋','宋诗','song-poetry','','[]','孤形侶雲漢，凉思滿山樓。',48,'全唐诗/poet.song.247000.json','["孤形侶雲漢，凉思滿山樓。", "高樹自吟籟，清樽聊賞幽。", "檢書初志動，撫劍壯心留。", "蟋蟀不知事，喧聲何不休。"]'),
('a131b0eb-a184-4057-b364-382779d9a131','訟風','周嵩','宋','宋诗','song-poetry','','[]','西風雲戰急，殺氣橫干戈。',48,'全唐诗/poet.song.247000.json','["西風雲戰急，殺氣橫干戈。", "有客懷鄉坐，無鄰送酒過。", "布袍欣豫暖，凍筆苦新呵。", "默訴玄冥后，天涯征戍多。"]'),
('42c0582a-540f-4be3-8112-deab3ce1a08c','近聞','周嵩','宋','宋诗','song-poetry','','[]','斜陽淡紫弄暉暉，澤國霜前落木稀。',64,'全唐诗/poet.song.247000.json','["斜陽淡紫弄暉暉，澤國霜前落木稀。", "遠憶東皇沉羽駕，近聞山鬼泣蘿衣。", "畫谿黑夜雙龍吼，霞幕清秋一鶴飛。", "送盡海天千里目，伶仃洋裏有誰歸。"]'),
('eca0b77f-7e28-4257-b325-49f8182030a5','晚菊','周嵩','宋','宋诗','song-poetry','','[]','落日西風弄晚晴，東籬曲曲燦金英。',32,'全唐诗/poet.song.247000.json','["落日西風弄晚晴，東籬曲曲燦金英。", "先生茅舍終年淡，惟有寒芳不世情。"]'),
('8a5463ae-da34-49be-a0da-d28f4a5c5de1','憶匡山','俞躍龍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬一掬裏，雪眼嗽天根。',48,'全唐诗/poet.song.247000.json','["匡廬一掬裏，雪眼嗽天根。", "時落凍僧影，不逢飛鳥痕。", "夢中石門路，月照柴桑村。", "春水自茲遠，幽期空復存。"]'),
('620d3590-9e23-49bc-b169-ca18e8ca2914','述懷二首  其一','孫璉','宋','宋诗','song-poetry','','[]','少也不諧俗，老去益美閒。',60,'全唐诗/poet.song.247000.json','["少也不諧俗，老去益美閒。", "百草生已綠，春雨滿南山。", "朝朝荷鋤去，既夕驅牛還。", "生長茆簷下，貧賤甚獨安。", "但願桑麻長，優游足歲年。"]'),
('51edfc6a-4432-4eaa-8957-579ea5126b87','述懷二首  其二','孫璉','宋','宋诗','song-poetry','','[]','坐倦秋樹根，攝衣步前丘。',48,'全唐诗/poet.song.247000.json','["坐倦秋樹根，攝衣步前丘。", "橫河澹如練，破月西南流。", "獨持一尊酒，悠然發清謳。", "俯仰無不足，吾生焉所求。"]'),
('d13ecd9f-18c6-4275-81ee-95721179f6fc','瑞跡山','陳自新','宋','宋诗','song-poetry','','[]','雨過山溪生虎迹，雲歸岩洞長龍威。',32,'全唐诗/poet.song.247000.json','["雨過山溪生虎迹，雲歸岩洞長龍威。", "煙鐘古寺敲殘日，樵笛一聲江鳥飛。"]'),
('b8db5c0a-62a5-47f4-9b44-1302a89a76e0','棲雲龍潭','陳自新','宋','宋诗','song-poetry','','[]','石刻仙潭神筆題，我來觀感仰靈祠。',64,'全唐诗/poet.song.247000.json','["石刻仙潭神筆題，我來觀感仰靈祠。", "千年墨浸東風裏，一掬吟魂秋水湄。", "日暖香生起鸞鳳，月明影動舞蛟螭。", "飛鸞白鶴俱王土，底事人家盡黍離。"]'),
('3adca751-631e-4c35-87f7-b64a4515385c','瑞龍寺','陳自新','宋','宋诗','song-poetry','','[]','寺外寒流玉一泓，白雲如練掛危層。',32,'全唐诗/poet.song.247000.json','["寺外寒流玉一泓，白雲如練掛危層。", "青山遶屋柴門掩，只見梅花不見僧。"]'),
('2b87200c-245a-4679-b62b-9bfb2770cbad','金峰寺','陳自新','宋','宋诗','song-poetry','','[]','金峰寺外望藍橋，只尺溪山路許遥。',32,'全唐诗/poet.song.247000.json','["金峰寺外望藍橋，只尺溪山路許遥。", "世事昏人心似醉，倚欄無計遣愁消。"]'),
('38717fea-1735-4e96-8759-b2ec00346ece','坐歎','陳自新','宋','宋诗','song-poetry','','[]','琴聲意似泉聲淡，劍氣威如霜氣雄。',32,'全唐诗/poet.song.247000.json','["琴聲意似泉聲淡，劍氣威如霜氣雄。", "世事關心憂不寐，蕭蕭白髪月明中。"]'),
('60597071-d431-4683-8e11-e21c8a6a07e3','釣月樓','王南美','宋','宋诗','song-poetry','','[]','居士作層樓，不愛風花雪。',24,'全唐诗/poet.song.247000.json','["居士作層樓，不愛風花雪。", "待得野雲收，只釣溪邊月。"]'),
('0b6b3dec-14d7-4ee9-9bcd-861dc90d1613','湖上','黄宏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山環臺榭水環堤，雪月風烟是處宜。',32,'全唐诗/poet.song.247000.json','["山環臺榭水環堤，雪月風烟是處宜。", "豢養宴安成鴆毒，西湖只合比西施。"]'),
('ea419a99-a017-4b98-86be-4772837981ea','過天姥嶺','黄宏','宋','宋诗','song-poetry','','[]','天姥連天橫，我過如牛脊。',72,'全唐诗/poet.song.247000.json','["天姥連天橫，我過如牛脊。", "乃知李謫仙，夢遊言過實。", "徐生亦好奇，請問劉阮迹。", "安知古仙人，太平入鬼域。", "妖狐花滿頭，媚人强求匹。", "流杯飲胡麻，磊塊皆沙礫。"]'),
('8cc8dc0e-48e4-4130-b5d1-6b8bd10b7f81','書歎','黄宏','宋','宋诗','song-poetry','','[]','文章關氣運，要與理亂符。',120,'全唐诗/poet.song.247000.json','["文章關氣運，要與理亂符。", "誰知周赧末，猶勝秦皇初。", "向來五星聚，奎躔遂華敷。", "南北起周召，東西擬歐蘇。", "豈惟一時盛，萬世垂楷模。", "我雖季世産，聞道端不誣。", "豈有蒼精劍，鑄自燒葉爐。", "豈有軒轅鼎，散入蠻娘沽。", "久幽世或有，速售理則無。", "夕陽淡茅塢，荒烟正模糊。"]'),
('ad0abb6c-79c3-4bad-a0fc-4e9f9417663f','呈蕭大帥','黄宏','宋','宋诗','song-poetry','','[]','太掖勾陳瑞靄浮，宮花時綴五雲裘。',64,'全唐诗/poet.song.247000.json','["太掖勾陳瑞靄浮，宮花時綴五雲裘。", "湛盧光截飛狐月，繁弱風號涿鹿秋。", "蟣蝨幾曾生介胄，貂蟬又見出兜鍪。", "南來穩作風流帥，日上榑桑瘴霧收。"]'),
('2c647976-6d40-42cf-8d66-ddac6ca7b52f','題擬虹橋','黄宏','宋','宋诗','song-poetry','','[]','父老橋邊問我公，笑談能辦濟水功。',64,'全唐诗/poet.song.247000.json','["父老橋邊問我公，笑談能辦濟水功。", "天光分碧一千頃，晴影飛虹二百弓。", "好與諸公來賞月，曾知此地亦垂虹。", "乘風似有驚人語，壓倒滄浪亭上翁。"]'),
('2145f3d8-9044-4992-bdd5-a32d3ad975f9','松徑','郭巖','宋','宋诗','song-poetry','','[]','一逕深且紆，森森蔭松柏。',48,'全唐诗/poet.song.247000.json','["一逕深且紆，森森蔭松柏。", "清風池上來，幽思與之發。", "逸響諧素琴，凉陰散清帙。", "弘景或可邀，高懷共披豁。"]'),
('1e2b1dfa-d923-4688-be87-c95cf6e03056','過從叔猥園','郭巖','宋','宋诗','song-poetry','','[]','風流吾大阮，嘉遁狎鷗盟。',48,'全唐诗/poet.song.247000.json','["風流吾大阮，嘉遁狎鷗盟。", "築得野亭曠，到來雲水清。", "斜林收橡實，涇水給茶鐺。", "翻笑支公拙，買山空得名。"]'),
('39fd4160-1f79-43c4-a68d-2219e2a63b8f','顧况讀書堆','郭巖','宋','宋诗','song-poetry','','[]','昔人何處讀書聲，此地猶存舊日名。',64,'全唐诗/poet.song.247000.json','["昔人何處讀書聲，此地猶存舊日名。", "衰草閉門黄葉冷，香林藏硤碧雲橫。", "地連踰李山河壯，江遶吳淞日夜鳴。", "陳迹已憐荒沒久，憑欄惆悵有餘情。"]'),
('8a8c663b-2177-42b0-a98e-3daf1a03ea30','寄無著','釋清壹','宋','宋诗','song-poetry','','[]','逢人稱宿臘，玄解少人知。',48,'全唐诗/poet.song.247000.json','["逢人稱宿臘，玄解少人知。", "俗濁唯貪隠，禪高不礙詩。", "水邊秋杖屨，石上雪須眉。", "雞犬添鄰曲，還同賦紫芝。"]'),
('f42e6c92-5899-4074-8b30-c105d2cec0fd','寄萬先輩','釋清壹','宋','宋诗','song-poetry','','[]','歸從衡岳此身清，老校群書眼倍明。',64,'全唐诗/poet.song.247000.json','["歸從衡岳此身清，老校群書眼倍明。", "白屋有田供伏臘，青雲無夢到公卿。", "頻挑野菜招僧至，少著深衣入郭行。", "早歲自嗟行役遠，失將詩律問先生。"]'),
('5e687733-9270-4b15-9b37-3a71afcdace0','題{山昂}山禹廟石柱','徐雪廬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭之陰小山幽，百靈雄衛來高邱。',112,'全唐诗/poet.song.247000.json','["洞庭之陰小山幽，百靈雄衛來高邱。", "我當十月值亂離，携家遠逐湖之洲。", "湖光接天晚浪靜，樹色照野晴雲浮。", "霜黄林頭橘柚熟，日冷波底蛟龍愁。", "北方兵馬想已到，南國城郭誰能收。", "我今買酒且消憂，醉舞拔劍揮斗牛。", "會須投筆去封侯，斬取盜賊清南州。"]'),
('07fb9035-70ea-458e-9630-f524031b3751','題海月巖  其一','趙東山','宋','宋诗','song-poetry','','[]','踏盡崔嵬倚石門，海風山月滿巖巒。',64,'全唐诗/poet.song.247000.json','["踏盡崔嵬倚石門，海風山月滿巖巒。", "自然仙室依蓬島，不覺人寰變廣寒。", "千載揚塵安可測，一杯對景且爲歡。", "崖前浴日皆詩境，喚醒東坡仔細看。"]'),
('f75e4977-95f9-48cb-9d7f-feef6a8df957','題海月巖  其二','趙東山','宋','宋诗','song-poetry','','[]','架巖鑿石有規模，不學桃源舊畫圖。',64,'全唐诗/poet.song.247000.json','["架巖鑿石有規模，不學桃源舊畫圖。", "亭豁人稀林鳥樂，錫飛天老野雲孤。", "雨餘石井泉深淺，煙淡虎門山有無。", "說與山靈莫分別，從教仙窟著浮屠。"]'),
('4d693f2b-becc-44c3-b9da-967c0eb525cf','句','趙東山','宋','宋诗','song-poetry','','[]','風雨送迎地，別離多少人。',12,'全唐诗/poet.song.247000.json','["風雨送迎地，別離多少人。"]'),
('131d75dc-5505-4b24-b4d5-99818948c2a0','志怪','陳古遇','宋','宋诗','song-poetry','','[]','沉沉萬仞淵，下有驪龍珠。',144,'全唐诗/poet.song.247000.json','["沉沉萬仞淵，下有驪龍珠。", "佩之壽松喬，售之富侔都。", "貪夫臨淵羨，重利輕微軀。", "百金不龜藥，千金水犀珠。", "丹砂與翠羽，陸産海所無。", "齎裝濤浪中，巨闕光炯如。", "粲粲兩青童，駢肩問所須。", "再拜上珠翠，敢問龍起居。", "青童粲玉齒，雲龍卧玄虛。", "爲君窮珠山，鞭雲取長驅。", "雲急風更惡，蒼梧來時徐。", "丹藥兩須失，哀哉飽鯨魚。"]'),
('6559defc-7965-46a2-9873-d21ccd6d028a','莫飲酒','陳古遇','宋','宋诗','song-poetry','','[]','莫飲酒，酒醒駡人繞盆走。',56,'全唐诗/poet.song.247000.json','["莫飲酒，酒醒駡人繞盆走。", "酒香入腦頭欲旋，駡聲漸低涎落口。", "草履有長短，伸脚可試否。", "未論身後五車書，已隨生前一杯酒。"]'),
('e1648dc5-a866-4f61-ac0c-896109e76bf4','馬別主','陳古遇','宋','宋诗','song-poetry','','[]','馬別主兮，涕泗霑臆。',40,'全唐诗/poet.song.247000.json','["馬別主兮，涕泗霑臆。", "士別主兮，喜見顔色。", "于嗟馬兮，胡戀而駐。", "于嗟士兮，胡棄而背。"]'),
('d7335d9b-a062-45c3-9b50-8ec5e28fe53b','讀蘭皋先生集','繆志道','宋','宋诗','song-poetry','','[]','自少從諸老，如公能幾人。',48,'全唐诗/poet.song.247000.json','["自少從諸老，如公能幾人。", "斵輪推老手，削鐻妙驚人。", "人物九泉古，詩名千載新。", "矮窗遺稿在，一讀一沾巾。"]'),
('0f69eb19-0de4-4412-a486-c526e1e71afe','寄友','王安之','宋','宋诗','song-poetry','','[]','憶昔青燈夜對牀，冷猿聲裏早梅香。',64,'全唐诗/poet.song.247000.json','["憶昔青燈夜對牀，冷猿聲裏早梅香。", "一從去櫂衝寒雪，幾度憑闌到夕陽。", "秋思漸于蟬外覺，別愁空入雁邊長。", "梧桐解得離人意，不遣西風葉盡黄。"]'),
('193b7974-0923-4317-b1fc-7526ca3e207d','題凈明寺','周日明','宋','宋诗','song-poetry','','[]','幽幽古寺中，石徑受苔封。',48,'全唐诗/poet.song.247000.json','["幽幽古寺中，石徑受苔封。", "白日無一事，青山只四峰。", "野蔬爲佛供，澗水替人舂。", "僧因煎新茗，林間拾墜松。"]'),
('2c29c2ea-9863-430a-936d-abb4693ce988','經賈秋壑故第','潘斾','宋','宋诗','song-poetry','','[]','相業如何不到頭，諸公歷歷頌伊周。',64,'全唐诗/poet.song.247000.json','["相業如何不到頭，諸公歷歷頌伊周。", "夢迷葛嶺酣歌夜，鬼哭樊城血戰秋。", "誤國正須憂大厦，覆師寧忍駕孤舟。", "木棉庵裏催歸魄，誰掩湖山富貴羞。"]'),
('3955c045-c473-4de1-9324-21a3b08eb146','廣潤寺新寮','釋自南','宋','宋诗','song-poetry','','[]','客不赴齋招，冥心坐寂寥。',48,'全唐诗/poet.song.247000.json','["客不赴齋招，冥心坐寂寥。", "青山若厭看，白日也難消。", "鷺起衝荷葉，蟲行蝕菊苗。", "何年稱老宿，來住此間寮。"]'),
('26014679-1552-4a03-94ea-1b92d91a4b5d','嵩山下至德祠','吳文忠','宋','宋诗','song-poetry','','[]','脫蹝岐陽迹已幽，默全忠孝復何求。',64,'全唐诗/poet.song.247000.json','["脫蹝岐陽迹已幽，默全忠孝復何求。", "文身幸獲辭姬祚，端委猶能化列侯。", "無語存商先叩馬，有心迓命待歸牛。", "象賢再見延陵季，十字碑題至德侔。"]'),
('36290330-df0c-41f2-b83b-c7b370f58f3b','石樓','朱南金','宋','宋诗','song-poetry','','[]','蒙茸披盡自成蹊，兩扇巖扉向日齊。',32,'全唐诗/poet.song.247000.json','["蒙茸披盡自成蹊，兩扇巖扉向日齊。", "說與白雲休鎖鑰，留將千古指人迷。"]'),
('cacbf5c6-7b3c-48e8-83ec-548636e8a47b','瀑布灣','黄仲','宋','宋诗','song-poetry','','[]','飛來瀑布破青山，遂作寒流水一灣。',32,'全唐诗/poet.song.247000.json','["飛來瀑布破青山，遂作寒流水一灣。", "民庶只疑投石效，豈知龍卧在其間。"]'),
('8e1999b7-e273-4e25-8257-02aa5152fa05','襄陽行','鮑輗','宋','宋诗','song-poetry','','[]','今日何日春氣柔，東城騎馬花綢繆。',96,'全唐诗/poet.song.247000.json','["今日何日春氣柔，東城騎馬花綢繆。", "爲君停馬一呼酒，花前倒披紫綺裘。", "玉脂汎濫魚鳥飫，歌舞倦矣蛾眉愁。", "千金萬壽好賓主，今我不樂歲如流。", "豈比世上狂馳子，一語不合行掉頭。", "嗚呼天倫古所定，非有大故寧相尤。"]'),
('b539cc7e-f9f7-4939-8b5b-d0b2b059dcae','天馬','鮑輗','宋','宋诗','song-poetry','','[]','天馬抱奇相，緊骨瞳方明。',108,'全唐诗/poet.song.247000.json','["天馬抱奇相，緊骨瞳方明。", "出入百萬中，有如一鳥輕。", "宇宙莽超踏，風雲慘經營。", "獨倚雄傑態，蕭蕭隨北征。", "朝飲南海頭，夕秣乃幽并。", "失主坐黯淡，別群奮長鳴。", "豈無輕俠兒，金羈懸朱纓。", "但感束帛義，不忍負死生。", "低頭爲君老，喑喑萬里情。"]'),
('e6fc1b01-51c5-498c-8c92-ebda18285f43','重到錢唐  其一','鮑輗','宋','宋诗','song-poetry','','[]','生死雙飛正可憐，若爲白髪上征船。',32,'全唐诗/poet.song.247000.json','["生死雙飛正可憐，若爲白髪上征船。", "未應分手江南去，更有春光七十年。"]'),
('aac46538-2bae-4e4c-a71a-ee2ab7c6f6fb','重到錢唐  其二','鮑輗','宋','宋诗','song-poetry','','[]','無頼山光疊疊青，玉魚金盌早飄零。',32,'全唐诗/poet.song.247000.json','["無頼山光疊疊青，玉魚金盌早飄零。", "冷思禹穴真奇事，千古衣冠託杳冥。"]'),
('88706bd9-5ab6-49d0-acae-3bf613d36efd','重到錢唐  其三','鮑輗','宋','宋诗','song-poetry','','[]','萬家歌舞送浮生，曾有涓埃答太平。',32,'全唐诗/poet.song.247000.json','["萬家歌舞送浮生，曾有涓埃答太平。", "猨鶴蟲沙天始定，不須辛苦怨南征。"]'),
('89c9f7ee-62cf-4392-a9b7-7bba719f0b7d','重到錢唐  其四','鮑輗','宋','宋诗','song-poetry','','[]','聞道深春雪打圍，誰憐身上藕絲衣。',32,'全唐诗/poet.song.247000.json','["聞道深春雪打圍，誰憐身上藕絲衣。", "莫憂白璧成塵土，解逐南風萬里歸。"]'),
('daa9c48e-e9c6-43d4-b0bf-7b60c59ad6c8','重到錢唐  其五','鮑輗','宋','宋诗','song-poetry','','[]','惟有寒潮不世情，朝朝莫莫過空城。',32,'全唐诗/poet.song.247000.json','["惟有寒潮不世情，朝朝莫莫過空城。", "百年車馬閶門外，獨被春風草又生。"]'),
('12b6f959-ef54-478d-8e81-327a5fa07f4b','九齡行','曾澈','宋','宋诗','song-poetry','','[]','我生九齡氣食牛，喑嗚頓挫無匹儔。',96,'全唐诗/poet.song.247000.json','["我生九齡氣食牛，喑嗚頓挫無匹儔。", "白雲無根起天末，一身萬事同悠悠。", "低頭拱手事先覺，談笑未了成仇讎。", "一譽不足勝百毀，言語起滅如浮漚。", "聖賢可與知者道，麟鳳豈在山中遊。", "蘧然夢覺大槐國，江花昨夜生凉秋。"]'),
('5ca2962d-b55f-4720-adc4-8f5bdce988b8','甘泉洞','趙澤祖','宋','宋诗','song-poetry','','[]','銀河瀉落萬山巔，玉界遥馳一道泉。',64,'全唐诗/poet.song.247000.json','["銀河瀉落萬山巔，玉界遥馳一道泉。", "夜浴丹沙浮暖氣，曉凝寒碧沁晴烟。", "靈泉透海流香細，雪液澄虛抱影圓。", "三咽只因凡骨換，坐臨盤石看飛錢。"]'),
('fd28c2c3-0a3a-444d-a9f9-d201b3c8df77','署中書懷','趙澤祖','宋','宋诗','song-poetry','','[]','庭下幽花照眼醒，綠陰成幄晚風清。',32,'全唐诗/poet.song.247000.json','["庭下幽花照眼醒，綠陰成幄晚風清。", "何時拋擲銅章去，小艇烟波弄月明。"]'),
('7c517e94-7e07-4b42-b38a-633b393f3a0d','春晚三客同出郊歸途甚醉','潘獻可','宋','宋诗','song-poetry','','[]','尋友逢三益，追歡且一時。',48,'全唐诗/poet.song.247000.json','["尋友逢三益，追歡且一時。", "買魚呼野艇，沽酒認村旗。", "暫覺行歌樂，何妨醉舞僛。", "牧兒休駭愕，橫笛且須吹。"]'),
('aa7a3f14-bbc3-4746-8ee4-fa5f18aaeb0d','四月十八日之桐川','潘獻可','宋','宋诗','song-poetry','','[]','白鳥蒼烟外，黄鸝綠樹間。',48,'全唐诗/poet.song.247000.json','["白鳥蒼烟外，黄鸝綠樹間。", "雨晴初有路，雲薄不藏山。", "村酒成孤酌，征鞍厭獨攀。", "日長人自倦，更覺馬蹄慳。"]'),
('212615b1-8b17-40c1-9df0-a1c7ced2dac5','固城懷歸','潘獻可','宋','宋诗','song-poetry','','[]','稅駕蠶將老，旋車燕欲歸。',48,'全唐诗/poet.song.247000.json','["稅駕蠶將老，旋車燕欲歸。", "人情秋思薄，酒力晚風微。", "青鬢愁邊改，丹心老去違。", "吾廬元不遠，望斷白雲飛。"]'),
('d2765363-426b-45b1-ab28-1fabd856f8b2','山樓枕上','潘獻可','宋','宋诗','song-poetry','','[]','山近寒偏早，愁多睡不濃。',48,'全唐诗/poet.song.247000.json','["山近寒偏早，愁多睡不濃。", "鴉啼半夜月，鶴唳五更風。", "曉接殘燈裏，吟成落葉中。", "塵埃今已厭，懶聽上方鍾。"]'),
('7115f62d-4f3c-4725-8f88-fd67aa5dafc8','寧川道中','潘獻可','宋','宋诗','song-poetry','','[]','十日爲山客，今朝問水程。',48,'全唐诗/poet.song.247000.json','["十日爲山客，今朝問水程。", "沙橫疑港斷，灘迅覺舟輕。", "遠近村舂合，高低漁火明。", "回頭忽蒼莽，一望一傷情。"]'),
('be59196b-092f-4e24-8dae-dfd68b12dc20','端居','潘獻可','宋','宋诗','song-poetry','','[]','竹院秋逾靜，柴門晝不開。',48,'全唐诗/poet.song.247000.json','["竹院秋逾靜，柴門晝不開。", "病先携老去，懶漸逐衰來。", "莫遣新緣結，都將舊念灰。", "川魚與雲鳥，從此莫驚猜。"]'),
('534a207e-6f2e-471c-ad50-8bf1d7fc3b04','初至莊舍','潘獻可','宋','宋诗','song-poetry','','[]','鷺立汀沙晚，牛眠徑草深。',48,'全唐诗/poet.song.247000.json','["鷺立汀沙晚，牛眠徑草深。", "黄花浮荇带，紅葉下楓林。", "客路溪中斷，柴門水半侵。", "一廛收歲晚，聊復此幽尋。"]'),
('1259afcd-5354-4dd0-947f-26a4c1aaac94','寓舍偶題','潘獻可','宋','宋诗','song-poetry','','[]','習嬾身無用，幽偏性所欣。',48,'全唐诗/poet.song.247000.json','["習嬾身無用，幽偏性所欣。", "校書隨馬隊，臨帖愛鵝群。", "公子悲春草，佳人隔暮雲。", "北山歸計决，未信有移文。"]'),
('50e58f82-3d99-4476-b6a4-3dd48b5e51eb','遊妙行寺','俞本','宋','宋诗','song-poetry','','[]','中峰蒼翠裏，微徑入禪關。',48,'全唐诗/poet.song.247000.json','["中峰蒼翠裏，微徑入禪關。", "石座香塵積，蓮池苔蘚班。", "鶴盤雲在樹，龍過雨侵山。", "會得規中意，怡然一解顔。"]'),
('0b70a329-c6c2-49ee-af4f-beb1846bf25b','笠澤亭','劉嘉謨','宋','宋诗','song-poetry','','[]','荷笠扁舟上，持綸巨澤中。',24,'全唐诗/poet.song.247000.json','["荷笠扁舟上，持綸巨澤中。", "無勞問名字，便是此亭公。"]'),
('8528b309-8073-4c85-abae-55ac08513179','北津口水閣','劉嘉謨','宋','宋诗','song-poetry','','[]','沉沉卧虹底，小閣貼平湖。',24,'全唐诗/poet.song.247000.json','["沉沉卧虹底，小閣貼平湖。", "魚戲幾堪掬，鷗馴欲就呼。"]'),
('ba494a29-046a-441e-9912-d932274db7f2','大明橋','劉嘉謨','宋','宋诗','song-poetry','','[]','東望扶桑路，迢迢幾萬程。',24,'全唐诗/poet.song.247000.json','["東望扶桑路，迢迢幾萬程。", "滄浪將盡處，忽見大明生。"]'),
('8dce37ac-8c3f-49e1-965c-6f17cafad2e7','萬頃橋','劉嘉謨','宋','宋诗','song-poetry','','[]','巨浸莽無極，聊爲萬頃看。',24,'全唐诗/poet.song.247000.json','["巨浸莽無極，聊爲萬頃看。", "世無黄叔度，君試倚闌干。"]'),
('1a8322c5-4bd3-4fd1-9bd7-f2d74822b535','定海橋','劉嘉謨','宋','宋诗','song-poetry','','[]','昔日松江上，潮翻定海來。',24,'全唐诗/poet.song.247000.json','["昔日松江上，潮翻定海來。", "而今舊橋水，不到半江回。"]'),
('b7bc356d-bd61-4952-bf49-4eaa83d7af7e','顧公祠','劉嘉謨','宋','宋诗','song-poetry','','[]','博洽傾當世，江東孔子儒。',24,'全唐诗/poet.song.247000.json','["博洽傾當世，江東孔子儒。", "荒墟訪遺廟，老稚輒名呼。"]'),
('720e98e3-5f79-43a7-a37d-dee9bd7e5749','櫟園','吳龍起','宋','宋诗','song-poetry','','[]','櫟園依古寺，景物久凄凉。',48,'全唐诗/poet.song.247000.json','["櫟園依古寺，景物久凄凉。", "荆棘無人翦，亭臺逐處荒。", "數禽棲曲沼，獨犬吠空堂。", "惆悵梅花發，憑誰管暗香。"]'),
('2dcdf230-10bf-41e3-a8d3-1920006cec51','秋興','吳龍起','宋','宋诗','song-poetry','','[]','定是憑高易得愁，客懷牢落怕登樓。',32,'全唐诗/poet.song.247000.json','["定是憑高易得愁，客懷牢落怕登樓。", "不知昨夜梧桐雨，添得闌干幾許秋。"]'),
('710899b6-d15f-4fe4-bba0-82621c1e3f59','玉馬山','朱克家','宋','宋诗','song-poetry','','[]','水石嵌空山犖确，瘦藤扶上青雲幕。',192,'全唐诗/poet.song.247000.json','["水石嵌空山犖确，瘦藤扶上青雲幕。", "平川一望渺無際，東疑嵎夷北朔漠。", "駕天疊巘輸翠浪，奔野細流橫雪槊。", "疏峰點點雁聚沙，密嶼喁喁魚縱壑。", "一江凈綠遶書元，幾隴斷畦成卦剝。", "乍驚漁唱出烟靄，時聽村舂動籬落。", "幽遐異景爭指說，老眼苦難覓渺邈。", "夜間支枕掛銀窗，閃閃星河手可摸。", "何年標名稱玉馬，蹴踏風雲跨寥廓。", "更連三十六奇峰，削玉排青相間錯。", "偶因佳友得壯觀，俗慮塵襟頓疏瀹。", "翛然物外豈非仙，不須更羨遼東鶴。"]'),
('93d79450-1571-4e07-9a61-fce88a182a65','掬水月在手','朱少游','宋','宋诗','song-poetry','','[]','十指纖纖弄碧波，分明掌上見姮娥。',32,'全唐诗/poet.song.247000.json','["十指纖纖弄碧波，分明掌上見姮娥。", "不知李白當年醉，曾向江邊捉得麽。"]'),
('3ecf2f56-8898-4340-85c2-8f61c15de7bd','芭蕉','朱少游','宋','宋诗','song-poetry','','[]','剪得西園一片青，故將來此惱詩情。',32,'全唐诗/poet.song.247000.json','["剪得西園一片青，故將來此惱詩情。", "怪來昨夜窗前雨，減却瀟瀟數點聲。"]'),
('cfc46c9f-a2b4-496b-8afe-233ce448b3f9','寓錢塘得鄉人消息','張眇','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西子湖邊放鶴仙，幾回同醉木蘭船。',64,'全唐诗/poet.song.247000.json','["西子湖邊放鶴仙，幾回同醉木蘭船。", "相思東路一千里，憶別西風十四年。", "遠信有時憑雁寄，新詩近日頼僧傳。", "不須更問垂綸叟，已有霜痕到鬢邊。"]'),
('5cdc59d3-3dc8-4cfb-ad00-454e160e1166','陪秋山相公遊大滌洞天一庵夜宿感夢','鄭斗煥','宋','宋诗','song-poetry','','[]','天柱清游尾使星，筍輿軋軋入山深。',64,'全唐诗/poet.song.247000.json','["天柱清游尾使星，筍輿軋軋入山深。", "龍行雨去泉花定，鶴叫雲來木葉陰。", "松石已安通夕寐，江湖空老百年心。", "圓冠方袂何仙子，夢里將詩索共吟。"]'),
('2933e2f7-6238-4d38-904a-fb2855a1d4a5','題廬陵義士傳','郭彥章','宋','宋诗','song-poetry','','[]','淮海風迴吹血腥，青原不改舊時青。',32,'全唐诗/poet.song.247000.json','["淮海風迴吹血腥，青原不改舊時青。", "中朝將帥論功賞，不及江南一白丁。"]'),
('1cbd1d86-1f09-4d40-8c7a-aeb850546ffc','題新淦劉貞女傳','郭彥章','宋','宋诗','song-poetry','','[]','百年節義仗英豪，一死翻憐女子高。',32,'全唐诗/poet.song.247000.json','["百年節義仗英豪，一死翻憐女子高。", "不敢高歌題卷上，轉喉恐觸舊官曹。"]'),
('d4695880-b80b-49ff-abf5-1513d629c16d','詠史','楊再十一君','宋','宋诗','song-poetry','','[]','張良大父父，相韓五世君。',96,'全唐诗/poet.song.247000.json','["張良大父父，相韓五世君。", "報仇誤一擊，佐命籌三軍。", "滅秦復誅項，興漢稱元勳。", "始終心爲韓，義烈千載聞。", "吾家世臣宋，紱冕興如雲。", "於今雖爲庶，義不忘宋恩。", "國亡幸免死，忍復干祿云。", "恥爲膚敏士，寧作殷頑民。"]'),
('8c615f15-473a-40b3-a390-5da11b9e11a4','書感  其一','楊再十一君','宋','宋诗','song-poetry','','[]','楓江渡口草淒淒，桃浦橋邊夕照低。',32,'全唐诗/poet.song.247000.json','["楓江渡口草淒淒，桃浦橋邊夕照低。", "惟有舊家雙燕子，年年飛繞綠楊隄。"]'),
('8023b85d-15bc-4312-8e18-a86afdb1a403','書感  其二','楊再十一君','宋','宋诗','song-poetry','','[]','深湖兩岸白雲秋，蘆荻花深隠釣舟。',32,'全唐诗/poet.song.247000.json','["深湖兩岸白雲秋，蘆荻花深隠釣舟。", "回首平原風浪急，却憐江海是安流。"]'),
('eff3c63f-f5b5-4283-b849-29024757c080','書感  其三','楊再十一君','宋','宋诗','song-poetry','','[]','潦倒江南一布衣，家貧歲晚寸心違。',32,'全唐诗/poet.song.247000.json','["潦倒江南一布衣，家貧歲晚寸心違。", "不堪倚杖楓江路，手種青松大十圍。"]'),
('7166d0d6-748c-410e-b67f-4bddae9618f2','夜坐','楊再十一君','宋','宋诗','song-poetry','','[]','竹窗吹雨夜瀟瀟，獨擁寒鑪歎寂寥。',32,'全唐诗/poet.song.247000.json','["竹窗吹雨夜瀟瀟，獨擁寒鑪歎寂寥。", "坐久不知更漏永，鐙花零落篆香消。"]'),
('fc85f1d2-20ec-4f11-90b5-ea5adef9ee65','華陽山堂落成','諸葛舜臣','宋','宋诗','song-poetry','','[]','小築菟裘石磴間，登臨極望意蒼然。',64,'全唐诗/poet.song.247000.json','["小築菟裘石磴間，登臨極望意蒼然。", "三更栗葉中峰雨，四月桃花一洞天。", "時聽茅君歸碧落，恍聞玉女鍊丹鉛。", "江湖萬里塵埃遠，留得深山一道泉。"]'),
('a9bbf345-6985-4f17-9e5e-e07d3c8a11f8','夜泛西湖','楊珂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','明月欺人醉不知，夜深偷入讀書幃。',32,'全唐诗/poet.song.247000.json','["明月欺人醉不知，夜深偷入讀書幃。", "好將松戶牢關鎖，留此清光莫放歸。"]'),
('8ed8c9af-4e35-462d-ac6c-3aa2576956de','靈巖一線天','張清子','宋','宋诗','song-poetry','','[]','一畫起于乾，先天至後天。',24,'全唐诗/poet.song.247000.json','["一畫起于乾，先天至後天。", "靈巖天一線，想在伏羲前。"]'),
('c844ec0f-a10b-4d09-bab4-f1c17142cf7b','句','虞德觀','宋','宋诗','song-poetry','','[]','我因國破家何在，君爲唇亡齒亦寒。',16,'全唐诗/poet.song.247000.json','["我因國破家何在，君爲唇亡齒亦寒。"]'),
('da401873-39ec-4257-bf80-10afb2f5ce1b','落筆峝','倭倭才','宋','宋诗','song-poetry','','[]','峭壁凌空望渺微，層層煙鎖霧雲衣。',64,'全唐诗/poet.song.247000.json','["峭壁凌空望渺微，層層煙鎖霧雲衣。", "深山古木高千丈，怪石青苔繞四圍。", "空有石銜仙骨在，想應人逐彩鸞飛。", "洞中仙子今何往，欲上雕鞍不忍歸。"]'),
('eee3eaa6-f0e1-4674-8ebb-8666e4f3305c','讀祖宗伯公臨難遺弟詩有感','羅榮祖','宋','宋诗','song-poetry','','[]','豫章風節振荆湘，匪爲殷亡爲晉亡。',64,'全唐诗/poet.song.247000.json','["豫章風節振荆湘，匪爲殷亡爲晉亡。", "執手痛罹鳴鶺難，焚裘夢斷樹藼鄉。", "三詩聊寄忠臣憤，九死寧迴國士腸。", "一展遺編一興慨，令人千載挹輝光。"]'),
('368a0d19-9745-42c3-87e5-d25c51f3176c','登齊雲和祖天錫公韻','羅榮祖','宋','宋诗','song-poetry','','[]','名山今日始攀躋，峭壁巉崖路欲迷。',64,'全唐诗/poet.song.247000.json','["名山今日始攀躋，峭壁巉崖路欲迷。", "荆棘撥開登月窟，脚根穩著步天梯。", "恍疑身在半空去，忽見鳥從平地飛。", "勝景可人觀不徧，揮毫石上且留題。"]'),
('dea30358-7793-4487-99e9-6823fd93cac3','題靈巖','羅榮祖','宋','宋诗','song-poetry','','[]','巨鰲戴山凌空起，橫絕碧雲千萬里。',96,'全唐诗/poet.song.247000.json','["巨鰲戴山凌空起，橫絕碧雲千萬里。", "嵐風飛凈明彩霞，四宇八紘皆望裏。", "霧障高懸五老峰，朵朵尖削成芙蓉。", "天柱南邊五丁立，香爐鑿出盤蛟龍。", "仙家七子燒丹處，瑶草瓊花間琪樹。", "洞門深鎖苔自封，黄鶴飛來復飛去。"]'),
('f1844e1b-4ee9-4245-828d-5a3436ec15c7','詠陶','羅榮祖','宋','宋诗','song-poetry','','[]','解體脫世紛，結志懷往義。',84,'全唐诗/poet.song.247000.json','["解體脫世紛，結志懷往義。", "織緯足充糧，種秫常供醉。", "素琴寄長謠，孤衿抗高視。", "國爵屏如羶，家貧甘若嗜。", "徑荒早歸來，園涉成佳致。", "依俗豈尚同，詭時非立異。", "遥遥五柳風，千載猶相喟。"]'),
('94c2851a-bd32-4b82-ad94-a13ed634293b','答招隠','羅榮祖','宋','宋诗','song-poetry','','[]','蕩蕩唐堯德，乃有箕山臣。',84,'全唐诗/poet.song.247000.json','["蕩蕩唐堯德，乃有箕山臣。", "巍巍周武功，不乏採薇人。", "四皓自躭洛，兩龔豈避新。", "并介實天性，離奇非世珍。", "君雖羞獨割，余敢辱均茵。", "東臯足舒嘯，南畝可充囷。", "弗罫聖人網，常期鷗鳥親。"]'),
('68c8717c-5745-4e66-bd89-e6bb02f1aa20','重沓嶺','張爚','宋','宋诗','song-poetry','','[]','松間疊石步高低，啼鳥幽林聽隔溪。',32,'全唐诗/poet.song.247000.json','["松間疊石步高低，啼鳥幽林聽隔溪。", "七尺枯藤可扶老，青鞋香汗落花泥。"]'),
('168030b8-f95a-4f90-99f0-ee0dee1fedb2','上趙主簿霽宇','張爚','宋','宋诗','song-poetry','','[]','辭棘鸞飛遠，重來棹雪舟。',48,'全唐诗/poet.song.247000.json','["辭棘鸞飛遠，重來棹雪舟。", "政聲清似水，官况冷於秋。", "譜系王侯貴，文章班馬流。", "賑民問錢穀，名已在金甌。"]'),
('ba1be7e5-4ad1-48c4-9963-54a98cfde35d','請趙季憲主玉虛道院','張爚','宋','宋诗','song-poetry','','[]','來自東山東復東，飛空一劍伴絲桐。',64,'全唐诗/poet.song.247000.json','["來自東山東復東，飛空一劍伴絲桐。", "能令矮屋疏籬下，如在十洲三島中。", "鍊句入神敲夜月，談玄動客笑春風。", "聞師曾得長生訣，同採丹砂訪葛翁。"]'),
('c4fa3d40-4e26-4dde-b4d8-d1ecc647add6','玉虛道院','朱鼎元','宋','宋诗','song-poetry','','[]','山東捨宅爲琳宇，公子超然趣不群。',64,'全唐诗/poet.song.247000.json','["山東捨宅爲琳宇，公子超然趣不群。", "帝足龜蛇交水火，將壇龍虎擁風雲。", "花階晝靜迎仙客，月殿香清禮老君。", "何日投閒同採藥，松邊坐石許誰分。"]'),
('1a6dc290-28dd-413b-ae80-afd81ce7a572','神仙名義','崔存','宋','宋诗','song-poetry','','[]','宿植靈根何太早，洞悟真風何年少。',64,'全唐诗/poet.song.247000.json','["宿植靈根何太早，洞悟真風何年少。", "常令丹海飛日烏，又使玉液朝元腦。", "崑臺氣候四時春，紫府光陰夜如曉。", "來時不用五雲車，跨著清風下蓬島。"]'),
('59963cfc-4cc2-4fef-901e-0a68dec8af8a','爲張莘疇題玉虛道院','崔存','宋','宋诗','song-poetry','','[]','小結烟霞作洞天，日長無事即神仙。',64,'全唐诗/poet.song.247000.json','["小結烟霞作洞天，日長無事即神仙。", "栽松待化山中石，種秫因分屋外田。", "滄海十洲人不到，丹砂九轉世空傳。", "何如坐對黄連炷，一卷南華內外篇。"]'),
('5ab8c21c-f5df-4f22-aa0e-a57862af794b','傷亂二首  其一','袁玧','宋','宋诗','song-poetry','','[]','龍蛇風浪起空潭，蒼莽山河泣墜簪。',64,'全唐诗/poet.song.247000.json','["龍蛇風浪起空潭，蒼莽山河泣墜簪。", "亂向十年餘史筆，貧無一字到詩函。", "心驚塞馬過淮北，夢逐關鴻度嶺南。", "肉食何人司重鼎，等閒揮麈事清譚。"]'),
('7a86eb36-3cf2-43d8-846c-6aaf232ababe','傷亂二首  其二','袁玧','宋','宋诗','song-poetry','','[]','轟轟烈烈一乾坤，北馬南船日夜奔。',64,'全唐诗/poet.song.247000.json','["轟轟烈烈一乾坤，北馬南船日夜奔。", "野老有懷悲故國，孤臣無淚哭中原。", "浮生似我仍留寓，季世何人不閉門。", "獨惜兩湖歸隠後，枕戈誰是晉劉琨。"]'),
('a9aa43d3-8542-4756-9e97-455cf7bbfb99','游白雲山','袁瑨','宋','宋诗','song-poetry','','[]','策杖白雲岑，雲深不知處。',60,'全唐诗/poet.song.247000.json','["策杖白雲岑，雲深不知處。", "恍見雲中君，白雲鄉裏住。", "舉手弄行雲，招我登雲路。", "漫漫雲路長，願乘黄鶴馭。", "黄鶴不復回，白雲自來去。"]'),
('5142b37d-0cda-41f9-8182-ceb02dc67ed1','卜居','袁瑨','宋','宋诗','song-poetry','','[]','宦海茫茫闊，幽棲洵遠圖。',48,'全唐诗/poet.song.247000.json','["宦海茫茫闊，幽棲洵遠圖。", "折腰原爲米，搔首却思鱸。", "笳鼓深秋動，田園舊夢無。", "干戈方滿地，吾輩尚窮途。"]'),
('712573aa-4307-4f69-9b15-6480b951b658','輓謝疊山  其一','湯雷奮','宋','宋诗','song-poetry','','[]','向老逢危亂，投軍復欲東。',48,'全唐诗/poet.song.247000.json','["向老逢危亂，投軍復欲東。", "九遷徒有命，一戰不成功。", "楚狂言猶在，韓讎事已空。", "風塵長蒼莽，身世轉飄蓬。"]'),
('fc0d664d-fa31-4082-9a8e-cb45d64443bc','輓謝疊山  其二','湯雷奮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','芒鞵初就道，慷慨不辭難。',48,'全唐诗/poet.song.247000.json','["芒鞵初就道，慷慨不辭難。", "滾滾長江盡，蕭蕭易水寒。", "風霜欺漢節，塵土上南冠。", "無復加餐飯，旁人掬淚看。"]'),
('48568e6d-90f6-4956-84ca-47c23ebafb4c','輓謝疊山  其三','湯雷奮','宋','宋诗','song-poetry','','[]','懷哉千古事，百煉不爲柔。',48,'全唐诗/poet.song.247000.json','["懷哉千古事，百煉不爲柔。", "漢祖尤封齒，殷臣不事周。", "寧隨文相國，真匹李潭州。", "浩蕩江相接，東西萬古愁。"]'),
('14275d5d-f33f-47a9-ae5b-40a2f1441108','絕句','瀟湘漁父','宋','宋诗','song-poetry','','[]','高枕形骸外，空江何限情。',24,'全唐诗/poet.song.247000.json','["高枕形骸外，空江何限情。", "落葉不成調，半夜起秋聲。"]'),
('10bb0312-5f1e-4a76-b5d0-7f0dba6ecea4','歌一首','瀟湘漁父','宋','宋诗','song-poetry','','[]','乾淳老人氣嶽嶽，破冠穿履行带索。',32,'全唐诗/poet.song.247000.json','["乾淳老人氣嶽嶽，破冠穿履行带索。", "撐腸拄肚書萬卷，臨風欲言牙齒落。"]'),
('e86d87d3-3780-406b-93a9-9f179c72f084','壽黎拙翁','陳儀慶','宋','宋诗','song-poetry','','[]','名重河汾道更尊，只將拙日養吾存。',64,'全唐诗/poet.song.247000.json','["名重河汾道更尊，只將拙日養吾存。", "南州佳士爭傾蓋，闕里諸生半在門。", "一笑何妨延賀客，六旬今已見曾孫。", "斯文壽脈天同久，挺挺霜松傲歲寒。"]'),
('46e0291d-323f-4231-8f08-c4d39681de21','九鎖山十詠 大滌洞','呂同老','宋','宋诗','song-poetry','','[]','巍巍元蓋天，巖穴閟仙宅。',96,'全唐诗/poet.song.247000.json','["巍巍元蓋天，巖穴閟仙宅。", "別戶穿虛明，層輝蕩空碧。", "神鼓振玉音，丹崖落瓊液。", "深通潜龍井，外障隔凡石。", "緬懷元同翁，於焉此棲息。", "華陽與林屋，隧道從所適。", "我來茲山中，偶值肥遁跡。", "靈草未易逢，翩翩飛鼠白。"]'),
('5c39fbbd-3f66-4528-a802-69a834605c62','九鎖山十詠 棲真洞','呂同老','宋','宋诗','song-poetry','','[]','殊庭天柱西，微逕羅荆棘。',96,'全唐诗/poet.song.247000.json','["殊庭天柱西，微逕羅荆棘。", "驅車谷口亭，清氣已迫人。", "元鎖爲我開，靈關豈無津。", "棋枰儼遺局，乳蓋垂空輪。", "側聞千載前，住此多隠淪。", "冥翳不可識，抱朴終成真。", "仙凡自有分，喧寂難並陳。", "歎息取歸路，吾猶濕囂塵。"]'),
('5c087c34-d722-4776-892e-5adf71b858ad','九鎖山十詠 鳴鳳洞','呂同老','宋','宋诗','song-poetry','','[]','連峰路塸堮，幽洞摩蒼穹。',96,'全唐诗/poet.song.247000.json','["連峰路塸堮，幽洞摩蒼穹。", "石門松蘿隘，傴僂趨兒童。", "泠泠太古泉，環珮聲丁東。", "相傳吳越年，威鳳翔其中。", "後來山中人，盛事誇無窮。", "我疑王者瑞，豈預霸業雄。", "元化有淪忽，世道多汙隆。", "何時鳴朝陽，遥問山上桐。"]'),
('86e22ace-d022-4b98-824f-f093145ba9cc','九鎖山十詠 蛻龍洞','呂同老','宋','宋诗','song-poetry','','[]','蒼山下孱顔，中有神龍棲。',96,'全唐诗/poet.song.247000.json','["蒼山下孱顔，中有神龍棲。", "神龍眇何許，一水涵清溪。", "深藏巖壑古，迥破風煙低。", "當其未蛻時，幽隠漫塵泥。", "既蛻頭角成，霄漢參雲霓。", "回顧昔所蟠，陳迹亦已迷。", "況我後來人，危磴重攀躋。", "四顧但絕壁，叢篠風淒淒。"]'),
('b2e73bf6-bcf6-4b30-9e12-cbd81704000b','九鎖山十詠 來賢巖','呂同老','宋','宋诗','song-poetry','','[]','昔賢所游地，道路行逶迤。',96,'全唐诗/poet.song.247000.json','["昔賢所游地，道路行逶迤。", "中分山腰半，倒插石脚危。", "公生元祐時，名與日月垂。", "至今草木間，英氣光離離。", "我行得遺迹，釃酒興遐思。", "天風豁然至，吹落瓊琚辭。", "不惜古人遠，但嗟我生遲。", "安得五雲表，一假黄鶴騎。"]'),
('0a848d4d-fad9-48f6-81f3-2c8d022f4a9a','九鎖山十詠 仙跡巖','呂同老','宋','宋诗','song-poetry','','[]','嬴秦亂天綱，猛志凌海水。',96,'全唐诗/poet.song.247000.json','["嬴秦亂天綱，猛志凌海水。", "長驅萬山石，鞭策無遠邇。", "餘威及茲地，夜半走百鬼。", "仙人惜靈宮，一怒俱披靡。", "巉然斷崖上，遺迹俯清泚。", "溪聲助叱咤，野蘚避冠履。", "茲事三千年，孰决非與是。", "摩挲蒼玉紋，俛仰求至理。"]'),
('1ecbc612-f8aa-42e2-b151-43a7fbd6768a','九鎖山十詠 翠蛟亭','呂同老','宋','宋诗','song-poetry','','[]','洄洑古澗深，蜿蜒層湍壯。',96,'全唐诗/poet.song.247000.json','["洄洑古澗深，蜿蜒層湍壯。", "長年蓄飛泉，一决起豪宕。", "高有百尺松，蓊鬰蔽青障。", "下有荇與萍，翠色映空曠。", "恍如千丈虬，窮壑潜異狀。", "忽乘風雲會，奮迅九天上。", "尚想玉堂仙，妙思發雄放。", "醉持白芙蕖，乘流動清唱。"]'),
('e66263f8-117b-4d70-8c54-1d4a9db68613','九鎖山十詠 丹泉','呂同老','宋','宋诗','song-poetry','','[]','觱沸檻外泉，遠出天柱陽。',96,'全唐诗/poet.song.247000.json','["觱沸檻外泉，遠出天柱陽。", "清音映空谷，潜波渙寒塘。", "昔人養靈芝，長年此山旁。", "金骨換玉髓，素虬朝紫皇。", "尚餘浴丹池，神光透扶桑。", "蓬萊幾揚塵，茲泉日泱泱。", "我願滌世紛，朗詠三元章。", "手持北斗杓，下酌流霞漿。"]'),
('7cbef78a-af94-4751-a8be-3c5cf2311925','九鎖山十詠 石壁','呂同老','宋','宋诗','song-poetry','','[]','清飈吹衣裳，縹緲淩層巔。',96,'全唐诗/poet.song.247000.json','["清飈吹衣裳，縹緲淩層巔。", "玲瓏峭壁下，杖策窮迴旋。", "名圖謝模寫，大巧無雕鎸。", "窅如晴雲影，靄靄行青天。", "飄如水風會，微瀾起平川。", "石崖前蔽虧，勝事惜未全。", "吾將運真宰，疏鑿成坦然。", "結茅此山阿，長吟伴飛仙。"]'),
('dc2be352-35d6-4742-ac8d-eb62d0385590','九鎖山十詠 雲根石','呂同老','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','吾聞泰山雲，觸石無不至。',72,'全唐诗/poet.song.247000.json','["吾聞泰山雲，觸石無不至。", "如何茲山中，有石象雲氣。", "仙人事狡獪，幻化翻手易。", "鱗鱗作薈蔚，冉冉湧蒼翠。", "清分澗水流，幽映林木邃。", "已逃蒼狗變，長見玉芝瑞。"]'),
('a398de87-a0e5-417e-930e-457c132d6f44','題高房山夜山圖','呂同老','宋','宋诗','song-poetry','','[]','我昔絕江看吳山，朝光正落山水間。',64,'全唐诗/poet.song.247000.json','["我昔絕江看吳山，朝光正落山水間。", "金波遠自海門入，翠嵐高插扶桑殷。", "安知璚樓有夜景，明月蒼茫墮清影。", "李侯勝賞高侯筆，展卷一時如夢醒。"]'),
('3d423200-498b-4636-9583-d86b58390286','龍泉寺納凉','呂同老','宋','宋诗','song-poetry','','[]','靡靡市廛盡，杳杳泉石閑。',120,'全唐诗/poet.song.247000.json','["靡靡市廛盡，杳杳泉石閑。", "灌木蔽榛莽，爽籟彌空山。", "飛甍納餘輝，丹雘粲以繁。", "巍然青蓮宮，俯此碧玉闌。", "化人淡無爲，趺坐觀塵寰。", "支郎杳不逢，玄蟬噪其間。", "昔賢憩游地，眢井潜龍蟠。", "詠歌之所傳，百世猶不刊。", "我生悅超曠，危磴重躋攀。", "歸隠諒未能，溯風發長歎。"]'),
('f5ba9a6d-0b1d-4614-a804-d9d4b03bf41e','携鸊鉞汎江','崔璆','宋','宋诗','song-poetry','','[]','酒星落京口，化爲崔子玉。',72,'全唐诗/poet.song.247000.json','["酒星落京口，化爲崔子玉。", "孤舟載壺觴，水花紅映肉。", "小兒唱銅斗，大兒倒醽醁。", "一笑不知年，浩蕩天地屋。", "慎勿臨竇呼，人生隨轉燭。", "嗣宗禮法仇，鍾會被殺戮。"]'),
('5e067f6f-2495-4ada-a969-cd853df699e8','咄咄','崔璆','宋','宋诗','song-poetry','','[]','咄咄復咄咄，小兒成老翁。',84,'全唐诗/poet.song.247000.json','["咄咄復咄咄，小兒成老翁。", "幺微各形色，追琢元化工。", "不知春風去，又見千綠叢。", "主人美客懷，載酒行溪東。", "一步一回首，十步尊已空。", "靈均與太白，醒醉同所終。", "願見化蠛蠓，生死託壺中。"]'),
('eb545fbb-bd09-421b-9e53-26029125502d','今日一何好','崔璆','宋','宋诗','song-poetry','','[]','今日一何好，花下醉狼藉。',120,'全唐诗/poet.song.247000.json','["今日一何好，花下醉狼藉。", "醉中有奇事，夢見生八翼。", "浩蕩排虛空，靈君好顔色。", "朱衣持大篆，授我醉鄉伯。", "頓首玉墀下，臣璆才蟣蝨。", "封此抑何功，請陳愚頑臆。", "臣家京口東，門前大江碧。", "臣願駕長風，吹作酒萬石。", "萬象各千鍾，拍拍大庭國。", "推枕在山中，紙衾霜曉月。"]'),
('1bfcf44b-257c-4d9b-958f-cca9c1085518','餘髪','柯芝','宋','宋诗','song-poetry','','[]','餘髪蕭蕭白垂領，十年守拙門庭冷。',128,'全唐诗/poet.song.247000.json','["餘髪蕭蕭白垂領，十年守拙門庭冷。", "來頻沙鳥頗相識，起晚鄰鷄已三請。", "形骸拄樹豈復好，心緒如蓬不能整。", "平生幾緉空馺𩣯，老去一杯先酩酊。", "俗言祇虞方鑿迕，人事但愜幽居屏。", "賦形不必盡芻狗，處坎何堪共蛙黽。", "若爲苴履曾足芥，幸不柳衫真欲癭。", "一聲樵響何處來，獨立看雲發深省。"]'),
('e5c8ec00-0aa6-414a-93ef-1cfecec9ed2d','耳耳','柯芝','宋','宋诗','song-poetry','','[]','耳耳非佳語，陸陸難爲顔。',135,'全唐诗/poet.song.247000.json','["耳耳非佳語，陸陸難爲顔。", "我生胡不淑，多戚長鮮歡。", "摇落復已綠，春風滿江干。", "最靈起予興，欲言骨肉酸。", "園桑摧爲薪，桃李亦半殘。", "翹蕘企晴燠，九室十更寒。", "飛錢如美色，乃入貴者闌。", "丘閭有穀賣，窮櫩朝無饘。", "不售信蹙隠，徒手良抱歎。", "宛轉愒餘息，溝壑分寸間。", "吾輩正不免，遑暇卹彼{疒衆}。"]'),
('5595f802-4100-448c-b6a3-fe014bfb123b','橫江','柯芝','宋','宋诗','song-poetry','','[]','橫江一片碧，携鶴上漁船。',24,'全唐诗/poet.song.247000.json','["橫江一片碧，携鶴上漁船。", "收綸不成下，却抱釣竿眠。"]'),
('ef804ad2-1ef4-43eb-8cf7-6f1dd51f6d53','江行早發','柯茂謙','宋','宋诗','song-poetry','','[]','陶鐺煮孤影，寒燈沸青花。',24,'全唐诗/poet.song.247000.json','["陶鐺煮孤影，寒燈沸青花。", "冰開數江樹，月落失人家。"]'),
('77563f73-a92f-4434-bd92-dc2516510730','魯港','柯茂謙','宋','宋诗','song-poetry','','[]','十年回首付霑襟，斷甲沈沙齒齒深。',64,'全唐诗/poet.song.247000.json','["十年回首付霑襟，斷甲沈沙齒齒深。", "可惜使船如使馬，不聞聲鼓但聲金。", "人歌鬼哭都堪淚，木落江空正獨吟。", "遺老蕭條漸無語，酒旗颭颭出蘆林。"]');
